insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-10-03','Requisitos para acceder a VPP. Contacto: Marisa Cortés y Eva (924-332000 y Ext. 50456). -Solicitarlo a través del Ayuntamiento en el que se encuentra empadronado. -Acreditar ingresos inferiores a 15000 euros. -Certificado de empadronamiento. -DNI. -libro de Familia. -Informe Social. La adjudicación o no de vivienda está sujeta a la disponibilidad de la misma en la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2011-11-02','Se envía Contrato de Admisión de la Casa de la Misericordia "Padre Leocadio" de Pinofranqueado a la Unidad de Recursos, Dispositivos y Serviocios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2011-11-03','Conversación con Luci, Directora de la Residencia de Torrecilla de la Tiesa. Ve conveniente que Dª Encarnación pase unos días en su pueblo, al igual que también su Psiquiatra lo considera aconsejable desde el punto de vista terapéutico. Actualmnente le está reajustando la medicación. Luci comenta que la hermana de Dª Encarnación se comprometería a volver a llevarla a la Residencia. Nos plantea también la posibilidad de que sea Dª Encarnación la que vaya a ver de vez en cuando a la hija a Jaraiz. Lo gestionaré con Futuex para que se pueda realizar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2011-11-03','Pendiente de hablar con Teresa (Directora) y María (Psicóloga) de la Residencia sobre posibles vacaciones de Dª Antonia Con su madre, tíos y prima en Miajadas para estas Navidades. En Torrecilla de la Tiesa lo creen conveniente en relación a su madre.','2');
