insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2011-11-10','-Se le reconoce el cpto. a minimos de su pensión , que ascienden a 403,59€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2011-11-10','-Se le reconoce el cpto. a minimos de su pensión , asciende a 385,33€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2011-11-10','Nuria, Psicóloga de "Los Delfines". José Antonio lleva unos meses muy buenos en el centro, mostrándose muy participativo en todos los aspectos. Ha establecido una gran confianza con un grupo de amigos en el propio Centro. Según Nuria, los comentarios de José Antonio hacia su padre pueden ser una forma de presión hacia este, más ahora que se acercan las Navidades: "José Antonio, aunque dice que se quiere ir a Extremadura, no es tanto por estar en su tierra como por estar más cerca de su familia, en especial de su padre". La propuesta de que sea su padre el que se desplace a ver a José Antonio le parece muy oportuna a Nuria, sobre todo porque eliminamos el riesgo de perder todo lo positivo quie la evolución de José Antonio está teniendo. No le comentará nada a él hasta que dicho viaje se pueda confirmar. En conversación con D. José Antonio, su padre, le comentamos la información proporcionada por Nuria: "Pues entonces no sé que pretende mi hijo diciéndome esas cosas...Me alegro de que esté tan bien. Yo creo que el centro es el apropiado para él...Yo, aunque quisiera no podría tenerlo conmigo porque cobro solo 400 euros y lo primero que hago es llenar la nevera. D. José Antonio está recibiendo estractos de la cuenta de José Antonio en su domicilio. Al parecer sigue teniendo abierta la cuenta en la que antes ingresaba la PNC y en la que aparecen ambos como titulares. Dice que cancelará esa cuenta porque en ella no hay dinero. Respecto a la posibilidad de ir a ver a su hijo quedamos en que, si éste cuenta con dinero suficiente para ello, pagaremos el viaje. En cualquier caso, y hasta que no confirmemos esta posibilidad, no le debe decir nada a su hijo. Comenta que a fecha de 26-10-2011 el saldo de José Antonio es de 1544 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2011-11-11','-sale del CSS Merida el dia 9-12-2011 , cumple la medida de seguridad.','2');
