insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2011-11-14','-Estamos pte. de que nos confirmen que tiene aprobada la P. Orfandad , para optar por la PF y dejar PNC ( solicitud de peticion ya recibida ) .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2011-11-15','Informante: Ester. Dª Coral fue ingresada en el Centro Sociosanitario el pasado domingo a raíz de un intento de suicidio (trató de tirarse por la ventana).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2011-11-15','Conversación con D. Álvaro Moralo, del BBVA. A raíz de mi conversación del día 26 de octubre, se puso en contacto con el Departamento correspondiente para ver cómo podían cumplir la orden de CTAEx para que D. Juan solo pusiese sacar 150 euros semanales. Ayer nos enteramos que había vuelto a sacar todo el dinero. la explicación: la información y claves que dieron a la sucursal eran erróneas y D. Juan pudo sacar, primero 150 euros y después el resto a través del cajero automático con su libreta. D. Álvaro me confirma que el problema está resuelto y que a partir de diciembre ya será efectiva la orden. Pagarán la transferencia Jaztell en cuanto haya nuevamente dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2011-11-16','-presentada solicitud de plaza en centro residencial de discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2011-11-15','Coversación telefónica con María, Psicóloga de Asociación "Vera". Le parece que puede ser adecuado para la evolución de Dª Antonia que ésta pueda pasar unos días con su familia en Miajadas para Navidad. En concreto del viernes 23 al lunes 26 de dicembre. Considera que el riesgo de que luego se resista a regresar merece la pena asumirlo: "Otros residentes han pasado por lo mismo y luego no han tenido problema para volver". Además, se puede valorar esta primera salida como una "prueba" para que, de vez en cuando, tanto ella como su madre puedan pasar algunos días en el pueblo. También ve como positivo el que la madre vaya a visitar d Dª Antonia alguna vez. Mantendremos el contacto y trabajará con ella para que se vaya haciendo a la idea de esta salida y de su posterior regreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GORDILLO'and apellido2='PINTO'),'2011-11-17','-se procede al internamiento involuntario con 112 al CSS Mérida para valoración. -Se cambia la cerradura de la casa, las llaves se depositan en el Ayto. ante el temor de existir dinero en el domicilio, y varias personas con llaves. -Estaremos pte. de su evolución clínica , y al alta se buscarán alternativas : una posible sería plaza privada en la Residencia de Medina , que se encuentra en la misma calle que su domicilio . El SAD no lo aceptó anteriomente , tb existe miedo por parte de las auxiliares. Come a base de latas de conservas , no elabora comida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2011-11-18','SE ESTABLECE POR EL CRR DE BADAJOZ QUE LE DEMOS UN REINTEGRO MENSUAL DE 240 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2011-11-18','-mantengo conversación tf. con Ramón ( TS módulo 3 ) sobre Rafael . : *solicito que las visitas sean en sabado. *cuenta peculio. los lunes haremos un reintegro de 40€ *tiene condena hasta 3 mayo de 2013.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2011-11-18','Se encuentra ingresado en la Casa de la Misericordia de Pinofranqueado, cumpliendo un pena de tres años por delito. Está allí desde el13 de octubre de 2011.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2011-11-18','Conversación con Dª Juana, posible compradora de la vivienda. La propuesta incial de D. Juan de 66.000 euros, que luego le rebajó a 63.000 le parece excesiva. Estaría dispuesta a pagar 50.000 euros: "Me ha dado tiempo a pensar y mirar y he visto alguna otra que, con la reforma que le quiero hacer, me saldría por ese precio -63.000-. La casa no está tan biern como la de Juan, pero en esta barriada esa cantidad me parece excesiva..." Comentaré con Carmen Díaz y Juan la oferta, pero le adelanto que no la va a aceptar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='AGUILAR'and apellido2='GARCIA'),'2011-11-18','Ingresada en la Residencia de Casares de Hurdes desde el 9 de noviembre de 2011.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2011-11-18','SE SOLICITA LA CANCELACIÓN DE UNA CUENTA DEL BANCO CAIXA GERAL QUE NO TENÍA SALDO Y SE HA SOLICITADO EL CAMBIO DE LAS DOMICILIACIONES A LA OTRA CUENTA QUE TIENE DONDE SE INGRESA SU PENSIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2011-11-22','Javier, Director CRR Plasencia. Nos comunica que en el CSS de Plasencia se eestán planteando la posibilidad de derivar a José María de la UME a Larga Estancia. Desconoce Javier los motivos de dicha derivación, pero quedo pendiente de hablar con el Psiquiatra de José María, el Dr. Sevilla sobre el tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMILIANO'and edp.apellido1='BAZAGA'and apellido2='CARRERA'),'2011-11-22','Conversación con el Dr. Herrero, Psiquiatra de Maxi en el CSS de Plasencia. Han realizado la solicitud de derivación a CRR en septiembre: Maxi no ha consumido ni "trapicheado" con ninguna sustancia en durante el tiempo de ingreso. Ha tenido pocas salidas, pero lo controles espóntáneos realizados han dado siempre negativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2011-11-22','Conversación con Juan sobre la venta de la casa. Se le comenta la última oferta de Dª Juana: 50000 euros. No la acepta y propone que le rebaje otras 150.000 (900 euros) como última oferta, aún a riesgo de perder definitivamente la venta. Puestos en contacto con Dª Juana rechaza también esta rebaja y, por lo tanto, damos por finalizada la posibilidad de esta venta. Se le comunica a Juan este hecho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2011-11-23','Conversación telefónica con Margarita GVarcía Díaz, abogada de Badajoz que ha llevado el procedimiento de nulidad de testamento en el que aparecía Dª Carmen como heredera de D. Enrique Guillermo Escalera Rosado, por no acreditarse fehacientemente la filiación de Dª Carmen. Margarita considera que existen indicios suficientes para solicitar un procedimiento de determinación de la filiación. No obstante, para iniciar ese procedimiento es necesario presentar pruebas claras de dicha filiación, dado que en el anterior juicio se presentaron como pruebas en contra el Libro de Familia y el Certificado del R.C. Desde la Comisión hemos pensado iniciar ese procedimiento, ya que Dª Carmen puede costear una prueba de ADN (en el Juzgado de Familia nos dijeron que costaba 600 euros). Margarita va a hacer las gestiones para que el "hermano" (¿el que inició el procedimiento de nulidad del testamento?) se preste a dicha prueba y cotejar los resultados con los de Dª Carmen. Hasta que la Abogada no se ponga de nuevo en contacto con CTAEx no se puede iniciar el procedimiento y, por lo tanto, tampoco solocitar Abogado de Oficio, nombramiento que desde CTAEx propondríamos recayera en Margarita García.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='OVONO'and apellido2='EDU-ESENG'),'2011-11-24','Ingreso y alta en el mismo día de D. Alberto en Hospital Don Benito. Tiene otra hernia en la ingle izda., que ha surgido tras operarse la de la dcha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCAS'and edp.apellido1='DIAZ'and apellido2='VAZQUEZ'),'2011-11-23','Acompañamiento a la consulta de Anestesia en el Hospital "Perpetuo Socorro" de Badajoz, para intervención ocular. Ingresará el Domingo 27 de noviembre y la intervención será el lunes 28. Demandas de Lucas: -Pedir a la familia que vaya a verlo o que le llamen. -Aumetarle 10 "eurinos" la paga semanal de 20. -Comprar una TV de 32", de plasma, para su habitación. -Comprarle una pareja de "perrinos" para criar y presentarlos a concursos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2011-11-24','Conversación telefónica con el Dr.Furones (Oncólogo). Trasladó la Historia Clínica de Dª Consuelo al Jefe de Ginecología, quien le dijo que tratarían de ingresarla la próxima semana, bien para intervenir por laparoscopia o por laparotomía. Le expuse la preocupación de su familia por la tardanza en ser atendida en el Hospital y su deseo de que lo antes posible le atendieran allí "para hacerle lo que considerasen necesario". Llamámos D. Ángel, hermano de Dª Consuelo, para informarle de esta conversación. También llamé a Aprosuna 12. Expuse a Mª José, la Directora, lo referido por el Dr. Furones. Me comentó que Consuelo llevaba unos días bastante bien, aceptando la comida y animada. Le pedí que hablara con Cristina y le comunicaran a D. Nicolás, hermano de Consuelo, las nuevas indicaciones desde el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2011-11-24','Visita al domicilio de Dª Carmen. Junto con Mª Ángeles, Educadora de los Pisos Tutelados. Ver fotografías en su expediente. Dª Carmen quiere arreglar la parte baja de la vivienda. El doblado está en malas condiciones, con parte de un obra anterior sin finalizar y con bastantes dificultades de acceso. En la planta baja querría poner una cocina(primera habitación, entrando en casa, a la izda.). La cocinilla la tiene ahora en el salón, que, si fuera posible, se podría comunicar con la nueva cocina con una barra americana. Justo antes de pasar al doblado hay un cuato de baño completo, con plato de ducha y bidé, nuevo completamente y sin usar. Para acceder a él hay que subir un tramo de escaleras, en bruto, que hay que arreglar, colocando pasamanos al menos en uno de los lados. Este cuarto de baño se podría trasladar a la planta baja, pero arreglando el acceso se podría mantener en su ubicación actual. En la planta baja habría que corregir el problema de humedades que hay, pintarla toda y Dª carmen quiere poner el suelo (parquet o tarima), pero el que tiene ahora de gres no está mal. La planta baja necesita habilitar un dormitorio: hay al menos tres armarios roperos que se podría usar, quitando los muebles sobrantes. También hay al menos dos somieres, que quizá habría que cambiar junto con la compra de un colchón nuevo que sí se necesita. Por último, la fachada habría que pintarla o ponerle proyectado. En el doblado hay una habitación con la obra a medio terminar que da acceso a una terraza. Como se ha dicho antes, el acceso e interior al doblado están muy mal, por lo que habría que cerrar los dos accesos que tiene con puertas. El tejado es de "uralita" de la de "plástico". Al parecer no hay goteras pero el tejado habría que revisarlo. También habría que cambiar la puerta de entrada. Dª Carmen trató de localizar a un vecino suyo, D. Samuel, albañil y pintor, que creemos fue quien le inició la obra sin terminar antes de que ella ingresara en el CSS. No estaba en casa, pero nos dió su teléfono para hablar con él. A Dª carmen le propuse pedir otro presupuesto más, pero ella querría que fuese D. samuel quien le hiciese la obra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2011-11-25','SE PONE EN CONTACTO CON NOSTROS EL HNO. DEL TUTELADO PARA INFORMARNOS DE QUE HAY QUE SOLICITAR LA APROBACIÓN JUDICIAL DE LA PARTICIÓN DE HERENCIA DE SU PADRE. NOS ENVIARÁ FOTOCOPIA DE LAS ESCRITURAS. TAMBIEN NOS COMENTA SU SITUACIÓN ACTUAL ANTONIO ESTÁ SEPARADO Y TIENE DOS HIJOS CON LOS QUE NO MANTIENE RELACIÓN, TAMBIEN COMENTA QUE A SU HIJA QUE TIENE 28 AÑOS LE PASA UNA PENSIÓN Y QUE DEBERIAMOS CANCELAR ESA TRANSFERENCIA . PEDIREMOS INFORMACIÓN AL INSS Y A SU BANCO PARA VER COMO ESTAN LAS CUENTAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2011-11-25','SE MODIFICA LA CUANTIA DE LA PNC QUE COBRA JUNTO CON SU NOMINA, COBRA DE PNC 29,08 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GUDIÑO'and apellido2='CACERES'),'2011-11-25','Fuga del CSS de Mérida sobre las 13:45h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2011-11-25','Conversación con Teresa, Directora de Asoc. "Vera". Dª Mª José amenazó con autolesionarse con eun cuchillo hace unos días. Quiere marcharse con su amigo Pedro al CRR de Plasencia. Teresa me plantea esa posiblidad, pero considero que el nivel de autonomía que se precisa para ingresar en CRR no está, al menos en estos momentos, al alcance de Mª José. Hablo con MªJosé, quien se pone al teléfono llorando y pidiendo que la llevemos al CRR con su amigo Pedro. Hacemos un "trato": si ella hace lo que su amigo hizo para irse al CRR (tarbajar en el huerto, ayudar en el comedor, arreglar la habitación, cumplir con lo que le piden Teresa y las Educadoras, etc.) yo hablaré con su Psiquiatra para que nos diga si ella puede ir al CRR. Mª José estuvo "de acuerdo" en ello y "lo va a intentar".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GUDIÑO'and apellido2='CACERES'),'2011-11-28','Localizado el mismo día 25 de noviembre en la Estación de Mérida. Quería irse a su pueblo. Se encuentra bien. Blanca Dice que, dado su problema con el alcohol, y a pesar de tener solicitada Residencia de Mayores, D. Ángel no está en estos momentos para residir en una de ellas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2011-11-28','-se le ha solicitado al INSS renuncia al cpto. a minimos de la P. Orfandad para que pueda seguir percibiendo prestación desempleo. Cuando se le agote el desempleo , tengo que volver a comunicarlo al INSS para que se lo reanuden , me avisaran del CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2011-11-28','Puerto (T.Social Mancomunidad "Valle del Alagón).(927-672928) Nos informa que la última vez que Dª Emiliana ha tenido que asistir a consulta en el ESM de Coria ha ido sola. Al parecer, los Auxiliares de los Pisos Tutelados de Calzadilla ya no pueden ir, porque ahora los 15 residentes quieren ese acompañamiento. De esto Puerto se ha enterado porque se lo ha dicho la propia Dª Emiliana. hablo con Graci, Auxiliar Pisos. Le indico que cualquier problema que surja con nuesros tutelados nos lo pueden indicar llamando directamente a la Comisión. Hablaré con Futuex para adecuar las visitas a los días de consulta. Próxima consaulta: 26-01-2012, a las 10:00h.','2');
