insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2011-11-30','Acompañamiento de Dª Consuelo a la consulta de Oncología del Dr. Carrillo, junto con D. Ángel, hermano de Consuelo. El Dr. Carrillo solicitó una prueba adicional a la Resonancia Magnética que se le va a realizar este viernes, 2 de diciembre: una punción de la masa que tiene en el abdomen para su posterior análisis anatomopatológico. Hablamos también con la Dra. Martín, de Radiología, quien nos dijo que esperaría al resultado del Resonancia para hacer la segunda prueba. Dejamos firmados los Consentimientos Informados para ambas pruebas y quedaron en que nos llamarían por teléfono (dejé los teléfonos de la Comisión).','2');
