insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2011-12-02','Conversación con Dª Juana Patilla Castro (633-305448) Se compromete a atender a su hermana Encarnación y a su sobrina Antonia durante los días 23 a 27 de diciembre, en su casa de Miajadas. El día 23 irán a recoger a Antonia a Jaraíz de la Vera y a la vuelta recogerán a Encarnación en Torrecillas de la Tiesa. la vuelta se hará de la misma forma el día 27 de diciembre. El taxi se pagará desde CTAEx: Anabel, T. Social de Miajadas no confía en que el hermano de Antonia se comprometa a realizar dicho trasportes, por lo que también en CTAEx consideramos que es mejor hacerlos en taxi. Hablo con Ana, Enfermera de la Residencia para comunicarle dicho permiso.(927-338116). Enviar autorización a la Residencia de Torrecilla de la Tiesa: Fax(Ayto.): 927-338025 (A/A) de Lucía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2011-12-02','Conversación con Dª Juana Patilla Castro. Se compromete a atender a su hermana Encarnación y a su sobrina Antonia durante los días 23 a 27 de diciembre, en su casa de Miajadas. El día 23 irán a recoger a Antonia a Jaraíz de la Vera y a la vuelta recogerán a Encarnación en Torrecillas de la Tiesa. la vuelta se hará de la misma forma el día 27 de diciembre. El taxi se pagará desde CTAEx: Anabel, T. Social de Miajadas no confía en que el hermano de Antonia se comprometa a realizar dicho trasportes, por lo que también en CTAEx consideramos que es mejor hacerlos en taxi. Hablo con José Antonio, de Vera, para informarle de todo ello. Para la marcha le darán instrucciones con la medicación, al igual que a su madre. Enviar autorización a la Asociación "Vera".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2011-12-05','Conversación con Dª Mª Teresa Amador Lobo, tía de los hermanos López Cabrera (696-423958). Colocará cartel para la venta de la vivienda y pedirá tasación. La parte de su marido es propiedad ya de sus hijas.','2');
