insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2011-12-07','Conversación con Juan Gordillo Mesa, Director del CAM "Ana Bolaños". Traslado de Iván a Aprosuba 3. Considera más conveniente que se produzca tras las Navidades: tenían previsto que Navidad y Año Nuevo los pasase con su tía y el resto de los días con sus hermanos en el CAM. Propone como fecha el 11 de enero. Se comunica esta fecha a Maite (U. de Recursos) por si fuese demasiado tiempo para mantener la plaza sin ocupar: se explican los motivos y hablará con Manuela al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2011-12-07','Conversación con Agustina, T.Social de Fuentes de León. David está viviendo actualmente con sus padres y hermanos (Álvaro y Cristian) en Segura de León. Tiene una PNC que le tramitó su padre y un grado de minusvalía del 65-66%. Sus padres tienen un seguro privado: Adeslas. El padre era G. Civil: le dieron la baja con poco más de cuarenta años. Tiene una Incapacidad Absoluta (1500 euros aproximadamente). Durante un tiempo David estuvo ingresado en la UHB de Llerena. El Dr. Idilio se interesó mucho por su situación. Se convocó una reunión (hace +/-2 años) en la que participaron tres Psiquiatras, una Psicóloga, la T. Social y el Programa de Familia: en aquella reunión se concluyó en que David podía ingresar en Apba. 5 de jerez o bien en los Pisos Tutelados, participando además en el C. Ocupacional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2011-12-07','Conversación con Pedro, hermano de Guadalupe. Estaría dispuesto a ayudar a su hermana en el pago de las escrituras de la permuta si sus hijas pusieran alguna pega para ello, lo cual no cree que ocurra. Me da los teléfonos de Raquel y de Juan (primo y abogado). Estaría interesado en el huerto si la pudiera cambiar con un vecino del pueblo con el que su padre habló del tema hace años. Si no fuera así, el no quiere la parcela para nada. Cree que no cuesta, tal como está, más de 600 euros. Nos ofrece su colaboración para todo lo que esté en su mano, tanto con nosotros cono con sus sopbrinas. Conversación con Juan Anta (primo y abogado). -pendiente de certificación de catastro. -hablará con sus primas sobre la posibilidad de hacerse cargo del coste total de la permuta, viendo la posibilidad de hacer un "contrato" para recuperar ese dinero de alguna manera: no cree que haya problemas en ello, ni siquiera que, según lo que cueste quieran recuperar dicho dinero. -de las deudas de Dª Guadalupe sabe que las hay, pero desconoce su cuantía. -respecto a Pedro, tío de sus primas y clientes, cualquier cosa que supusiera venta de algún bien lo harían contando en todo momento con él: se ha portado estupendamente con la madre de mis clientes y tenemos todos muy buenas relaciones con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2011-12-07','Conversación con Ester, T. Social del CAMP "Las CRuces". Jesús se ha escapado ayer, a las 7:30, llevándose objetos personales de algunos residentes. Se ha puesto la correspondiente denuncia. Cuando el Cuidador de noche se dió cuenta de la huída, salió a buscarlo: lo encontró en la estación de ferrocarril. Trató de convencerlo para que volviera con él al CAMP, sin conseguirlo. Se le indica que hablen con la Policía ante la que se hizo la denuncia indicándoles la posibilidad de que pueda estar en Badajoz con la familia. Recomendaciones para otra situación así, propuestas a la T. Social para que las comunique en el Centro: -Tratar de convencerlo con el diálogo. -Si no resulta, llamar a la Policía o Guardia Civil indicando que se trata de una persona tutelada que trata de escapar del centro que tiene la guarda y custodia, mientras se trata de retener hasta que lleguen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='TREJO'and apellido2='MUÑOZ'),'2011-12-09','SE SOLICITA AL JUZGADO LA APROBACIÓN DE LA PARTICIÓN DE LA HERENCIA PROPIEDAD DE SU PADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2011-12-09','SE VENDE LA FINCA DE LA FUENTE LOS PERROS POR 2400 €. PAGAMOS LA OBRA DEL ARREGLO DE LOS DOS TEJADOS A JUAN PAREDES, IMPORTE 2980 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2011-12-12','Conversación con Taxista de Miajadas, D. Pascual (679-960334). Se le indica el siguiente itinerario: DÍA 23: recoger a Antonia Bravo Patilla en Asoc. "Vera" (se le indica dirección y teléfono) y a la vuelta recoger a Dª Encarnación Patilla en el Centro de Mayores de Trorrecilla de la Tiesa (conoce ya la dirección). DÍA 27: itinerario inverso. Hablo también con Dª Juana Patilla, hermana de Dª Encarnación, y le doy el teléfono del Taxista para que quede con él el día 23 para ir a recoger a su hermana y sobrina. Se le insite en el control de la medicación de ambas, indicándole que en cada Residencia le darán instrucciones para su administración: "y si no lo hacen se las pediré yo..." -me dice-. Ante cualquier problema se pondrá en contacto con la Comisión y/o con el SSB de Miajadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2011-12-12','Conversación con Taxista de Miajadas, D. Pascual (679-960334). Se le indica el siguiente itinerario: DÍA 23: recoger a Antonia Bravo Patilla en Asoc. "Vera" (se le indica dirección y teléfono) y a la vuelta recoger a Dª Encarnación Patilla en el Centro de Mayores de Trorrecilla de la Tiesa (conoce ya la dirección). DÍA 27: itinerario inverso. Hablo también con Dª Juana Patilla, hermana de Dª Encarnación, y le doy el teléfono del Taxista para que quede con él el día 23 para ir a recoger a su hermana y sobrina. Se le insite en el control de la medicación de ambas, indicándole que en cada Residencia le darán instrucciones para su administración: "y si no lo hacen se las pediré yo..." -me dice-. Ante cualquier problema se pondrá en contacto con la Comisión y/o con el SSB de Miajadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALVES'and apellido2='MATEUS'),'2011-12-12','Conversación con Pilar (T.S. CSS Plasencia). Último ingreso en 2007 y hasta el presente. Tiene la idea de que D. José (66 años) podría estar mejor en un Centro de Mayores, con cierto nivel de supervisión: " Pero él no quiere marcharse del CSS si no es para ir a su casa, cosa abolutamente descartable... Él tiene dinero para estar en una privada hasta que le dieran una pública, pero no quiere". Pilar continuará barajando esta posibilidad y me irá informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2011-12-13','Conversación con David Cuenca Silva (hermano). 664-380294. Llama para dar de alta la luz del piso, pero no nos ha enviado las escrituras como quedamos en la conversación mantenida en octubre (yo creo que lo había olvidado). Los hermanos no quieren que su hijo ocupe el piso. Le hago ver lo innecesario de dar de alta la luz para no ocupar nadie esa vivienda (lo que parece entender). Sí se le recuerda la conveniencia de que busque las escrituras en las que D. José figure como usufructuario, para enviárnoslas y tenerlas en caso de tener que hacer alguna gestión sobre ese piso. Sí se "queja" de las frecuentes llamadas del CSS de Mérida pidiéndole que se ocupe de su hermano: "...Pero yo no puedo ocuparme de él, ni él puede estar solo en el piso. Además, la última vez que vino no sabe que día nos dió..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2011-12-13','SE HA SOLICITADO LA REVISIÓN DE GRADO DE MINUSVALIA AL CADEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2011-12-14','SE ADMITE A TRÁMITE LA SOLICITUD DE EXPEDIENTE DE JURISDICCIÓN VOLUNTARIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='EXPOSITO'and apellido2='MORENO'),'2011-12-14','NOS COMUNICAN SU INGRESO EN EL HOSPITAL DE DON BENITO TIENE METÁSTASIS MUY EXTENDIDA, SE LE PONDRÁ UNA CUIDADORA 24 HORAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2011-12-15','Ayer, 14 de diciembre, acudimos al Juicio de Faltas de Miguel contra su padre. El mismo no llegó a celebrarse ante la pregunta de la Juez de si deseaba mantener la denuncia y seguir el procedimiento o desistir en la misma. Miguel prefirió retirar la denuncia. Hablando tras estosa momentos con el padre de Miguel, insistimos en la necesidad de que situaciones de este tipo no se volvieran a repetir, y le dijimos que si en algún momento se producía algún problema con su hijo que se pusiese en contacto con CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BENITO'and edp.apellido1='GILGADO'and apellido2='GALAN'),'2011-12-15','Conversación con Verónica, T. Social de "Felipe Trigo". Citación del Juzgado de 1ª Instancia nº001 de Castuera. Fueron con Benito ayer, y en el Juzgado no sabían el motivo de esta citación, si bien le hicieron el reconocimiento médico-forense y examen judicial que figuraba en la citación. (Cristina, Secretaria del Juzgado: 924-773979). Benito sigue sin tener relación con ninguno de los residentes en el centro. Su sobrino no ha vuelto a ir por allí desde mayo de este año. La última revisión en ESM fue en octubre: le mantuvieron la medicación antidepresiva. Le pido a Verónica copia del Informe Médico y ode otros que pueda tener.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2011-12-15','Hablamos con Caterina, T. Social de Aprosuba 3. El ingreso de Iván se realizará el próximo 19 de diciembre. Se les envía por fax la documentación de la que disponemos. Hablamos con Juan Gordillo, director del CAM "Ana Bolaños". Se confirma el traslado para el 19 de diciembre y en el mismo aportarán toda la documentación de que disponen, incluído DNI, Tarjeta Sanitaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2011-12-15','SE DA TRASLADO A LA ACUSACIÓN PARA QUE DECIDA SI QUIERE SEGUIR CON EL PROCEDIMIENTO ABREVIADO POR LESIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2011-12-15','Conversación con D. David Cuenca Silva. Las escrituras del piso las tiene su hermano Daniel (606-900058). Ha hablado con él y no tiene inconveniente en enviarnoslas. Pendiente de llamarlo para que nos envíe fotocopias compulsadas. Plantea que tiene otro hijo que a lo mejor podría ocupar el piso: le indico que en caso de hacerlo, sería mediante contrato de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2011-12-15','Conversación con Mª Eugenia, T.Social del CSS de Mérida. Tienen prevista una salida de Luis este fin de semana a casa de su padre, ya que éste va a terminar de cumplir la sentencia en su domicilio. La idea de Maribel, Psiquiatra, es mantener estas salidas durante un tiempo. Mi propuesta es que dicha temporalidad se mantenga hasta, por lo menos, que el padre cumpla completamente su condena: de esta forma podemos prevenir que, si se produce un nuevo quebrantamiento, Luis se vea nuevamente solo y tengamos que volver a dar los pasos ya andados. Pido hablar con Maribel, pero está en otro pabellón. Mª Eugenia le hará llegar esta propuesta. Si finalmente se reanuda la convivencia de padre e hijo, contactaremos con Futuex para llevar a cabo visitas, inicialmente semanales, y el acompañamiento a ALREX, que no pudo ser iniciado al coincidir con el encarcelamiento del padre. También en ese momento se retomaría la actividad con la empresa encargada de prestar la atención domiciliaria reconocida por la Ley de Dependencia. Igualmente, si se reanuda la convivencia, contactaremos con la Dra. Marisol (M. de Familia) y la Dra. Constanza (UHB de Llerena).','2');
