insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2011-12-21','- grado de discapacidad del 39% revisable en diciembre del 2012. -La P.Orfandad que venia percibiendo se le ha dado de baja con fecha 1-12-2011 al cumplir los 22 años que como norma general estipula la ley . Concertar cita en CAISS para ver si se le puede ampliar. -No tiene acceso a PNC ni PF por no cumplir requisito de discapacidad.','2');
