insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2011-11-28','- Percibe PNC, se le solicitó PF + ORFANDAD. Se opta por la PF aún sin tener la resolución de orfandad , ante el segundo requerimiento de la opcion por la SS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPA'and edp.apellido1='RASTROLLO'and apellido2='PAJARES'),'2011-12-29','SE PAGA LA DEUDA QUE TENÍA CON LA COMUNIDAD DE PROPIETARIOS DE LA CALLE CHAPIN Y SE HACE LA TRANSFERENCIA PERIODICA MENSUAL A PARTIR DE FEBRERO 2012','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2012-01-03','Conversación con el Padre Frenando (Casa de La Misericordia de Pinofranquerdao). Se le imforma del reconocimiento del derecho al cobro de la pensión por Incapacidad Permanente Absoluta desde el 01 de diciembre de 2011: 785.33 euros. Considera que, en justicia, Lázaro debería seguir aportando los 1000 euros actuales, ya que si la prestación vinculada al servicio la tiene es porque se le está prestando dicho servicio. Me remite por fax la resolución del Cadex sobre reconocimiento del grado de discapacidad: 66%. Tipo de Discapacidad: Psíquica, con carácter definitivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2012-01-03','Acude al despacho. Quiere informarnos de que tiene pensado, tras pasar consulta de Enfermería en el ESM mañana, marcharse a Utrera para ayudar a su tía Dª Josefa Rodríguez en los trámites para acceder a un recurso de la Red de Salud Mental del SAS. Dice que va a estar allí un par de días. Sigue con el Dr. Felíx, su Pisquiatra, y con Leonor, su Enfermera, con la cual está encantado por el trato y ñla confianza dispensados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2012-01-03','Acude al despacho. Nos enseña las fotografías de varias grietas que han aparecido en distintas estancias de la vivienda: desde luego no deberían haber aparecido tras haber realizado esta obra hace tan pocos meses. Llamaremos a la empresa que se encargó de la reforma para que corrijan las deficiencias. Nos mustra también fotos de la cocina ya instalada: falta la fontanería, que dice que se la va a hacer un amigo suyo (probablemente gratis). Ya se pueden abonar los siguientes gastos: +++La mitad pendiente de la cocina.............1160 euros +++Los electrodomésticos.......................1705 eurosa +++Cables y canaletas.......................... 20 euros TOTAL..........................................2885 EUROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='PILAR'and apellido2='ROJO'),'2012-01-04','Conversación con Mª Eugenia (CSS Mérida). Fallecimiento de D. Isidoro el pasado 31 de diciembre de 2011. La sobrina con la que se contactó desde el CSS no quiso saber nada al respecto. Fue enterrado en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='PEREZ'and apellido2='GARCIA'),'2012-01-04','Se recibe Informe Social de Roicío García Amaya, Trabajadora Social de "Hogar Siloé" (956-237146).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2012-01-04','Conversación con Lucía, Encargada de la Residencia. Dª Encarnación planteó algunas dificultades para irse a su pueblo: quería llevarse todas sus pertenencias porque no quería volver. SE le convenció finalmente. A la vuelta estaba triste porque no había podido ver su casa: su hijo se lo había impedido. Se quejaba de que había comido mal (¿poco?) y ha vuelto constipada. Queda pendiente concretar don Futuex la psosibilidad de visitas alternas de Encarnación y su hija Antonia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2012-01-04','Conversación con Mª José (Asindi). Se realizó el traslado ayer, día 3 de enero. Llegaron sin equipaje, tan solo con una bolas con las medicinas y las pautas de tratamiento. El Equipaje se quedó entre Asindi y Apba. 6 en dejarlo en el Ayuntamiento de Villanueva del Fresno, dado que la recogida de los hermanos se haría en el domicilio familiar. Mª José dice que no ha sido capaz de hablar con nadie del Ayto. que sepa algo del equipoje de Isabel e Iganacio. Julián, de Apba. 6, está tratando de averiguar lo sucedido. Me llamará para indicarnos si ha aparecido o no. Los dos hermanos llegaron algo desaseados, con lo puesto. Han dormido bien los dos: Ignacio está contento, pero su hermana demandaba mucha afectividad cuando llegó, pero ya ha empezado a hablar con otros chicos y chicas del Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2012-01-04','Conversación con Mª José (Asindi). Se realizó el traslado ayer, día 3 de enero. Llegaron sin equipaje, tan solo con una bolas con las medicinas y las pautas de tratamiento. El Equipaje se quedó entre Asindi y Apba. 6 en dejarlo en el Ayuntamiento de Villanueva del Fresno, dado que la recogida de los hermanos se haría en el domicilio familiar. Mª José dice que no ha sido capaz de hablar con nadie del Ayto. que sepa algo del equipoje de Isabel e Iganacio. Julián, de Apba. 6, está tratando de averiguar lo sucedido. Me llamará para indicarnos si ha aparecido o no. Los dos hermanos llegaron algo desaseados, con lo puesto. Han dormido bien los dos: Ignacio está contento, pero su hermana demandaba mucha afectividad cuando llegó, pero ya ha empezado a hablar con otros chicos y chicas del Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='GARCIA'and apellido2='SANTOS'),'2012-01-12','SE HA SOLICITADO ASISTENCIA JURIDICA GRATUITA PARA RECLAMAR LA INDEMNIZACIÓN POR ABUSOS SEXUALES CONTINUADOS A LOS HEREDEROS DEL CONDENADO FALLECIDO.','2');
