insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='ESCOBAR'and apellido2='MACIAS'),'2012-01-13','SE SOLICITA AUTORIZACIÓN JUDICIAL PARA ACEPTACIÓN DE HERENCIA DE SUS TIAS PATERNAS','2');
