insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2012-01-13','SE DA LA ORDEN DE PAGO A ASINDI, SE PAGARÁN 268 MÁS 30 € DE GASTOS PERSONALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-01-17','Conversación con Mar, T. Social del CAMP. Siguen sin noticias de Jesús. Se le indica que se envió Informe de fecha 05 de enero al Juzgado de 1ª Instancia Nº 4 de Badajoz comunicando esta situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-01-16','Ángel se presenta en la CTAEx a las 8.30 de la mañana. Se marchó de Aprosuba con la bicicleta el domingo por la mañana y pasó la noche en el Centro de Transeúntes "Padre Cristobal" de Mérida. Quiere 200 euros para tabaco e irse en el tren. Denuncia una situación de posibles abusos. Nos trasladamos con él a Villanueva para hablar de ello con la Directora del Centro. Planteamos el caso al Coordinador de la Fiscalía de Villanueva, y quedamos pendientes de una nueva reunión con la Fiscal el miércoles día 18 de enero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-01-17','Ángel se presenta nuevamente en CTAEx a las 8.45 de la mañana, con las mismas peticiones que ayer. También ha venido con la bicicleta. Se informa a la Directora del Centro. Se marchó de Aprosuba cuando abandonamos el centro ayer por la mañana. No quiere volver en taxi: quiere irse en tren y con dinero para tabaco (200 euros). Ante su negativa a volver al centro, se pone en conocimiento del Juzgado de 1ª Instancia nº 2 de Villanueva de la Serena esta circunstancia mediante fax. No obstante, se le consigue convencer del traslado en taxi, dando cuenta nuevamente al Juzgado de esta circunstancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2012-01-17','Llamada de Dª Antonia Canelada. Se ha marchado del CRR y ahora está en su pueblo con el señor José. Se ha marchado porque otro residente del CRR la está maltratando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2012-01-20','SE ABONAN 300 € AL CONQUISTADOR PARA PAGO DE LA DEUDA QUEDAN PENDIENTES 2194 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2012-01-24','Comunicación con Juzgado de lo penal nº 1 de Villafranca de los Barros. Cuetsión planteada: Miguel quiere retirar la denuncia que en su día interpuso contra su padre, según nos informa Soledad Olmos. No se puede retirar la denuncia en este momento del procedimiento por cuanto se trata de una comparecencia para declarar, estando también ciatado para reconocimiento médico-forense. Hay que acudir a la citación y plantear allí la posible retirada de la denuncia. Se comunica dicha información a Soledad (924-237551).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2012-01-24','Conversación con Daniel Cuenca Silva (606-900058). El cree que no tiene las Escrituras del piso. En cualquier caso, asegura que en las mismas siguen figurando sus padres como propietarios del mismo ya que nunca se cambiaron. Es en el Testamento donde se recoge que se deja el usufructo de la vivienda a D. José y que, a su fallecimiento, la propiedad pasa al resto de los hermanos. Buscará esa documentación y nos la hará llegar. Respecto a que su sobrino, el hijo de David, ocupe el piso no están de acuerdo ninguno de los hermanos, "...y menos mpor la cara, como pretende mi hermano..." Ya en tiempos les quitó a a mis padres todo el dinero que quiso de la cuenta...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2012-01-24','- se solicita al INSS badajoz reclamación sobre la baja de su P. orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2011-01-24','-concedida plaza en Asindi , se avisa a Sonia . -llamo a su hno. Jose Maria , prefiere ser él el que se lo comunique a su hna. para evitar que se ponga nerviosa. -hablo con Conchi , TS, Victoria quiere ir ya a un centro , ella estará en el traslado . -Gestionado tte. con Cruz Roja para el lunes dia 30 de enero .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2011-01-24','-se ha solicitado al Juzgado por parte del CSS Plasencia , cambio de la medida de institucionalización para pasar a tto. ambulatorio seguido en el ESM de Caceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2012-01-24','- se celebra el juicio por denuncia de malos tratos de la madre . Se acuerdan : 45 dias de servicio en la comunidad y 1 año de alejamiento de J.Manuel a más de 200 metros y ningun tipo de comunicacion .','2');
