insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2012-01-24','- se comunica a Dependencia el cambio de prestación de incapacidad pte. que venia percibiendo Lázaro , que pasa a ser de 481€ a 785 €. ( consultar en su expediente el informe que se hizo a la Unidad de dependencia solicitando plaza residencial ) .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2012-01-24','- se ha escapado del CAMP y se ha ido a su casa . - Se manda autorización al centro para q pase en casa unas vacaciones con su madre ( tf.678284973) -Tenemos que ir a visitarle y reconsiderar la vuelta al CAMP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2012-01-30','El traslado de Victoria se hizo con Cruz Roja el día 30 de enero de 2012 y lo pagamos íntegro nosotros de su dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2012-01-30','RECIBIMOS UNA OFERTA DE LA CONSEJERÍA DE FOMENTO PARA PODER ADQUIRIR EN PROPIEDAD LA VIVIENDA DE MARIA LUISA, LLAMAMOS PARA INFORMARNOS PERO NOS DICEN QUE HAY QUE ESTAR AL CORRIENTE DE PAGO DE LOS RECIBOS. PUESTOS EN CONTACTO CON EL OAR NOS COMUNICAN QUE LA DEUDA DE MARIA LUISA ASCIENDE 7385,59 DE RECIBOS DE ALQUILER Y ADEMÁS UNOS 5000 € DE AGUA Y DE COCHE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2012-01-30','Ati se presenta ayer en el despacho. Quiere cambiar la cerradura de su piso y la de la puerta de la comunidad. Se le indica que la del piso solo tiene que decírselo a su casero para que se lo autorice y la de la Comunidad es asunto de su Presidente. Dice que han entrado en su casa y le han quitado varias cosas...sin decir cuáles cuando se le pregunta. Menciona que han tenido que ser o Joaquina (que se supone sigue en Bartcelona, o sus hermanos, que son los únicos que tienen llave). "Con mi padre he roto la relación". Se niega a poner denuncia a pesar de insistirle en la conveniencia de ello. Su negativa es rotunda. ¿Veracidad de estos hechos?. Pendiente de hablar con Leonor, Enfermera del ESM de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2011-01-30','- Nos llama por tf Javier desde " Hogar 2000" tf.925224318 para pedirnos un cambio de centro , le han sancionado y no quiere cumplir la medida impuesta. Tras contactar con Adelina ( TS ) me explica que ha sido sancionado por consumir y vender psicofarmacos en el centro a 6 meses sin salidas . No se acepta la peticion de centro ,justificando la medida . A los dias hago seguimiento y Javier ha cambiado de opinión , quiere continuar en el centro aunque está serio por la medida que tiene que cumplir .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2011-01-31','- Pedro y Amalia visitan la R.M. la Esperanza de Albalá para conocer la situación de Rosario. Está ocupando plaza de válidos y por su empeoramiento de salud necesita pasar a plaza de asistidos. Se solicita cambio de PIA y revisión de grado y nivel .','2');
