insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2012-02-08','Conversación telefónica con Patricia (Directora Residencia).675-679677. 927-382097. Último incidente: Dª Rosario empujó a otra residente, cayendo la señora al suelo y fracturándose una cadera. Recomendaciones mientras gestionamos posible cambio de plaza o Residencia: **pedir cita a su Médico y que la derive al ESM de Cáceres. **llamar al 112 en el momento que se produzca la agresión y que la ingresen en UHB. Comunicando ingreso al Juzagado en las siguientes 24h. Se solicita Informe sobre todas aquellas incidencias protagonizadas por Dª Rosario, incluidos informes médicos, que puedan justificar soliciotar al Juzgado internamiento involuntario. Lo envirán, a ser posible esta semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='SANCHEZ'and apellido2='BANDA'),'2012-02-09','TIENE SEGURO DE DEFUNCIÓN CON SANTA LUCIA','2');
