insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-02-03','Fue llevado de nuevo al CAMP el viernes 3 de febrero, acompañado por la Policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-02-10','Conversación telefónica con Dª Mª José Vázquez Díaz. Desde el despacho del Programa de Familia (Reme, 924272790). Desea remover la tutela de su hermano y hacerse cargo de él, porque "...él dice que no está bien en ese Centro, que quiere estar con su familia. Y a mí se me cae el alma al suelo cuando lo oigo llorar..." Se le informa de lo que debe hacer para solicitarlo al Juzgado, a la vez que se le trata de hacer comprender que, dadas las caracteristicas de su hemano, es una persona que necesita una atención profesional, que no puede estar dando tumbos por su cuenta y riesgo, tanto por su propia seguridad, como por la de terceros, que necesita el control estricto de su tratamiento, el control de conducta, etc. Reme tampoco considera una buena idea que su hermana asuma la tutela, con el riesgo adicional del entorno en el que viviría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2012-02-10','Conversación con Álvaro, Psquiatra del CSS Mérida. Hoy deriva a Ati a UME durante 2 ó 3 semanas, antes de que vuelva a su piso. Quedamos en ir a por él el lunes a las 10:30 para llevarlo a su piso a por la ropa que necesite. Nos acompañará un auxiliar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATIAS'and edp.apellido1='NIETO'and apellido2='CRUZ'),'2012-02-09','Acompañamiento de D. Matías al ESM de Cáceres. Lo acompañaban también su hermana y Justo, con quien dijo que quería ir. (Futuex) La consultya era de Enfermería. Lo atendió Joaquín, quien tras la entrevista también era de la opinión de que no estaba para cumplir trabajos a la Comunidad. Le pareció acertada la alternativa planteada por CTAEx: solicitar al Juez sustituir los 31 días de trabajo por e4l cumplimiento exacto de las visitas programadas por el ESM. Este mismo día acudimos también a S.S. Penitenciarios, donde hablamos con la Trabajadora Social, Nati. Cuando se enteró de que habían pagado ya la multa de 1080 euros, hizo algunas consultas al Juzgado: ++La modificación del C. Penal de dicembre del 2010 había beneficiado a D. Matías, por lo que había un Auto del Juzgado, no comunicado a él, por el que se suspendía la pena de multa y solo permanecía la de los 31 días de trabajos. ++Planteó al juzgado la posibilidad de no tener que cumplir estos trabajos al haber pagado ya la multa: queda a la espera de que el Juzgado se pronuncie al respecto. En cualquier caso, y hasta tener respuesta al respecto, a D. Matías no se le ha dicho nada al respecto para tratar de garantizar que, a partir de ahora, cumpla con lo controles en Salud Mental. Este caso es propuesto para valoración de Comisión de Salud Mental con derivación a CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2012-02-09','Ingreso en Hospital Infanta Cristina ayer, 9 de febrero, por intento autolítico. A las 13:20h de hoy sigue ingresado en observación en la UHB. Pdte. de hablar con la Médico a las 14h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-02-10','Conversación telefónica con Ester, T. Social CAMP. Jesús se ha vuelto a escapar hace unas dos horas, sobre las 12:00h. Se ha puesto la correspondiente denuncia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='GARCIA'and apellido2='SANTOS'),'2012-02-14','Entrevista con D. Juan José Aparicio González, abogado del Turno de Oficio asignado a nuestra Tutelada (Teléfono y fax: 924-330607). Se le informa sobre el caso a defender y se le entrega copia de la siguiente documentación:Auto en el que se asigna a la CTAEx el cargo de Tutor, Aceptación del cargo, Certificado Grado de Discapacidad, Sentencia 164/2009 y Auto de extinción de responsabilidad criminal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2012-02-14','Conversación telefónica con D. Francisco Bueno Guisado, hermano de Dª Juana(617-836710). Respecto al contrato de compraventa del olivar, está de acuerdo en devolver al comprador los 901.51 euros que éste entregó en concepto de arras. No obstante, ha de consultarlo con su otro hermano para ver si también está de acuerdo. Esperamos su llamada para dejar terminada esta cuestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2012-02-17','Está solicitada Ley de Dependencia. Falta que le valoren','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2011-02-16','-Amalia realiza visita a la R. M. " La Soledad " ó Hnas de los ancianos desamparados . Mantengo entrevista con la TS , Eva ( 924255503).Ella desconoce el problema de Andrea , la persona que la supervisa y dispone es Sor Isabel . No entiende la tutela , está en contra de que la Junta administre sus bienes y no colabora con nosotros . Le recalco la necesidad de solicitar nuestra autorización para las salidas de Andrea , que se va los dias que que quiere a su casa que no dispone de condiciones de habitabilidad ni agua . Va sin dinero y sin comida .Come de lo que le llevan las vecinas y va a por agua a una fuente cercana del domicilio. Andrea entrega la pension integra a la cuenta de la congregación , de ello Sor Isabel dice que le da 100€/ mes de lo que paga la luz , le da en persona a una vecina lo que paga por seguro de defunción , más el taxi de ida y vuelta . No se compra nunca ropa ni nada . Estamos ptes. del Informe de Salud para solicitar LAAD pero desde la residencia siguen sin facilitarlo , la tienen q llevar a su medico de cabecera , pero como son una entidad no acreditada y saben que no recibirán ningún beneficio , no nos lo dan , además temen q la saquemos a otra R.M. Sor Isbel solicita q le vendamos algunos de sus bienes y les entreguemos el dinero a ellas . Aseguran que está integrada y a gusto y que no quiere irse de allí. No puedo hablar con Andrea , ante la negativa de esta a acercarse. -Pedro y Amalia realizan visita al SSB de Ftue. del Maestre y mantenemos entrevista con Antonio Nisa y sus dos sobrinas . La situación cuando va al pueblo es lamentable . Solicitan cambio de recurso y que sea traslada a una residencia pública. Quedamos pte. con Antonio la posibilidad de que Andrea pueda pasar estancias temporales en la residencia de la localidad , privada de orden religioso. Se le va a solicitar residencia pública.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2012-02-16','-Visitamos a Hermenegildo en su casa para convencerle para que vuelva al Camp. Nos reunimos ( Pedro y Amalia ) previamente con la TS del SSB y allí mismo con una tia suya ( Rosa ) . Madre e hijo quieren q el chico se quede en el domicilio familiar , ayudando a su madre ya mayor y trabajando unas horas con un señor ( Manolo " Lisboa " ) cuidando caballos . Tras horas de conversación los convencemos para que la proxima semana regrese ( se irá en tren ) a cambio solicita : no castigo en en centro por la fuga , 10 € por el trabajo que hace en T.O. al igual que le dan a su compañero Agustín y tener más visitas a su casa . Solicita cambio para Aprosuba 11 . La casa está en malas condiciones , vivienda de promoción publica con barreras arquitectocinas. Su madre ha habilitado una habitación y allí comen , durmen... Estaba limpio .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2012-02-20','Comversación con Patricia (Directora Residencia Albalá). Dª Rosario se ha caído esta mañana. Están esperando al Médico. Creen que puede tener fractura de cadera (¿?). Me llamará cuando llegue el Médico. Se le propone que pida a éste/a que solicite también consulta en ESM para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='GARCIA'and apellido2='SANTOS'),'2012-02-20','Nueva asignación de Abogada del Turno de Oficio: Dª Yolanda Torres Hurtado (924-802483) en sustitución de D. Juan José Aparicio Glez. por baja laboral de éste.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATIAS'and edp.apellido1='NIETO'and apellido2='CRUZ'),'2012-02-18','Nati, T. Social de SS Penitenciarios de Cáceres. Nos comunica que D. Matías notendrá que cumplir los trabajos en beneficio de la comunidad. Cuando tenga el Auto del Juzgado nos lo hará llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATIAS'and edp.apellido1='NIETO'and apellido2='CRUZ'),'2012-02-20','Se informa a Dª Maribel, hermana de D. Matías, la decisión del Juzgado de que su hermano no cumpla los servicios a la comunidad, conmutándolos por la multa que ya fue pagada con anterioridad por su madre y hermana. Se les pide que mantengan, en la medida de lo posible, esta circunstancia fuera del conocimiento de D. Matías, para tratar de garantizar así su seguimiento en ESM de Cáceres, al menos de momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GUDIÑO'and apellido2='CACERES'),'2012-02-20','D. Ángel se ha escapado del CSS de Mérida esta mañana. Se le locliza en el Hogar de Transeúntes de Cáceres, de donde es trasladado por Cruz Roja al H. Virgen de la Montaña. Del Hospital se escapa nuevamente, y nos llaman de la sucursal de Caja Badajoz (Avda. Virgen de la Montaña 6) donde se encuentra. Llamamos al Hospital y al 112 para ir a recogerlo, activándose el protocolo establecido, con la finalidad de llevarlo nuevamente al CSS desde el Hospital Virgen de la Montaña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2012-02-20','Conversación telefónica con Dª Cristina, sobrina de D. Pedro. Se le informa de la imposibilidad de que su tío les pueda "prestar" 3000 euros para la compra de un coche, en opinión de CTAEx: "...No, si nosotros con el Wolsvaguen que tenemos para los cuatro nos es suficiente. Si lo hacíamos era para que él, cuando nos vamos los cinco, fuese más cómodo ...". Manifiesta su intención de hacerse ecargo de la Curatela de su tío porque "...Total, estoy encargándome de su cuidado y lo único que hacerme cargo de él (legalmente)me supondría es el gestionar su dinero...". Se le informa de los pasos a dar para solictar este punto en el Juzgado, como ya se le explicó en ocasiones anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2012-02-21','Conversación telefónica con Dra. Marisol (C. Salud de valverde de Burguillos). Ha podido comprobar que en el pueblo no compran alcohol, pero no sabe si puden consumir algo en Zafra: "...Me dijeron que habían visto al padre bebiendo una cerveza...". Han ido al CEDEX y han quedado en hacerles un control de orina todos los viernes (sin que ellos sean conscientes de los motivos). No han vuelto a dar problemas desde su regreso al pueblo. Está pendiente de confirmar su visita a ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2011-02-21','-LLamo a la TS de aprosuba 11 para hablar sobre la situación de Rosa , hna. de Hermenegildo y tutelada por su madre. Su hna. va a CO de 9.00 a 18.00 h. come allí y regresa a su domicilio . Va cuando quiere , la situación en casa en problematica , con intento de abuso sexual por parte de otro hno. alcoholico q su made ha echado del domicilio y vive en una carabana . No cree q nuestro tutelado asistiera a CO . Conoce a Manolo " Lisboa " , dice que es buena persona pero q no sale de los bares , no es buena influencia. A veces se van a pasar unos meses con otra hija que tiene en Ciudad Real y no asiste al centor...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2011-02-21','No es posible solicitar plaza en residencia publica sin La valoracion de dependencia . Podemos pedirla al medico del AP de Fuente del Maestre como otra opción, puesto que las monjas no nos lo facilitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2012-02-23','SE HACE LA TRANSFERENCIA PERMANENTE MENSUAL A ASINDI POR EL 75% DE SU PENSIÓN QUE SON 761,40 € ADEMÁS LES INGRESAMOS 100€ PARA GASTOS PERSONALES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2012-02-23','SE SOLICITA EL CAMBIO DE DOMICILIACIÓN DE LA PENSIÓN NO CONTRIBUTIVA A LA CUENTA QUE LE HEMOS ABIERTO EN CAJA BADAJOZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDO'and edp.apellido1='IGLESIAS'and apellido2='DOMINGUEZ'),'2012-02-22','Visita domiciliaria. La Pesga. No tienen teléfono. Acompañado por Mª José, T. Social del SSB. Dª Consuelo venía en esos momentos de hacer la compra. D. Segundo estaba acostado y aydamos a su mujer a levantarlo y sentarlo en una silla, maniobra que hace sola ella habitualmente y para la que su marido no puede colaborar en nada. Cuando está su hijo Enrique le echa una mano. Nos comunicamos con D. Segundo a base de presión en un dedo de mi mano metido en la suya. Apenas habla y con esfuerzo respondió sí en una ocasión. La vivienda no reune las condiciones necesarias para tener a una persona en esas condiciones, e incluso para su mujer la ausencia de barandilla en el acceso a la escalera que está frente a la cocina es un peligro evidente y elevado. El dormitorio de D. segundo está en la planta 2ª: no sale de allí desde hace tres años. Los tobillos los tenía protegidos con un pañal para evitar escaras, de las que una aparecía en la planta del pie izdo. en proceso de curación. Parece existir una gran afectividad netre la pareja, aunque, como dicew su mujer, en ocasiones se enfada mucho con ella. Conclusiones: **D. Segundo aceptó la propuesta de solicitarle plaza en la Residencia de la Pesga. **La T. Social le llevará la solicitud para que la pueda firmar (huella) y también la solictud de cambio de PIA (prestación vinculada a servicio residencial). Dª Consuelo, que anteriormente se había opuesto a cualquier tipo de ayuda externa, no puso ninguna objección a esta solución. No solo eso, sino que incluso la vió bien. También hablamos con D. Enrique, que llegó del campo, y que también aceptó está solución. Por teléfono hablamos con D. José Luis, hijo de D. Segundo y Dª Consuelo que vive en Sevilla: quedamos con él en tener una reunión el próximo martes 28 de febrero en Mérida. En el Centro de Salud hablamos con Emi, Enfermera que conoce a la familia desde hace tiempo. Le parecíó una buena solución y quedamos en que la médico valoraría una derivación de D. Segundo al Hospital de Plasencia al Servicio de Cardiología, para revisión de la válvula que le pusieron en los años 80 y que, según su mujer, nunca ha vuelto a revisarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='MURILLO'and apellido2='LADERA'),'2012-02-24','se paga al centro la diferencia recibida de los atrasos por la pensión durante el año 2011.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2012-02-24','Visita al domicilio de Dª Carmen en Valdecaballeros. MOTIVO: INCENDIO el pasado día 22 de febrero. Todo el tejado ha quedado prácticamente detruido. El fuego no ha afectado a la planta baja de la vivienda y el doblado aparecía con muebles viejos amontonados (inservibles) y las pareces ennegrecidas por el humo. Al parecer, según nos dijo el Sargento de la Guardia Civil, el fuego se inició en el corral de detrás de la vivienda, al parecer al quemar alguien algo en una esquina, que hizo prender el tejado. Dª Carmen no quiso poner denuncia. Le comenté al Sargento que si sabían de quién era el corral, pero al parecer, dijo, hay un "jaleo" en cuanto a ello considerable, y no saben quien es el propietario. De cualquier forma, le pedí que nos mantuvieran informados si se averiguaba algún fato más. Dejé nuestra tarjeta. Contactamos allí con dos empresas de reformas, a través de Dª Mª Carmen, hija de Dª Carmen. Quedaron en mandarnos los dos presupuestos. Madre e hija se vieron, a petición de aquella. Pero Mª Carmen no quiere mantener relación con ella más allá de que no quiere que le suceda nada malo y que, en lo que pueda, está dispuesta a colaborar con CTAEx siempre que eso no suponga tratar con su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ELOINA'and edp.apellido1='HERNANDEZ'and apellido2='SUAREZ'),'2012-02-27','Conversación con el Dr. Carlos Sanchez Rodilla. Medicina Interna Hospital de Mérida. Dª Eloína tiene un cáncer de pulmón no intervenible ni tratable. Quedo con el Dr. sánchez a las 12:30 en el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2012-02-27','Nos informan del CRR de Plasencia que se ha hecho una permuta de plaza con el CRR de Cáceres en relación a Dª Emilia Morales Botello, por aproximación a sus hijos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='SANZ'and apellido2='BARRAGAN'),'2012-02-27','Ingreso de Dª Isabel Sanz Barragán en el Servicio de Urgencias del Hospital de Mérida. En visita realizada al Servicio, Dª Isabel seguía ingresada en él a las 13:15h. Su Médica me informó de que allí no había tenido el cuadro febril por la que se le había trasladado del Centro Sociosanitario. Tiene un edema pulmonar con un fuerte encharcamiento de los pulmones. Pronóstico: Muy Grave. Son escasas las probabilidades de que supere este proceso. Dejo la dirección y teléfono de CTAEx. Comnunico esta situación a Agustina Gómez, T. Social de Bodonal de la Sierra: informará al marido de Dª Isabel de la misma. Agustina me comunica que al parecer tienen Seguro de Deceso, quizá en Santa Lucía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ELOINA'and edp.apellido1='HERNANDEZ'and apellido2='SUAREZ'),'2012-02-27','Entrevista con el Dr. Carlos Sánchez Rodilla, Médico Internista del Hospital de Mérida. Dª Eloína tiene cáncer de pulmón. la valoración clínica pasa por realizarle dos pruebas, TAC y Endoscopia, para en función de los resultados, proceder a intervenir quirúrgicamente. ***La cita para el TAC es el día 5 de marzo de 2012 a las 16:20h, sala 42 (tc 64c) en la planta baja del Hospital (Servicio de Radiología). ***La cita para la Endoscopia es el día01 de marzo de 2012 a las 08:30h, EN AYUNAS. ***La consulta para dar los resultados es es 20 de marzo de 2012 a las 09:30h, en Consultas Externas (2ª planta). Dr. Carlos Sánchez Rodilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='SANZ'and apellido2='BARRAGAN'),'2012-02-28','Nos comunican a las 08:45h el fallecimiento de Dª Isabel Sanz Barragán. Nos ponemos en contacto con Agustina, T. Social de Bodonal (609-636764) para que le comunique a su marido el fallecimiento de su mujer. Me da el teléfono de Angelines (924-721626/ 654-104007), Agente de la Compañía "Santa Lucía" del Seguro de Deceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2012-02-28','Conversación telefónica con la Notaría de Fuente del Maestre (GARCÍA MORLESÍN). Motivo: comprobar la factura pagada por la hermana de Miguel, Gema, respecto los gastos de Notaría correspondientes a su hermano. La cantidad es correcta (247.50 euros) que efectivamente pago ella. Nos enviarán copia de la Escritura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-02-28','Volvió ayer al CAMP. Pidió el dinero a sus tíos. Hoy ha llamado su hermana para decírnoslo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2012-02-27','Conversación con Dª Dolores, madre de Hermenegildo. Debe volver al CAMP ya. Si no deberemos dar cuenta al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2012-02-28','Hermengildo ha vuelto hoy al CAMP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCOS'and edp.apellido1='GARRIDO'and apellido2='PEREZ'),'2012-02-28','SE PROCEDE A ABONAR LA FACTURA DE LUZ DE 535 €. EL SSB DE CASAS DE D. ANTONIO NOS COMUNICA QUE EL HERMANO DE MARCOS VIVE EN UNA RESIDENCIA DE MAYORES DESDE NOVIEMBRE DE 2011 POR LO QUE CUANDO PASE EL PLAZO PERTINENTE HABRÁ QUE RENUNCIAR A LA VIVIENDA SOCIAL QUE TENÍAN CONCEDIDA LOS DOS HERMANOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2012-02-29','Visita domiciliaria, acompañados por Cristina, T. Social del SSB. Conclusiones de la visita. ***D. Francisco vive solo en un apartamento alquilado. ***No existe relación alguna con sus hermanos, a pesar de la proximidad física entre ellos. ***Carece de relaciones sociales y, al parecer, tampoco lass desea. Se limita a pasear con su perra, única compañía imprescindible para él. ***Sus únicos contactos son con la compañera de los SSB y la del ESM. SALUD. ***Su brazo derecho está en muy malas condiciones, tras siete operaciones y, según nos comenta, varias sesiones de quimioterapia que, al parecer, y según él cuenta, las pruebas realizadas confirmaron no ser necesarias ¿?. ***Refiere molestias de espalda importantes, lo cuál no parece raro al dormir en un sofá en el que apenas tiene sitio. El motivo: necesita apoyarse con el pie en la mesita baja que tiene delante del sofá para levantarse, lo cual es imposible en la cama al no tener esa posibilidad de apoyo. ***Se le informó sobre las Ayudas Técnicas que le podrían facilitar la vida diaria y quedamos en que acudiría con la Aux. del SAD a una Ortopedia para preguntar por ellas. ***Hablaremos con el Dr.Luis Castañón, del Hospital de Plasencia, que fue quien lo opero para saber qué pronóstico tiene su brazo y, además, tratar de adelantar la prueba de RX que tiene en junio y la consulta en julio. ECONOMÍA. ***','2');
