insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2012-03-01','- Llamo al tf de su madre ( Estrella ) para que me informe sobre cómo está Vanesa. Me comenta que está bien , que estuvo en el domiicilio del novio un mes viviendo y que ya está de regrso al domicilio que tienen en Trujillo ,junto con su hermano . Estrella ha roto su relación de pareja . Se mantienen con el poco dinero que ella percibe de algunos trabajos , y acude a por comida a Caritas . Hablo con Vanesa q me dice que se encuentra bien y que no quiere regresar al centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2012-03-01','-Mantengo conversacion tf. con Patricia la Dtra. de la R.M. Rosario ya tiene el alta medica y ha regresado pero en condiciones de total dependencia , necesitando silla de ruedas. -La han pasado a plaza de dependientes , que tiene un precio de 1300€ que tenemos que abonar . Rosario tiene dinero ahorrado . Mientras se resuelve el cambio de grado y nivel ya solicitado tendremos que hacerlo así . -En el caso de que nos concedienran Grado 1.1. con la ayuda de dependencia ( vinculada al servicio ) y su pension abonariamos casi la totalidad de la plaza. -Ya se puede quedar en esa residencia pq ha quedado plaza de dependiente libre al fallecer la señora a la que Rosario cayó .','2');
