insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-03-12','Ángel no se presentó en el Juzgado de 1ª Inst. e Instr. Nº 1 de Villanueva para reconocimiento forense, tal como aseguró que haría en la conversación mantenida con él la semana pasada, en la que nos comunicó que se encontraba en Illescas (aspecto este no confirmado). También se le recordó el reconocimiento del próximo 15 de marzo en el Instituto de Medicna Legal de Badajoz. La semana pasada, y tras dicha conversación, se comunicó mendiante fax al mencionado Juzgado, así como a la Audiencia Provincial de Badajoz (Fiscalía de Villanueva de la Serena) y al Instituto de Medicina Legal de Badajoz, el supuesto paradero de Ángel, no confirmado, y la posibilidad de que no se presentara al exámen forense del día 12 de marzo, así como al del día 15 de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='OBREGON'and apellido2='CAÑAMERO'),'2012-03-12','Se envió la semana pasada contestación al Oficio remitido por el Juzgado de 1ªInstancia Nº 1 de Trujilio en relación a la propuesta de Centro para D. Manuel Obregón Cañamero, remitiendo al Juzgado al E.S.M. de Cáceres, conocedores del caso. Previamente lo hablé con Pilar, T. Social del ESM (695194573). Me confirman desde el Juzgado la recepción de nuestra respuesta y su ya puesta en contacto con el ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2012-03-02','Reunión con Marisa Álvarez y Mª Eugenia, Psiquiatra y T. Social respectivamente del CSS de Mérida e Ildefonso. El alta de Ati no va a ser inmediata, pero no se retrasará tanto como él querría si todo evoluciona como se espera (Ati querría que no fuese antes de Julio). La idea es ir buscando un nuevo piso de alquiler, ya que su permanencia en el actual es totalmente contraproducente para que supere su actual ¿paranoia? respecto a que están entrando continuamente en su piso. Según Marisa, esto probablemete se repita al cabo de cierto tiempo también en cualquier otro lugar en el que viva, dado que es la forma en que se manifiesta su patología. Quedamos en que Ati empezaría a buscar piso y cuando encontrara dos o tres alternativas iríamos con él a verlas. Con un mes de antelación a dejar el piso debemos avisar al propietario (VER CONDICIONES DEL ALQUILER) y contemplar la posibilidadde contratar un guardamuebles hasta que se produzca el alta de CSS. Ati no quiere quedar mal con el actual casero, aspecto en el que insite en varias ocasiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDO'and edp.apellido1='IGLESIAS'and apellido2='DOMINGUEZ'),'2012-03-12','Conversación con Mª José, T. Social de la Pesga. La información que ha podido recabar sobre la situación económica de D. Segundo es que el cobra su pensión en la sucursal de Caja Extremadura de La Pesga. Al parecer, Dª Consuelo, su esposa, ha estado sacando su pensión íntegra -¿desde que somos los tutores de su marido?- ingresándola en una cuenta nueva abierta, al parecer, a tal efecto (((¿quizá por esto no demostraron ni su hijo ni ella oposición alguna al ingreso de D. Segundo en la residencia, como hasta este momento había ocurrido...?))). Actualmente, D. Segundo no dispone de dinero alguno en su cuenta que le pudiera permitir afrontar el pago de la plaza durante el tiempo en que se resolviera el PIA para poder disponer de la Prestación Vinculada a dicho Servicio. Pediremos extracto de la cuenta de D. Segundo a Caja Extremadura desde la fecha de la sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2012-03-13','Conversación con Esperanza, T.Social del SSB de Trujillo. Vanesa no ha tenido ningún hijo. La información facilitada al respecto por su novio, del C. E. Empleo de "La Encomienda", no es cierta, a pesar de la fotografía mostrada,de los detalles dados por él (nació a los 8 meses, le da biberón, etc.). Maribel tratará de averiguar por qué este chico ha referido esta historia.','2');
