insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2012-03-13','Cierre de la Residencia el Conquistador: fecha límite el 30 de abril de 2011. Hablé con Mª León para que se tuviera en cuenta la situación de Dª Dolores y su hermana Dª Sofía a la hora de trasladar de centro a ambas, y ello tanto por estar Dª Dolores ocupando plaza privada y su hermana concertada, como por la necesidad de mantener a ambas juntas en el mismo Centro.','2');
