insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2012-03-19','-Se le ha gestionado LAAD con la intención de negociar en el PIA acceso a plaza residencial de discapacidad . Igual q en Ctros. de mayores existen las 2 vias de acceso , o por el D 45/ 2002 o via Ley 14 / 2009 . No hago solicitud de centro pq me acogeré a la segunda via . Quedo pte. de resolucion de Grado y nivel y PIA.','2');
