insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2012-03-19','Conversación telefónica con Beatriz, T. Social del SSB de Quintana de la Serena. Considera que la propuesta de visitar a Dª Mª FE la semana que viene puede ser precipitada: la situación actual está en una relativa calma. Sus hermnos también tienen procedimientos de incapacitación abiertos desde febrero de 2011. El temor de Beatriz es que la hermana de ellos, Juana, si vamos a ver a Mª Fe, empiece a "moverse" para solicitar la tutela de sus hermanos o impedirla, cuando se entere de en qué consiste la misma. Nos llamará Beatriz si hay alguna incidencia en las próximas semanas.','2');
