insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2012-03-22','-se tramita prestación vinculada en PIA con G. 2.2 y quedamos pte. de la revision del grado . Se envía a Albalá Resolución de Grado y Nivel(G II N 2) por fax y correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='PEDRERA'and apellido2='SANGUINO'),'2012-03-21','VISITA DOMICILIARIA acompañados por Estrella, T. Social de Malpartida de Cáceres. Llegamos a las 9:15 a casa de D. Eusebio, tras pasar pr el despacho de Estrella. Estaba saliendo con el coche: "Ya me iba, porque como no venían y me dijeron que estarían aquí a las 9:00h". En estos momentos D. Eusebio se encuentra bien (estable). la conversación mantenida con él fué correcta: se le explicó en qué consistía la curatela que ejercíamos sobre, nos informó de las deudas que tebnía pendientes (3 años para terminar de pagar el coche y unos 60 euros para terminar de pagar un sillón ergonómico). La vivienda, de dos plantas, estaba en malas condiciones de higiene y limpieza, ropa amontonada sobre las camas y el sofá, desorden. Nuevamente ha aceptado el SAD (la primera intervención fue el día anterior)y le llevan la comida a casa (tenía la fiambrera en la puerta para que se la recogiesen cuando llegarán).Pudimos confirmar en el ESM de Cáceres que acude regularmente a las citas programadas (nos avisarán si en algún momento no acude a ellas). Hablamos también con Dª Antonia, la hermana de D. Eusebio y anterior Curadora. Sigue muy preocupada por su hermano. Ella quiere que cuando entre en crisis lo tengan ingresado un mes y medio o dos "...que es lo que tengo comprobado que le duran a él las crisis. Pero lo he hablado con la Psiquiatra cada vez que ha ingresado (en ocasiones a petición de D. Eusebio) y dice que ella, una vez que se encuentra estable, le tiene que dar el alta...Y luego pasa lo que pasa, que a los dos días ha tenido que volver a ingresar..." Plan de Intervención. De momento, D. Eusebio puede permanecer en su entorno si se da continuidad en el control desde ESM, y en adherencia al tratamiento. ***Control por ESM de Cáceres de la asistencia a las consultas programadas. ***Supervisión desde el SSB de la situación general de D. Eusebio, especialmente de la aceptación de la intervención del SAD. ***Contactos con Dª Antonia cuando ella perciba también síntomas de crisis inminente. ***Ante situaciones de crisis, activar el 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2011-03-21','-acudimos Pedro y Amalia a comision en el ESM de Caceres , con la psiquiatra, Pliar TS y Jorge del CRR para estudiar cambio de recurso. Se decide solicitar acceso por parte de la psiquiatra a la URH del CSS de Plasencia .Enviarán toda la documentación y los informes médicos que justifican tal medida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='PEDRERA'and apellido2='SANGUINO'),'2011-03-21','-La sentencia de esta curatela , detalla que somos responsables de su tratamiento médico en situaciones de crisis . Ante una crisis podemos activar nosotros directamente el 112 adjuntando la sentencia ó solicitar al médico de cabecera que proceda a activarlo él .','2');
