insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2012-03-20','-valorado con un Grado II.1. Esta derivado por su psiquiatra de CSS Merida a CRR ( puesto 27 ) y a Piso Supervisado desde el 13 de este mes . Se valorará para este recurso y se eligirá entre uno y otro , son incompatibles ambas listas . Quedo pendiente de esta confirmación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2012-03-23','-aprobada la PF con 357,70€/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2012-03-23','-Se solicita a SS , cambio de titularidad y de cuenta de la PF y de la P. Orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='FRUTOS'and apellido2='DORADO'),'2012-03-22','VISITA DOMICILIARIA. Realizada en compañía de Nieves, T. Social del C. Salud. D. Ignacio nos recibió en la puerta de su casa, donde estaba discutiendo con unas personas. Aspecto físico. Físicamente sano, de constitución fuerte y ágil. Barba muy poblada,larga y sucia. Evidente falta de higiene general: ropa sucia, vestía chaqueta de mono de trabajo, un jersey, pantalones de trabajo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2012-03-26','SE PIDE CERTIFICADO AL REGISTRO DE LA PROPIEDAD PARA VER LA SITUACIÓN REAL DE LA VIVIENDA DE LOGROSÁN','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-03-26','Se comunica al Juzgado la vuelta de Jesús al CAMP de "Nuestra Señora de las Cruces" el pasado día 20 de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-03-26','Se intenta dos veces localizar a Ángel en su teléfono móvil: nunca está disponible, tampoco la pasada semana cuando lo intenté varias veces.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2012-03-27','Citación judicial en el juzgado de instrucción nº2 de Badajoz, para tomar declaración sobre los hechos producidos en Fuente del Maestre, consecuencia de consumo de sustancias toxicas y la asistencia sanitaria recibida en el Hospital de Zafra. (copia de la declaración en su expediente). Citado para examen por medico Forense el día 11 de abril a las 11:30 horas en Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2012-03-27','Visita domiciliaria para comunicarle la disponibilidad de plaza en Centro Residencial en la localidad de Casar de Hurdes. Reticente a la propuesta de ingreso en Residencia, acepta ir a conocer el Centro y si le gusta, la posibilidad de “probar”. Se le informa que una vez ingrese en el Centro situado en Casar de las Hurdes, hay la posibilidad de solicitar un posterior traslado a otro Centro de la Comunidad Autónoma, ya que refiere no estar muy conforme con la ubicación del Centro. Demanda manejar el importe integro de su ingresos, dejando una cantidad para hacer frente a los distintos recibos domiciliados, disponiendo de 1000 € al mes, fraccionado los mismos en reintegros de 250 € semanales. Se acuerda dedicar el mes de abril al acceso al recurso residencial. Respecto a la demanda económica se aplaza para el mes de mayo, en función de la aceptación y adaptación del recurso residencial. A medida que avanza la entrevista sus pretensiones se van centrando más en la demanda económica. Se encuentra presente en el domicilio un señor, llamado Manolo, el cual es presentado como tío de Juan, quien manifiesta que Juan se encuentra ahora bien, siendo él la persona encargada de la supervisión del mismo. Manolo en todo momento trasmite a Juan estar de acuerdo con las propuestas realizadas por los miembros de la comisión. Igualmente se encuentra en el domicilio la T. Social del Ayuntamiento (Ana), para hacer valoración de la prestación del SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='OBREGON'and apellido2='CAÑAMERO'),'2012-03-28','Conversación mantenida con el Juez del Juzgado de 1ª Instancia e Instruccióm nº 1 de Trujillo, D. Javier Carreño Sánchez. Pendiente de dictar sentencia en el procedimiento de incapacitación a la espera de Centro de Internamiento como medida cautelar. Se le informa de que la alternativa de CRR supone un medio abierto para un internamiento involuntario. El Juez comenta que, si bien es involuntario, D. Manuel, que ya ha estado en el CSS de Plasencia, no pondría ningún inconveniente en quedarse en él, no cree que se fuese a marchar y tampoco que de problemas de convivencia. Es consciente de la lista de espera existente y no sabe si la existencia de una orden judicial podría solventar dicho problema. Se le indica que se está estudiando el caso desde la coordinación para darle respuesta lo antes posible, respuesta que, como ya sabe, no depende de la CTAEx:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2012-03-28','Contacto telefonico con Juan, manifestando que NO esta "conforme" con el ingreso en la Resicdencia de Casar de Hurdes, ni él ni sus hermanas. Hace referencia de estar muy largo y que desde aquí se le estan arregalndo lo de la paga, como así se expuso en la entrevista mantenida en el día de ayer. Solamente desa ingreso en Centro Residencial en Cáceres o Badajoz, y "mas bien en Badajoz". Irá al fiscal para preparar los papeles..... Se le informa que no pude tomar ninguna decisión sin previa autorizacion por parte de la Comisión Tutelar, refiriendo que una vez tenga prepardos todos los papeles nos los remitira. Insiste en residencia en Badajoz y mientras sea concedida permanecerá en su domicilio, en las condiciones estipuladas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2012-03-28','Venta de inmueble. Notaría de Florencia Tejeda. Se paga a Miguel por parte de la compradora 5000 euros en cheque nominal de la Caixa. Se deposita el día 29 de marzo en la caja fuerte del SEPAD hasta que se habra cuenta en entidad bancaria para su depósito.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2012-03-28','Venta de inmueble. Notaría de Florencia Tejeda. Se paga a Francisco Javier por parte de la compradora 5000 euros en cheque nominal de la Caixa. Se deposita el día 29 de marzo en la caja fuerte del SEPAD hasta que se habra cuenta a Francisco en entidad bancaria para su depósito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2012-03-30','Conversación telefónica con Juan Rodríguez. Tema: plaza concedida en la Residencia de Casares de Hurdes. ***Va a verla "...porque me comprometí a verla, pero de ninguna manera me quedo allí..." . Quiere solicitar plaza en Badajoz, en la Granadilla: "Hablaré con una fiscal y con la ley de dependencia seguro que entro pronto..." No acepta Casares de Hurdes y luego, caso de disconformidad, solicitar cambio de Residencia. ***Tiene que firmar la renuncia de plaza : "No firmo nada por órden de mi hermana. Le mando a ella el papel que sea y si me dice que lo firme lo hago. Pero no firmo nada sin contar con ella..." Tema calentador: ***Necesitamos factura de compra. "¿No vale con un papel firmado? Es que un policía amigo mío me lo va conseguir más barato..." Necesitamos presupuesto y factura de compra. Tema: disposición íntegra de la pensión. ***A partir del 1 de mayo podrá sacar 205 euros semanales. Condiciones: 1)Uso adecuado del dinero. 2)Siempre saldo suficiente en cuenta para gastos domiciliados. 3) En caso de un uso inadecuado de la pensión, se volverá a la restricción de la cuenta. 4)Pagas extraordinarias: se quedarán en la cuenta y de ellas se puede tirar para los gastos de vacaciones. Parece claro que el OBJETIVO de Juan es manejar todo su dinero sin control alguno. Haremos la prueba durante el mes de mayo. COMISIÓN TUTELAR. GESTIONES: ***Pendiente hablar con su hermana María (San Sebastián 943-393633) de todo esto. ***No ir a visitar la Residencia puesto que ha tomado la decisión de no quedarse bajo ningún concepto. ¿Gestionar otra? Probablemente sucederá lo mismo. ***Llamar a la Residencia para hablar sobre el tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2012-04-02','NO PUEDE RETIRAR LOS 80€ CADA QUINCE DÍAS HASTA EL 16 DE ABRIL DE 2012.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2012-04-02','- Tras el cierre de la R.M. " El Conquistador " se procede al traslado de las hnas. a " GERYVIDA " en Caceres . El traslado lo hará el SEPAD por bloques.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-04-02','Se realiza visita domiciliaria acompañados de Auxiliar del Departamento de Trabajo Social del Ayuntamiento de Campanario, y por un miembro de la Policía Local (Alonso). Personados en el domicilia, Antonia muestra desconfianza, accediendo finalmente a que entremos en la vivienda. Se niega a contestar a cualquier pregunta, manifestando que antes debe informarse. Antonia aparece mal vestida y aseada, la ropa sucia, la bata que lleva puesta está muy sucia y deteriorada, como calzada lleva una alpargatas rotas, sin medias ni calcetines. La vivienda presenta un desorden importante, posible síndrome de Diógenes, con gran cantidad de cajas de cartón por las distintas dependencias de la vivienda a las que tenemos acceso. Se niega a mostrarnos el resto de la vivienda. Las dependencias a las que tenemos acceso aparecen limpias pero muy desordenadas. Fuerte olor según se accede a la vivienda. La casa,rehabilitada recientemente, consta de dos plantas,y cuenta con equipamiento. Está situada en el centro del pueblo. Antonia es una persona conocida por los vecinos de la localidad. Desde hace algún tiempo ya no conduce, el vehículo se encuentra aparcado cerca de su casa. No le han renovado el carné de conducir.Se trata de un Citröen Saxo, matrícula 9075 BZZ. Problemas auditivos y ante cualquier pregunta, por elemental que sea, se niega a contestar. Mantenemos entrevista con su medico de familia, quien manifiesta no conocer a Antonia como paciente, la conoce de oídas y de verla ocasionalmente por el pueblo. Posibles alternativas. +++Ya solicitado internamiento involuntario al Juzgado. +++Dada la amplia red de apoyo social que tiene Dª Antonia, otra alternativa, ya que dispone de medios para ello, sería contratar a una persona que le ayudase en las tareas de la casa y supervisión de tratamiento. El problema es que Dª Antonia rechaza cualquier ayuda, sea del tipo que sea. +++Ingreso en residencia: las consecuencias del desarraigo podrían ser perjudiciales para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='FRUTOS'and apellido2='DORADO'),'2012-04-02','Visita domiciliaria sin previo aviso. Personados en el domicilio de Ignacio nos encontramos con la puerta cerrada sin respuesta alguna desde el interior. Un vecino nos informa que no debe estar, que estará en el huerto que nuevamente ha comenzado a cultivar. Nos dirigimos al Centro de salud para hablar con su Medico de Familia (Enrique), quien manifiesta desconocer al paciente, no siendo persona demandante de servicios sanitarios, refiere conocerlo de oídas. Se realiza una segunda visita domiciliaria, siendo un vecino quien nos informa que Ignacio se encuentra en el interior de la vivienda, que estará durmiendo, siendo él personalmente quien insiste llamando a la puerta, finalmente Ignacio abre la puerta y sale de la vivienda, cerrando rápidamente por lo que no accedemos al interior de la misma. Según manifiesta la T. Social del SSB la vivienda no reúne condiciones mínimas de habitabilidad, aportando fotografías. Se mantiene entrevista con Ignacio, quien aparece descalzo, con los pies muy sucios e inflamados, las uñas muy largas y mal vestido y aseado. Ignacio finalmente manifiesta que el día 3/04/2012 se acercará al Centro de Salud para hablar con la T. Social, con la finalidad de poder acceder a otra vivienda, situado en otro entrono de la localidad, con el fin de evitar la situación que esta viviendo con los vecinos. A lo largo de la entrevista Ignacio continua con sus ideas delirantes consecuencia del trastorno que presenta y la falta de tratamiento del mismo. Se pone en conocimiento de Marta T. Social del SSB ya que Nieves la T. Social del Centro de Salud no se encuentra trabajando este día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='FRUTOS'and apellido2='DORADO'),'2012-04-03','Se contacta con el Centro de Salud de Villanueva de la Serena para confirmar la visita de Ignacio, y Nieves T Social informa que Ignacio no se ha presentado en el Centro de Salud en el día de hoy. Igualmente se habla con Marta T. Social del SSB e igualmente refiere que Ignacio no se persono en el día de hoy en las dependencias del SSB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2011-04-03','- Se encuentra en los Pisos Tutelados asociados al CRR de Badajoz . Su padre falleció y su madre está en la Residencia de Mayores de Validos de Caceres. Ha pasado por CEDEX por consumo de drogas y de ahí fue derivado a CRPS de Caceres y al piso del Comité Antisida de Caceres. He pedido informes al CRR Bjoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2012-04-04','-Percibe 357,70€ de P.f + 368,98€ de P.Orfandad , se renunció a un suplemento de la P.orfandad para q pudiera percibir la P.Desempleo. Se le dió de baja a la PF pq venía a su nombre y se le da de alta a nombre de Cristina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2012-04-04','- percibe PNC , no se le puede tramitar PF +Orfandad , pq su grado de discapacidad es bastante posterior ( 2002) al fallecimiento de sus madres .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ORTEGA'and apellido2='SEVILLA'),'2012-04-05','-Mantengo conversacion telefonica con PNC de Burgos . El cambio de titularidad de la PNC está hecho pero la prestación ya se habia cerrado , por eso en Marzo sigue apareciendo Mª Dolores Beltran . En Abril , va a percibir 357,70€ y en Mayo , todos los atrasos desde Nov del 2011 a Marzo de 2012.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2012-04-04','Conversación telefónica. Nuria, Enfermera del ESM de Jerez de los Caballeros. D. Ramón ha ido a ponerse el inyectable, pero al tener que esperar se ha enfadado y se ha marchado sin ponérselo. Nuria, preocupada, nos ha llamado a la Comisión, La indiccación ha sido llamar a la Policía Local, finalmente ha sido la Guardia Civil, y tratar de llevarlo voluntariamente. En caso de mostrarse agresivo, llamarán al 112 para ingreso involuntario. Caso de que en lo que queda de jornada no sea localizado para ponerse el inyectable, Nuria informará a los compañeros del Servicio de Urgencias para que estén pendientes del tema. Le propongo que mantengan con la Guardia Civil su búsqueda para tratar de garantizar el tratamiento durante estos días de Semana Santa y, caso necesario, llamar al 112 y promover su ingreso en UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-04-04','En el día de hoy, hemos recibido llamada telefónica de D. Ángel desde el propio Juzgado Nº 2 de Villanueva de la Serena. Nos comenta que ha vuelto por el Juzgado “...para ver si tenía algo pendiente...”: se le recuerda que no se presentó al reconocimiento médico-forense al que fue citado el pasado día 12 de marzo por el Juzgado de 1ª Instancia e Instrucción Nº 1 de esa localidad, , ni a la cita del Instituto de Medicina Legal de Badajoz el pasado 15 del mismo mes. Se le recuerda que nuevamente está citado en el Instituto de Medicina Legal el próximo día 10 de abril a las 11:00 horas. Dice que al Centro no vuelve, que se va a quedar en casa de su tía en Villanueva. Refiere que ha estado trabajando de feriante en Illescas y en otras localidades y que está esperando “...que me hagan la transferencia del dinero...”. Días atrás, a través de la información bancaria, nos enteramos que había sacado en dos ocasiones dinero, en una 500 euros y en otra 200. Nos pide 200 euros para “...mi tabaco, mis coca colas,...”. Se le indica que una vez que vuelva la Centro podremos hablar de todo ello. Su contestación ha sido: “...Pues si no me autorizas sacar el dinero no vuelvo al Centro...”. Y ha colgado. Comunicamos esta situación a la Directora de Aprosuba 9 en Villanueva. Pasadas unas dos horas, recibimos una llamada desde los Servicios Sociales de Villanueva de la Serena. La Trabajadora Social nos dice que está allí Ángel, que dice estar tutelado por la Comisión, que no tiene dónde ir ni qué comer y que le tenemos que dar dinero. Hablamos nuevamente con Ángel y se le vuelve a indicar que si quiere hacer las cosas correctamente debe volver al Centro y acudir el martes que viene, 10 de abril, al Instituto de Medicina Legal. Entonces podremos plantearnos los temas que él quiera. Al cabo de una hora, más o menos, nos llaman del Centro: Ángel está allí y, ya el lunes, llamarán un taxi para que lo lleve a Badajoz.','2');
