insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-04-10','-No acude a la cita programada en el Instituto Medico Forense de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE VALERIANO'and edp.apellido1='RUBIO'and apellido2='ENCINAS'),'2011-04-10','- Se hace Visita Domiciliaria para conocer este caso y reunión con la TS del ESM de Ciudad Jardín , referente para este caso . -José es el mayor de 4 hermanos , tiene 3 hermanas , la mayor está casada y tiene dos hijos . Las otras dos están solteras , la chica presenta Sindrome Down . Todas viven en Badajoz , zona de Valdepasillas . -José tuvo brote de esquizofrenia a los 24 años asociado a consumo . Habia estudiado Ingenierea Tecnica y estaba trabajando de dependiente en una farmacia . Ante los primeros sintomas y tto. médico se asusta , y se marcha a Fuerteventura sin avisar a nadie. Allí ha permanecido 30 años , viviendo en la calle , pedia a las puertas de un hotel y dormia en la calle. No ha mantenido contacto con nadie en este tiempo .Su familia inicia procedimiento judicial y se le da por fallecido por sentencia . Unas monjas lo encuentran y lo llevan al Hospital donde lo atienden en la Unidad de Psiquiatria. Cuenta que es extremeño y que quiere regresar y el Cabilo Insular paga el viaje de avión a José y un TS q lo acompaña y vuelve a Extremadura. Se ponen en contacto con Carmen Lozano , TS , que es la que gestiona todo el caso . Le busca plaza en el Ctro. Hno. en Badajoz , inicia procedim. incapacitación y le gestiona PNC . Allí ha permanecido un año . -Actualemente vive en un domicilio familiar , creemos que está como inquilino y come en el comedor social . - Plan de intervención : *Prestaciones . se solicita Cdo. de pensiones a PNC *Situación economica :Hay que cambiar la titularidad de las cuentas bancarias y poner límites . *Comida : gestionar comida a domicilio ó Prestacion Vinculada de LAAD para ello . *tareas domésticas : acude a su domicilio un monitor de CRPS para ayudarle a desarrollarlas. *LAAD. Se está pendiente de negociar PIA. *Tema herencia. Ël no quiere que hagamos nada ,no quiere problemas con la familia . *Contacto familiar . Visitas semanales con la familia , mejorando. *Acude a CRPS y a AEMIS , asociacion de Enf. Mentales , por la tarde. *Buena presencia , buen estado higiénico y muy buen estado de limpieza en la vivienda.','2');
