insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2012-04-19','-Visito a Vicente en el CRR . Se encuentra residiendo en los P.A. del CRPS ,gestionados por la misma entidad que el CRR. Muy adaptado al piso y sin ningún problema. Sanitariamente muy compensado , sigue tto. en el ESM de Ciudad Jardín con el Dtor. Fernando Galán y TS , Carmen Lozano. Adherencia al tto. Socialmente integrado , tanto en el piso como en la ciudad. Su padre fue su tutor y ha fallecido recientemente. Hay que proceder al cambio de titularidad de su PF y gestionarle P. Orfandad. Tiene una hna. en Orense ( 679312383 ) con la habla por tf. con frecuencia . Su otro hno. Jesús se encuentra en el CRR . Su madre se encuentra ingresada en RM en Caceres con Alzheimer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GORDILLO'and apellido2='PINTO'),'2012-04-20','-TRAMITADA SOLICITUD LAAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2012-04-19','Visita domiciliaria realizada con Margarita, T. Socal del SSB de Villa del Rey (927-390002). Dª Salvadora (Dori) nos estaba esperando a puerta del despacho de la T. Social. Estaba muy nerviosa y con me vió supuso quién era: "Usted viene para verme a mí, ¿verdad? Soy Salvadora y, mire usted, yo no quiero que me hagan daño, porque estoy solita pero solo quiero que me dejen tranquila..."-todo ello entre lagrimones irreprimibles y una fuerte angustia. Una vez más tranquila pudimos hablar de los siguientes temas: +++ANTONIO, SU "PAREJA" (más de 60 años): tiene absoluta confianza en él y parece ser su único apoyo afectivo. Quiere mantenerlo en la cuenta de Caja de Extremadura a pesar de nuestras dudas de la idonedidad de ello. "Usted no se preocupe, que él no me va a quitar nada. Yo quiero que esté en la cartilla porque cuando me muera quiero que el dinero se lo quede él." +++ENTIDAD BANCARIA. Actualmente en Caja extremadura de Brozas (al parecer canceló la cuenta que tenía en Banesto, lo que hemos de confirmar). Este mes quiere sacar toda la pensión 593,46 euros: "Porque tengo que comprar el pienso para la gallinas y otras cosas..." A partir de mayo, se limitará la cuenta para que saque 400 euros (los quiere sacar todos a primero de mes) y queden 193 para los gastos que se concretan a continuación. Si no da resultado, se "pactó" con ella el sacar 100 euros semanales. +++DEUDAS: la única conocida es con el Ayuntamiento, en concepto de la limpieza que se realizó hace unos meses (844 euros) y de varios recibos pendientes de agua y basura (60.78 euros). En total 904.78 euros. Se le propuso al Secretario y al Alcalde un fraccionamiento para el pago de 50 euros/mes hasta liquidar la deuda, propuesta que fue aceptada a la espera de enviarla por escrito.Se ordenará transferencia a la cuenta del Ayto. indicada. +++RECIBOS e IMPUESTOS: hay que domiciliar luz, agua, basura y el IBI (Diputación de Cáceres). Se pagarán con el dinero restante cada mes en la cuenta, teniendo también en cuenta la extra caso necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BENITO'and edp.apellido1='GILGADO'and apellido2='GALAN'),'2012-04-23','Nieves, T. Social de "Felipe Trigo". Ha ido un señor, José del Pozo?, que dice ser tío de D. Benito, para que éste firme lo que parece ser un alta a terceros y otro documento ¿? para aceptar una herencia. Nos enviará dicha documentación y una dirección de contacto para hablar con D. José.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2012-04-18','Visita domiciliaria a los hermanos Moreno Borreguero. Acompañado por Mª Eugenia y Lola, T. Sociales del C. de Salud y SSB respectivamente. ***Domicilio: no estaba tan mal como esperaba encontrarlo. La habitación de Victoriano estaba bastante arreglada y ordenada (también cerrada con llave). No así la de su hermanos Francisco. Cocinan en un microondas que tienen en la salita, donde también hay un frigorífico que estaba apagado. ***D. Francisco quiere ir a Corporación Oftalmológica en Madrid (902-181828). Un conocido suyo dice que fue operado allí y que recuperó la vista. NO ACEPTA NINGÚN TIPO DE AYUDA HASTA QUE LE DIGAN SI SU VISTA TIENE SOLUICIÓN O NO. Quiere saber si para ir a Madrid tendría que pagar la ambulancia o no. ***D. Victoriano es el que se encarga de su hermano y de las ovejas. Se reconoció cansado y, aparentemente más predispuesto a irse a una residencia "...SIEMPRE QUE ESTUVIESE CON SU HERMANO...". Incluso podría vender el ganado si su hermano lo permitiera, cosa que no permite. ***Dinero: no quiere tener dinero en el banco. Tampoco reconoció tenerlo en casa. *********************************************************** Conclusiones: ***Mª Eugenia recabará los Informes médicos referidos a la vista de D. Francisco y nos los enviará. Hablaremos con los médicos que lo han atendido hasta ahora para valorar las posibilidades de recuperar la vista (si existen) y plantear una visita en el centro que D. Francisco desea. ***D. Victoriano se compromete a estar todos los días de 13 a 13.30 horas en casa para recoger la comida que le llevarán de la residencia. El coste del servicio lo pasarán por el banco donde cobra la pensión. ***Evaluaremos la evolución de la situación a la hora de llevar a cabo otras medidas, y a la espera de la respuesta del Juzgado respecto al Expediente de Jurisdicción Voluntaria en trámite. ***De la visita realizada se desprende, en mi opinión, que D. Francisco y D. Victoriano, a pesar de los problemas de ceguera del primero y de la pérdida de un ojo del segundo, se encuentran físicamente en un estado aceptable de salud e independencia, al igual que desde el punto de vista mental: la conversación con ellos fue fluída y cordial, razonando todo aquello que se les planteaba en todo momento. Su forma de vida responde más a un estilo propio que a una inacapacidadpara valerase por sí mismos, por lo que el internamiento involuntario puede ser una solución a considerar más adelante, cuando las circunstancias empeoren o ellos mismos, voluntariamente, así lo soliciten.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2012-04-12','Visita Martín Domínguez Palencia 12/04/2012 (Curatela) Interno en Centro Socio Sanitario de Plasencia cumpliendo medida judicial Entrevista con T. Social, Psicóloga, Medico psiquiatra e interno. Por parte de T Social y Psicóloga plantean la posibilidad de cambio de medida (demandado por Martín), para cumplir la medida en régimen ambulatorio, residiendo en su domicilio ubicado en la localidad de Cáceres. Por parte del medico se considera que el cambio de medida debería estar condicionado a red de apoyo familiar o comunitario, sin contar con dicha red de apoyo no es aconsejable solicitar cambio de medida. En la entrevista mantenida con Martín refiere que su hermano Jesús quiere asumir su Tutela, dato que el hermano no ha trasmitido ni a los profesionales del Centro ni a la propia Comisión Tutelar. Martín autoriza a miembros de la Camisón a visitar su casa en Cáceres, manifestando que se encuentra muy deteriorada, responsabilizándose el mismo del estado lamentable en el que se encuentra (No tiene luz, agua ni teléfono), informando que no se encuentra en condiciones de habitabilidad. Las llaves de la vivienda se encuentran en el piso de su madre, este fin de semana se las entregará a su hermano Jesús para que junto con miembros de la comisión se realice vista. Respecto al reparto de la herencia, mas o menos los hermanos están de acuerdo, pero este fin de semana con motivo de la salida de Martín, ultimarán los detalles. Desde la Comisión Tutelar se contactará con el hermano para programar la visita a la casa de Martín en Cáceres así como para concretar tema de la herencia e igualmente valorar la implicación de Jesús respecto a la situación de su hermano (asumir la curatela)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='LOPEZ'and apellido2='PILARES'),'2012-04-12','Visita domiciliaria. Maria presenta cuadro delirante. No cuenta con red de apoyo ni social ni familiar. Vivienda en malds condiciones de habitabilidad, carece de equipamiento básico como frigorifico, lavadora, calentador','2');
