insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2012-04-19','Vista domiciliaria. Se mantiene entrevista tanto con Sara como con su hermana Esther, conla quien convivie la tuteleda. Esther manifiesta su deseo de la institucionlización de su hermana. Refiiere ser madre de dos hijos, uno de ellos con discapacidad (posiblemente enfermedad mental), estr separada y no poder hacerse cargo de prestar los cuidados que su hermana necesita. Se le plantea a Sara la posibilidad de ingreso en Centro, aceptando en principio el acceso al recurso residencial.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2012-04-27','Solicitado DNI al SSB de jerez de los Caballeros. Igualmente se solicita informe médico a través de la T. Social del Centro de salud. Documentos necesarios para tramitación de recurso residencial.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2012-05-02','El responsable de la vivienda tutelada de Cáceres (Jose Maria tlf 669439020), lugar en el que reside José, llama para comunicar que José esta subiendo fotografias íntimas a las redes sociales, en concreto facebook, en principio consecuencia de las amistades mantenidas en las propia red','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='OTERO'and apellido2='NOGALES'),'2012-05-02','Se firma consentimiento informado para intervención de hernia inguinal. Dr. Kotragh, de Cirugía general y Digestiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='GARCIA'and apellido2='DE PRUNEDA TREVIJANO'),'2012-05-02','Conversación con la hermana de D. Fernando, Dª Pilar (924-273971). Las inmobiliarias en las que está a la venta el piso han recomendado bajar de los 215.000 euros iniciales si se quiere vender. Han propuesto fijar un precio de 180.000 euros, dadas las condiciones en las que la vivienda se encuentra. Se rebaja a 180.000 al no ser viable, según Dª Pilar, una rebaja menor ni más progresiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-05-03','Se pasa nueva valoración (revisión) de grado de minusvalía en CADEX de Badajoz. A la cita acudieron la madre y hermana de Jesús y la cuñada de esta última. Durante el tiempo que estuvimos allí, unas tres horas, Jesús pasó por dieferentes estados de ánimo: felicidad al ver a su familia, enfado, reclamando no querer volver a ningún centro y solo aceptar quedarse con su familia (reclamaba ver al juez, al forense, para hablar con ellos), tristeza por haber estado siempre en los centros desde pequeño, amenazas de fuga (no volver a coger el taxi con el que había llegado), amenazas autolíticas, amenazas personales y, finalmente, tranquilidad, insistiendo en que quería volver a Ávila, con su "novia" , de donde no se volvería a escapar: "Te juro que no me voy a escapar, tenía que haberle hecho caso a Elena que me quería mucho. Pero esto no se lo digas a mi familia, ¿vale?. Podría llamar a mi novia con tu móvil...". Llamamos a Ávila y habló con Elena, pero no con su novia. Elena explicó la negativa del Equipo Técnico del centro para que volviera allí no tanto por él mismo como por lo que su presencia en el Centro suponía para los demás residentes en el mismo en cuanto a las influencias que sobre los demás tenía. La hermana y la madre de Jesús insistían en que lo dejaramos quedarse con ellas, que lo querían mucho y que no le pasaría nada estando con ellas. No entienden, en nuestra opinión, las implicaciones que ello puede llegar a tener, al no tratarse de una medida de unos días, sino de un día tras otro conviviendo con las limitaciones que Jesús tiene y que requieren una atención lo más individualizada posible en un recurso específico para atender a sus características personales. Al ir a volver al CSS, la madre de Jesús sufrió un ataque epiléptico a la entrada del CADEX (al parecer no se había tomado esa mañana su medicación). Acudió el 112 y tras su reconocimiento regresó a casa con su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='ESPINO'and apellido2='ROMAN'),'2012-05-07','Convesración telefónica con Rosaura, T. Social de Menmbrío. Dª Dionisia es de Salorino, aunque vive en la Residencia de titularidad municipal de membrío. Rosaura nos enviará la documentación solicitada y el expediente completo de solicitud de la Ley de Dependencia para su firma y tramitación desde la CTAEx. Según comenta existen deudas con la residencia.','2');
