insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2012-05-09','Visita domiciliaria realizada a Dª Antonia Canelada en Logrosán. Se acude al Registro de la Propiedad.La vivienda sita en la Calle Las Cruces nº 59, propiedad anteriormente de nuestra tutelada, fue vendida por ésta a D. José Gómez Luengo el 4 de junio de 2002. Actualmente se han iniciado las obras de reforma por parte del propietario. Respecto a que sea nuestra tutelada la que se haga cargo de dicho coste, para el que no existe presuesto, no consideramos que deba ser ella la que lo asuma, ya que no es la propietaria y así se les dijo tanto a ella como al propietario. La casa es antigua, de dos plantas, y de 25 metros cuadrados de superficie: en la planta baja hay un recibidor de unos 3 metros y dos cuartos muy pequeños; en la superior, hay una estancia diáfana, con media bañera y nada más.','2');
