insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='IGLESIAS'and apellido2='SANCHO'),'2012-05-05','Intento autolítico (ingesta de pastillas): acude la Policía Nacional al domicilio de la calle marquesa de Pinares. Ingresa en UHB y le dan el alta ese mismo día. Según refiere, no puede volver al piso porque la han hechado, se han quedado el dinero y le han tirado la ropa y documentación¿?. Acude al Centro de Transeúntes "Padre Cristobal", de donde nos llaman el lunes 7 de mayo para informarnos de dónde está.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='IGLESIAS'and apellido2='SANCHO'),'2012-05-10','Nos llama Yolanda, T. Social del centro de Transeúntes informando de que Mª Ángeles se encuentra mal desde ayer, está muy nerviosa y hoy ha empeorado: quiere ingresar voluntariamente en el C. Sociosanitario. Se le va a buscar al centro de Transeúntes y se le acompaña para ingresar en Unidad de Agudos (UHB) del Hospìtal de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='IGLESIAS'and apellido2='SANCHO'),'2012-05-11','Nos llama Agustina, Psiquiatra de la UHB de Mérida. Nos dice que Mª Ángeles está bien y que en unos días le dará el alta. Le explico que si no está en situación de crisis nos somos sus tutores sino sus curadores para cuestiones económicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2012-05-04','Hermenegildo ha organizado en su casa y en el SSB de Cabeza del Buey un altercado que ha merecido la intervención de la Policía Local. En contacto con la Médico de Guardia, Purificación Herrera, le va a hacer una visita en el Cuartel de la P. Local y me llamará por la tarde.Ya lo había hablado con Casimisro, T. Social del C. de Salud. Hablo con Águeda, T. Social del SSB(924-600077, 636-786917 y 674-095644): la madre de Hermenegildo, Dª Dolores, está muy asustada, dice que allí no puede estar, que así no puede vivir (fue ella la que insistió en que se podía quedar con ellos); en el SSB también montó un buen escándalo. A las 16.00 me llama la Dra. Purificación: va a dar orden de ingreso en Agudos de Don Benito. Allí estuvo solamente un día y se le dió el alta. Estamos a la espera de contestación por parte del Juzgado para autorizar internamiento involuntario.','2');
