insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='VAZQUEZ'and apellido2='RODRIGUEZ'),'2012-05-22','Llama del Hospital la Doctora Castro (Serv. de Otorrinolaringología): D. pedro está en lista de espera para intervención en cuerdas vocales. Cuando le llamen, nos avisarán para firmar el Consentimiento Informado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2012-05-23','Realizadas gestiones con el ayuntameinto de Jerez de los caballeros y con el servico de atención al mayor, Ramón no podría acceder al Club de Comidas del Centro Residencial Hernando de Soto de esta localidad por no cumplir con los requisitos de acceso a este recurso. Por otro lado el servico de distribuciñon de comidas, llevado a cabo por la asociación de mujeres progresistas de esta localidad ha dejado de prestar el servicio por finalización de la subvención que teneian asignada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2012-05-23','Visita realizada en el CSS de Mérida. D. Feliciano reiteró su demanda de traslado a CRR,de Cáceres o de Badajoz. Descartó el deseo anterior de una independencia total "...Yo sé voy a estar institucionalizado toda mi vida y no quiere vivir ya solo...". Se le informó de la falta de plazas en estos momentos y de que se está haciendo todo lo posible por agilizar el trámite: Juan Pedro planteó la posibilidad de llevarlo por Emergencia Social, para lo cual se le propuso que enviaran desde la Unidad un Informe en ese sentido dirigido a la Comisión de Salud Mental. Se quedó también en ver la posibilidad de que desde Futuex se realizara una visita quincenal a Feliciano, lo cual podría suponer para él una mayor tranquilidad al permitirle salidas no necesariamente acompañado por los cuidadores, medida esta que también se intentará llevar a cabo con más frecuencia apelando a la voluntariedad de los cuidadores dispuetos a ello, fundamentalmente por cuestiones de horario. CONDICIÓN: el Delegado de Apyo que pueda realizar este acompañamiento debe ser HOMBRE, lo que en el caso de Feliciano supone para él un "extra" de respeto que no se ha verificado en el caso de las profesionales. Planteada la posibilidad de llevar a cabo estas visitas, Feliciano se sintió rápidamente atraído por la idea. A lo largo de la conversación, Feliciano manifestó su arrepentimiento por lo sucedido hace ya 28 años (aspecto este que hasta ahora no teníamos conocimiento en CTAEx se hubiera producido). Y no solo el arrepentimiento por lo ocurrido, sino que también manifestó su deseo de pedir disculpas a las familias de las víctimas "...pero no sé como podría pedírselo...". Descartó también cualquier deseo de regresar a su pueblo. Tras la conversación comenté este aspecto con Juan Pedro quien, en mi opinión, no pareció muy convencido de su veracidad. La conversación transcurrió con normalidad, con momentos de cierta cordialidad incluso que despertaron alguna tímida sonrisa en Feliciano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2012-05-23','Visita realizada en el CSS de Mérida. Javier ha sido "expulsado" de APENESMER durante varias semanas por mal comportamiento. En la reunión inicial mantenida junto con el Equipo se le indicó la necesidad de mostrar su capacidad de control de impulsos, en la que ha mejorado bastante, y su mantenimiento en el tiempo. Estaba durmiendo en el piso de Apenesmer dos noches a la semana y los viernes va a buscarlo su madre, Dª Adoración, para pasar la tarde con su familia en Almendralejo (no ha vuelto a ir al piso de su madre desde su ingreso). PETICIÓN ACTUAL: quiere irse con su novia tres días de vacaciones, lo cual el Equipo no descarta aunque hay discrepancias en cuanto a la duración de esa salida. Por otra parte, la misma está supeditada de momento a un cambio a mejor de Javier en todos los sentidos y lugares (Apenesmer, CSS, etc.) En la conversación mantenida a solas con él no rechazó la idea de que esas vacaciones pudiesen ser más cortas, incluso de una sola noche fuera. Inicialmente el destino sería la playa, pero antes de salir del Centro, en una de sus varias interrupciones, manifestó que quizá también podría ser la Jerte o algún sitio parecido. La novia, con la que dijo llevar seis meses, es una chica que también acude a Apenesmer, pero no se tiene de momento más información sobre ella en el equipo. Mencionó también el ingreso del dinero de la herencia, que él cree que son 3000 euros y su deseo de disponer de él. Se le indicó que con ese dinero teníamos que cubrir todos los gastos más necesarios que pudiesen surgir y que deberíamos tratar de alargar lo más posible ya que carecía de otros ingresos. No se le confirmó ni la cantidad ni el ingreso efectivo de la misma. Insistimos en que el objetivo ha de ser su recuperación completa y, si esta se demuestra, la posibilidad de que puedsa recuperar su capacidad legal absoluta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2012-05-24','Hablamos con su hermana Esther, quien manifiesta que su Sara se encuentra en Plama de Mallorca desde el día 19/05/2012, localidad donde reside su hermana Margarita. trascurrido un mes se trasladará a Villafranca donde permanecera otro mes en compañia de su otra hermana. Telefono de Sara: 660373996','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2012-05-25','La pasada semana recibimos escrito del CAMP de Plasencia informando de la imposibilidad de realizar la exploración correspondiente al Programa de Detección Precoz del Cáncer de Mama a Dª Francisca Sánchez Benitez. Acompaña al escrito documento de renuncia, de la D.G. de Salud Pública, a la participación de nuestra Tutelada en el mencionado pograma para ser firmado por la CTAEx, cosa que de ninguna manera se va a firmar. Puestos en contacto con la D.G. de Salud Pública se ve la posibilidad de realizar dicha exploración con la usuaria acostada, si su mobilidad permite dejar libre la zona a explorar. En contacto con Maite, la T.S. del CAMP, quedamos en que volverá a pedir cita para la prueba y, caso de algún problema, se pondrá nuevamente en contacto con nosotros, ofreciéndonos a acudir a la cita en caso necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='GARCIA'and apellido2='SANTOS'),'2012-05-28','Reconocimiento del derecho a la Asistencia Jurídica Gratuíta de Dª Mª Luisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2012-05-28','Conversación telefónica con D. Francisco, hermano de Dª Juana. Los 901.51 euros que en concepto de arras había pagado el señor Pocostales por el Olivar no se le han devuelto todavía: llegaron al acuerdo de que lo harían cuando se vendiera la finca. Se comunica al hermano que ya nos ha llegado la autorización de la venta por parte del juzgado. Al parecer ya tienen comprador, por un precio de entre 9000 y 10000 euros. Nos avisarán cuando sepan que Notaría va a llevar a cabo las gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='RUIZ'and apellido2='PAREJO'),'2012-05-28','Conversación telefónica con Dª Juli, hermana de D. Manuel, y con el hijo de aquella, D. Juan Carlos Suárez. Se les comunica que ya tenemos la autorización judicial para la venta del solar y de la finca. Solicitarán la tasación pedida por el Juzgado. DªJulia está interesada en la compra de la parte de su hermano de la tierra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2012-03-30','Se recibe llamada telefónica de la hermana de D. Jesús. Nos comenta que se encuentran residiendo en en la C. de Madrid, en la calle Francisco Babal nº5, 4ºB en la localidad de Arganda del Rey. Se le comentó que debía haber informado a CTAEx de esta situación antes de producirse y que la misma la comunicaríamos al Juzgado. Teléfono:606-424930','2');
