insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2012-05-31','Reunión con Asunción Cabrera en CSS de Mérida. CONCLUSIONES: +++Nos enviará informe sobre Carmen para adjuntar a la petición al Juzgado. +++Solicitar al Juzgado autorización para vender la casa de Valdecaballeros y, a la vez, autorización para la compra del piso y su reforma en Mérida (ésta podría estar supeditada a la venta de aquella). +++Pendiente4s de recibir el presupuesto de la inmobiliaria y, en su caso, abrir cuenta en Bankia con los 1000 euros de fianza. +++LLAMAR A OTRAS INMOBILIARIAS PARA VER SI EXISTEN PISOS EN ALQUILER CON OPCIÓN A COMPRA en la misma zona o distinta de la ciudad. +++VACACIONES: estamos de acuerdo en que Carmen no se puede ir más de 3 ó 4 días seguidos como ella pretende. Lo que sí se puede negociar con ella es ir a su pueblo con algo más de frecuencia.','2');
