insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2012-06-13','Conversación con Águeda, T. Social. Hermenegildo ha sufrido una bajada de tensión en la calle y se ha desmayado. Ha necesitado atención del 112. Estamos a la espera del Informe Médico correspondiente. Al parecer, ayer también sufrió un desmayo en casa, cayendo al suelo y haciéndose una herida en la frente. Su madre está "harta" de esta situación. Situación que ella favoreció en su momento apoyando e insitiendo en que se quedará en el pueblo, que ella se podía hacer cargo. hay indicios, se3gún refieren tanto Águeda como Dª Dolores, la madre, de que está consumiendo drogas (caballo, etc.) Su madre dice que no lo quiere allí y que, o hacemos algo, o ella se va y lo deja solo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-06-14','Se responde al Juzgado de lo Penal Nº 1 de Mérida en el sentido de no ser posible en este momento que Ángel cumpla la medida de sueguridad de internamiento por tiempo máx. de un año establecida por ese tribunal. También se respondió hace unos días al Juzgado de Instrucción nº 2 de Villanueva respecto a la solicitud de internamiemnto involuntario solicitada por CTAEx en 2007. Además, se informa sobre el último contacto mantenido con Ángel, quien al parecer se encuentra en Sevilla viviendo con una chica y el hijo de esta: en la última conversación mantenida con Ángel éste no me dejó hablar con ella (ver informe emitido al Juzgado).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2012-06-15','-solicitada Ley de dependencia.','2');
