insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2012-06-21','Se habla con anonio de EALEX, para comunicarle la ratificación por parte del juzgado de la resolución de extinción de visitas por parte de la madre y abuelo de Daniel. Se le remite copia de','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2012-06-22','-Tras la fuga de Vicho de Los Robles llega hasta Malaga . Se persona en diligencias policiales y se identifica . La policia Local lo lleva al Hospital Clinico Universitario y pasa a la Unidad de Psiquiatria donde pasa 3 dias . El dia 22 se traslada con Cruz Roja de Malaga al Hospital San Fco. de Asis . Precio plaza 2395€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2012-06-22','-comunicado el traslado de Burgos a Malaga al Juzgado. -comunicada baja a los Robles. -comunciado a su familia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2012-06-26','Se recibe en la Comisión Tutelar DECRETO de la Ilma. Sra. Fiscal Instructora ( Sección Territorial de Villanueva de la Serena) de la Fiscalía Provincial de Badajoz, por el que SE ARCHIVAN las actuaciones relativas a las Diligencias Informativas Nº 8/12 (denuncia de Ángel de un cuidador de Apba. 9). Se comunica dicho archivo a Maribel, Directora de Aprosuba 9.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2012-06-26','Se recibe informe médico de Oncología. Conclusión: enfermedad estable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='CACHO'and apellido2='LINDO'),'2012-06-25','Se comunica desde el CSS de Mérida el traslado de D. José María Cacho Lindo en el Servicio de Urgencia del Hospital de Mérida y su posterior alta. Motivo: sospecha de AIT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='VALIENTE'and apellido2='VILLALBA'),'2012-06-22','Se comunica traslado desde el CSS de Mérida de D. Francisco Valiente Villalba al S. de Urgencias del Hospital de Mérida por posible masa en pulmón izdo. Se le da el alta ese mismo día. El estrudio de la lesión se hará en Consulta de Alta Resolución en vía muy preferente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2012-06-25','Aceptación de herencia realizada en esta fecha en la Notaría "Gil Coredero" de Cáceres. (927-222200). No se pudo realizar la extinción de la comunidad de propietarios del campo y la vivienda que por herencia comparten, como así habían acordado, al tener que hacer efectivos los pagos correspondientes de uno a otro (Jesús, el hermano de Martín) para justificar los mismos ante el Juzgado en el caso de nuestro curatelado. En visita realizada al Banco Sabadell, se nos informó de que había un embargo sobre las cuentas que inicialmente ascendía a 14464.82 euros y que actualmente ronda los 7.000. Además, se nos indicó en dicha conversación, que había un Traba Judicial sobre las cuentas hasta el año 2050 (Juzgado de 1ª Instancia/Instrucción nº 1 de Cáceres (DILIGENCIA 543/2008).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2012-06-26','Comunicación telefónica con el Servicio de Ejecución del Juzgado nº 1 de Cáceres. Maribel (927-620415). La única "traba judicial" existente es el propio embargo, para el pago del cual Tesorería de la Seguridad Social retiene mensualmente 23 euros. Acudiremos al Juzgado en la próxima visita a Céceres, debidamente acreditados, para recabar toda la información al respecto. Al parecer, existe también un embargo sobre dos casas de las que en una Martín es propietario único y copropietario en la otra. A ellos no les consta que Martín esté curatelado, por lo que no pueden darnos más información, aunque sí personarnos en la causa. Acudiremos al Juzgado en el próximo viaje a Cáceres debidamente acreditados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2012-06-25','Hoy le dan el alta a Antonio Fernández Merchán desde la UHB del Hospital Virgen del Puerto, está estable y han realizado un cambio de la pauta de medicación. Antonio ha manifestado que tiene ganas de volver al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2012-07-02','Isabel de Cáceres, madre de Alfonso (91-5935365 y 680-784490). Se llevó a su hijo a Móstoles pensando que la Orden de Alejamiento había prescrito, sin ser así. Alfonso está ingresado actualmente en el Hospital Viejo de Móstoles reclamándole que se lo lleve de allí. xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx Llama Julia, hermana de Alfonso (91-5274918)y nos da los teléfonos de Móstoles: 91-6648791 y 91-6648609). El médico es el Dr. García, aunque su médica es la Dra. Sánchez Cugas. Ellos ponen una ambulancia (el Hospital) si lo acompaña un familiar. La hermana estaría dispuesta a acompañarlo siempre que se quede en un Centro. xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx Hablar con CSS de Plasencia como posible lugar de retorno según su estado de salud. xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx De no ser posible CSS, hablar con Padre Fernando de la Casa de la Misericordia de Pinofranqueado, donde ya residió entre febrero y agosto de 2011, por la Orden de Alejamiento).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2012-07-23','-tf de Antonio Giron Gonzalez ,amigo de su pade . 617916398 , quiere ir a visitarlo a Malaga cuando nosotros confirmemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2012-07-03','- su padre y su hno van a visitarle a Burgos ,hoy es su cumpleaños. - Se le han dando 400€ en total y ellos han organizado el viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2012-07-04','- Ha sido traslado del Hospital de Mostoles a la Unidad de psiquiatria del Hospital de Leganés .Tiene tarjeta sanitaria y aparece en Leganés , ha sido trasladado allí pq está como desplazado y es donde vive la familia. Quedo pte. con su psiquiatra de gestionar traslado cuando sea valorado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2012-06-01','Realizada visita domiciliaria. En el momento de la visita la madre no se encontraba en el domicilio familiar. Hablamos con su hermano y con la propia Tutelada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2012-07-04','Buenos días Isabel: En relación con la Tutelada por esta Comisión, Doña Mª del Pilar Rodriguez Escalare, una vez realizada visita domiciliaria por parte de la propia Comisión y valorada la situación actual, desde la propia Comisión se considera como recurso más acomsejable en la negociación del PIA,l Centro Residencial ajustado a su perfil, preferentemente en la localidad de Badajoz. Un saludo Fdo. Julio García Rubio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2012-07-05','- Hay que devolver por cobor indebido a la SS 418€ , se lo descontarán sucesivamente por meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2012-07-05','Comunican, desde el H. Infanta Cristina, el ingreso de D. Francisco Javier el pasado día 3 de julio en la Unidad de Psiquiatría. Médico de contacto: Dr.Guisado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2012-07-04','Desde el CSS de Mérida nos comunican la derivación al Servicio de Urgencias del Hospital de Mérida de Mª Luisa para extracción de cuerpo extraño. En conversación con asunción Cabrera hemos podido saber que se tragó la traba de una sandalia. Este hecho creemos que no debe hacer perder el objetivo inicial de las intervenciones con Mª Luisa tendentes a dotarla de mayor autonomía y mobilidad, considerando este hecho como una recaída previsible dentro del proceso rehabilitador establecido para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2012-07-06','Comunicación a Dolores Bernal (T. Social del SSB de Siruela) el Auto 41/2012 que en su parte dispositiva indica que no ha lugar a la autorización para el internamiento involuntario. Así mismo Dolores informa que la empresa encargada del servicio de de ayuda a domicilio (INTRESS)no considera caso adecuado para prestar su servicio, debido a la falta de cualquier tipo de habitos fundamentalmente higiénicos. Dolores remitirá informe al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2012-07-06','-aprobada el cambio titularidad de PF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2012-07-06','Se recibe infromación del CSS de Plasencia: José Mª se ha escapado. Julia, su madre, llama diciendo que está en casa. Ha llamado al 112. Amalia convence a José Mª para que regrese a Plasencia voluntariamente, en taxi y acompañado por su padre, el cual volverá de la misma forma a Cilleros. Se desactiva el 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='CINTA'and apellido2='GONZALEZ'),'2012-07-09','-PF , aceptado el cambio de titularidad y/o cuenta bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='PEREZ'and apellido2='MONTAÑO'),'2012-07-09','- PF , cambiada titularidad y cuenta bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='POZO'and apellido2='GONZALEZ'),'2012-07-09','Nuria, Directora del CAD "Los Pinos". Nos comunica que D. José ha fallecido la madrugada del 8 de julio en el Hospital "Virgen del Puerto" por un edema pulmonar agudo. SE TRATA DE CONTACTAR CON AMBOS HIJOS: D. Juan José Pozo Regalado (647-546434) y D. Miguel Pozo Regalado (685-812080). Se deja mensaje a ambos para contactar con CTAEx. RESPONDE D. MIGUEL: no tienen ninguna preferencia en que su padre sea enterrado en uno u otro lugar, creen que no tenía ningún seguro de deceso (como confirman en el CAD "Los Pinos") y aceptan cualquier decisión que desde CTAEx se pueda tomar en relación al fallecimiento de su padre. Le pido que lo comunique a su hermano y les damos el pésame desde CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2012-07-09','Se recibe en la Comisión fax del Juzgado de 1ªI.e I. nº 1 de Logrosán solicitando información sobre "...el estado y supervisión del tutelado." A raíz del escrito presentado por D. Juan ante el Juzgado solicitando su ingreso en el CSS de Plasencia y su atención por parte del Dr. Sevilla. C.S. de GUADALUPE. Dra. CONSOLACIÓN SÁNCHEZ: "HACE UNOS DÍAS QUE SE LE VE MÁS DESALIÑADO. Hasta ahora siempre ha acudido a ponerse los inyectables y a recoger la medicación que debe tomar en casa ¿la toma?. En la última consulta, el pasado jueves o viernes, le tuvo que poner un tranquilizante. Quiere irse al CSS de Plasencia pero yo solo lo puedo derivar a UHB de Cáceres. Creo que está citado para el 20 de julio en ESM de Trujillo, donde no quiere ir. Con Consolación he barajado la posibilidad de ingreso con el 112 en UHB de Cáceres si ve que la estabilidadde D. Juan ha empeorado. CONVERSACIÓN CON E.S.M. DE TRUJILLO. MIGUEL MEDINA (PSIQUIATRA). Enviará Informe el miércoles tras ver la historia clínica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-07-09','-Recibimos llamada tf. de los SS.SS. de Badajoz donde se ha personado Jesús . Me pide dinero para tabaco, comida y gastos personales .Le indico que mientras no regrese al centro no se le puede enviar dinero , le animo a ello y accede . Tras gestionar con CSS Mérida que me indica que sigamos el protocolo y lo enviemos en primer lugar a la UHB de Badajoz , llamo a esta unidad y a un taxista para que lo acerque. Cuando el mismo llega a recoger a Jesús , este se ha ido sin decir nada .','2');
