insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2012-07-09','Conversación con Javier, CRR de Plasencia, sob re dudas que le surgen en torno a la sentencia. Se consulta a Carmen Barquilla, Fiscal de Cáceres, sobre las dudas que la sentencia de incapacitación plantea respecto al papel del tutor. Está de acuerdo en que la redaccción de la misma se presta a las dudas que le planteo y le parece oportuno que solicitemos una aclaración de dicha Sentencia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2012-07-10','Se envía al Juzgado de 1ª Instancia e Instrucción Nº 2 de Cácceres solicitud para aclaración de Sentencia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2012-07-11','Conversación con el Dr. Miguel Medina(927-320769), Psiquiatra de ESM de Trujillo. Ve signos preocupantes que indican que el tratamiento actual no está surtiendo los efectos deseados en D. Juan. Enviará Informe médico y tratará de convencerlo, en la consulta del 20 de julio, para ingresar en UHB de Cáceres (él no quiere Cáceres, sino Plasencia, como indica en su solicitud al Juzgado). Si la Dra. Consolación lo ve peor, "que me lo envíe directamente antes del día 20..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2012-07-12','-aprobada PF . -Enviada opción de PF y dejamos PNC.','2');
