insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2012-07-10','-Hecha la parte social para el inventario . -Percibe PNC y P. Orfandad , con un total de unos 400€. A veces son compatibles , si no superan en conjunto los ingresos estipulados, si bien , la PNC se ve reducida. Por el momeno lo vamos a mantener asi , si nos hiciera falta más dinero podemos cambiarla a PF .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2012-07-10','-Tf. de la madre : 680784490 ( Isabel )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2012-07-12','-Juan nos llama muy alterado , no acepta que le demos los 1000€ fraccionados y los quiere por adelantado. En su afán de manipulación me amenaza con venir a matarnos ( la llamada la he guardado en su expediente ) . Me pongo en contacto con su psiquiatra , Antonio insiste en su afán de manipular , como haciendose daño a sí mismo no consiguió nada ahora utiliza esta fórmual ; sabe bien lo que hace y no está descompensado . Su respuesta está en las grabaciones del día de hoy . Intento contactar con las hnas. para confirmar que se va a ir con ella un mes pero no es posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN ANTONIO'and edp.apellido1='EVERLISTA'and apellido2='LEONISA'),'2012-07-13','Conversación telefónica con Silvia Millán, T. Social SSB de Valdelacalzada. Fijar fecha de visita domiciliaria aplazada del 21 de junio. Cree que es mejor que esté ella presente: está de vacaciones hasta el día 8 de agosto. Considera que una visita en estos momentos, sin estar ella presente, va a provocar en D. Julián un desasosiego e incertidumbre innecesarios. Ayer mismo estuvo con él y se encuentra bien, dentro de sus circunstancias. Quedamos en visitarlo el 9 de agosto a las 10:30 de la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2012-07-13','-Aprobada PF y Orfandad. Optamos por dejar la PNC.','2');
