insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2012-07-18','Solicitan autorización para pasar las vacaciones del 1 al 21 de agosto junto a su familia. El hermano prestará atención a un posible reencuentro con el ex-marido de Mª Josefa. En Vera consideran que estas vacaciones le pueden venir bien. Además, Mª Josefa está colaborando más en las tareas del Centro y sale por el pueblo con un grupito de chicas.','2');
