insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2012-07-23','An tonio, T. Social de Fuente del Maestre nos informa que Miguel va a trabajar durante 15 días en el CEE del Ayto. Hablamos con Neli, de Contratación del Ayto (924-530125. Ext 307):no es necesario contrato para labores inferiores a 28 días. Nos enviará por fax la documentación relativa al SEXPE, Seg. Social, una vez que lo haya contratado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='ESPINO'and apellido2='ROMAN'),'2012-07-23','Rosaura (T. S. Membrío. 647928370)Forma de pago del "repago" en farmacia. Opciones: ++++Dinero de bolsillo mensual. ++++Factura mensual de la farmacia que la residencia nos haga llegar. Verán cula de las dos alternativas es viable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2012-07-23','Recibido escrito del Juzgado de 1ªInstancia Nº 2 de Navalmoral de La Mata solicitando la aceptación o no de la división de herencia. Se llama al Juzgado, a Mª Victoria, para pedirle toda la documentación en relación al tema y poder valorar o no la correcta división de la hrerencia. Comenta que nosa llegará ya en septiembre y que el plazo de cinco días que refeleja el escrito no ha ligar en estas circunstancias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2012-07-18','Respuesta del Juzgado de 1ª Instancia e Instrucción Nº 3 de Cáceres a la petición de "aclaración de sentencia" realizada por CTAEx: "No ha lugar a la aclaración solicitada por la Comisión Tutelar de Adultos de Extremadura de la sentencia dictada en los presentes autos toda vez que la misma es firme y por consiguiente inamovible en cualquiera de sus términos". XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXAntes de nuestra solicitud, basada en la demanda del CRR de Plasencia sobre una posible solicitud de ligadura de trompas, hablé con la Fiscal de Cáceres, Carmen Barquilla, quien comprendía las dudas generadas con esta sentencia y apoyaba la opción de solicitar desde CTAEx dicha aclaración. Tras la respuesta del Juzgado, volví a hablar con la Fiscal, reiterando que no pedíamos una rectificación ni modificación alguna de la sentencia, sino solamente una aclaración en aspectos puntuales recogidos en dicho escrito. Las dudas se mantienen, como reconoce la propia Fiscal. Quedé con carmen Barquilla que dadas las dudas, consultaríamos con ella aquellas cuestiones que considerásemos no estuvieran claramente respaldadas por la sentencia, a lo cual no puso objección alguna, sino todo lo contrario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-07-23','Cristina, T. Social Centro Penitenciario de Badajoz. Nos comunica que Jesús fue detenido el miércoles 18 de julio e ingresó en prisión el pasado viernes 20 de julio por robo con violencia e intimidación e intento de agresión sexual. Actualmente en situación de Preventivo. Se Sigue DILIGENCIAS PREVIAS 2728/12 EN EL JUZGADO DE 1ª INSTANCIA Nº 2 DE BADAJOZ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2012-07-24','Conversación con Mari Carmen: comprobará si, como dice Carmen, el tejado está casi arreglado. Ivan sigue interesado en la compra de la casa. Hoy ha estado Carmen en CTAEx diciendo que estaba dispuesta a vender la casa y que lo quería hacer ella porque tenía un comprador. Se le explica que la venta ha de ser autorizada por el Juzgado y que ella no puede ni debe firmar nada sin consultar previamente con la Comisión. En agosto se va al pueblo de vacaciones cinco días y dice que el comprador le va a hacer una oferta. Se insiste en la alternativa del alquiler antes que en la compra de vivienda y, quizá, como paso previo a esta " si disapone de recursos económicos suficientes para ello, sin endeudarse..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2012-07-10','Se envía al Juzgado de 1ª Instancia e Instrucción Nº 2 de Cácceres solicitud para aclaración de Sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2012-07-09','Conversación con Javier, CRR de Plasencia, sob re dudas que le surgen en torno a la sentencia. Se consulta a Carmen Barquilla, Fiscal de Cáceres, sobre las dudas que la sentencia de incapacitación plantea respecto al papel del tutor. Está de acuerdo en que la redaccción de la misma se presta a las dudas que le planteo y le parece oportuno que solicitemos una aclaración de dicha Sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2012-07-24','Ayer se recibió en la Comisión Providencia del Juzgado de 1ª Inst. e Instruc. Nº 2 de Cáceres, comunicando que se ha librado oficio a la Guardia Civil de Cañaveral para que proceda a auxiliar en caso preciso al 112 en el traslado de Dª María de Jesús Plasencia Majadas. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Contactos realizados en el día de hoy: -Nieves, T. Social de la Residencia "Felipe Trigo". Está de vacaciones hasta el día 6 de agosto. Propone el 8 de agosto para el traslado, ya que preferiría estar presente para la admisión de nuestra tutelada. -Hortensia, T. Soc. de Cañaveral. Ella está en Cañaveral lunes y miércoles, aunque en caso necesario se desplazaría cualquier otro día. En estos momentos la situación familiar de la tutelada es tranquila "incluso la sacan a pasear con más frecuencia desde el intento de traslado". Cree que no supone ningún problema que el traslado se realice el día 8 de agosto. -112. Eva, Jefa de Sala. Le enviaremos nuevamente la toda la documentación, incluída esta última providencia. Se la enviaremos vía fax dos o tres días antes de la fecha de traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2012-07-12','Se envía al Juzgado de Logrosán Informe de seguimiento de la CTAEx, adjuntando Informes Médicos de la Médico de Familia, Dra. Consolación Sánchez y del Dr. Miguel Medina, del ESM de Trujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-07-25','La familia de Jesús quiere ir a visitarle.Hablamos con EMI, T. Social del Centro Penitenciario de Badajoz (924-289117). XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX El teléfono de Comunicaciones es el 913-356099. NIF del Interno: 2011021026 XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Deben indicar al solicitar la Comunicación el NIF del Interno, el DNI del interno y de los familiares o personas que quieren comunicar con él. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Informamos de todo ello a Almudena, T.S. Badajoz (924-277535)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2012-07-26','Oti, T. Social de Badajoz. No le ha sido posible localizar a Dª María en la dirección indicada en nuestra petición de Informe: no figura empadronada en Badajoz desde 1998.Se le informa que esa dirección corresponde a una casa abandonada en la que quizá viva. Volverá a realizar la visita. Se le da la dirección del padre si lo anterior no diera resultado y, caso de no localizarla, nos lo comunicaría por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2012-07-26','Ester, hermana de Sara. Se comunica la citación del Juzgado de 1ª Instancia e Instrucción Nª 1 de Jerez de los Caballeros para reconocimiento médico forense el próximo día 31 de julio a las 11.00h. Nos confirma su asistencia. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX La solicitud de plaza en centros para Personas con Discapacidad esta pendiente de Pérfil Cadex.','2');
