insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2012-07-30','Conversación con Raquel, de la empresa "Adelanta" (633425539). Comunico la situación del pago de la "deuda" y Raquel está dispuesta a seguir prestando el Servicio estos dos próximos meses. Si al final de este plazo el pago no se ha realizado, quedaría la opción de pagar un mes con el dinero de su tío (opción de último extremo para evitar retirar el servicio). XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Se comunica a Abraham el acuerdo con la empresa (sin mencionar solución de última hora). Abraham, hijo de Gabriel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2012-07-30','Conversación con Concha (VIPRÉS 924-310305). Se solicita dar de baja a Dª Carmen en la compra de la vivienda que estuvimos viendo en la Calle Bellavista 7, bajo. Queda pendiente de informarnos de los pisos en alquiler, amueblados, con dos habitaciones y salón, que pueda haber en la misma zona o en otras. Los precios oscilan entre 300 y 350 euros. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Con Asunción Cabrera se estudia ñla posibilidad de que comparta dicho alquiler con una compañera de los pisos supervisados (ver Informe).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2012-07-30','Nueva conversación con Beatriz (T. Social). La situación sigue tranquila, sin cambios y pendiente del Juzgado de Castuera respecto a los procedimientos de incapacitación de sus tres hermanos. Postponemos la visita para septiembre, salvo comunicación a la CTAEx de alguna situación que aconseje no aplazar más la misma.','2');
