insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2012-08-01','Conversación con Clara Gómez y Asunción Mayoral. Asun pedirá una nueva valoración del PIA como plaza residencial pública. Llamarla para indicarle orden de preferencia: en primera opción, la residencia en la que se encuentra "La Esperanza" de Albalá y luego, por proximidad. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX May: NO existe concierto con Albalá. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Asun Mayoral. Única alternativa: solicitar cambio de PIA a plaza residencial pública e indicar orden de preferencia. Actualmente, por proximidad, existen plazas en Aliseda, Casar de Cáceres, Garrovillas, Miajadas (S. Martín de Porres). XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Patricia, Directora Residencia "La Esperanza" de Albalá.(volveré a llamar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GONZALEZ'and apellido2='NEVADO'),'2012-08-01','Hablamos con CSS y UHB de Mérida: no ha estado nunca allí. En UHB, Inés (Admva.) me dice que estuvo en UHB de Cáceres el pasado 6 de marzo. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX UHB de Cáceres:Soledad (T.Social)"Virgen de la Montaña": xxx Dirección: C7. Río Ródano 14 (la misma). Tel:622-240948 xxx FAMILIAR: Monserrat Glez. (sobrina). C/. Corchito 6. Tel: 646-076742. xxx Dos ingresos en Hospital en 2011 con alta. xxx C. Salud "Aldea Moret". Estuvo allí con la Trabajadora Social, Valentina (927-235012(L,M,J,V) y 927-285316(X)) los días 10,16 y 24 de abril. xxx MÉDICO Dde FAMILIA: Dr. Francisco Pérez Gallego (C.Salud de Aldea Moret") xxx Urgencias Hospital de Mérida:ingreso el 12 de abril y alta el 13 (fue con intención de pasar la noche).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2012-08-01','Justo (Futuex). Informa de que Almudena tiene la casa "desmantelada":ha vendido la lavadora, dice haber tirado la cama (duerme sobre el colchón, en el suelo), ha estado a puntpo de vender el frigorífico ahora, no se ha comprado la ropa con el dinero que le mandaste..." En conversación con Almudena se muestra como siempre, sin síntomas de descompensación, justificando con excusas todo lo dicho. Ha amenazado con "matar" a su padre si no le quitan la tutela que él pidió, denunciar a la Comisión ante el Juzgado, se ha hechado a llorar cuando le he preguntado qué le pasaba realmente. Quedo con ella en hacerle una visita este viernes o la semana que viene.','2');
