insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2012-08-07','Desea hacer Separación de Bienes antes de celebrar el matrimonio. Consulta con la Notaría de D. Fernando Gutiérrez (C/. Los Maestros 2. 924-319011): presentar la Sentencia de Incapacitación (en su caso Certificado Médico) y no es necesario presentar documentación de los bienes de cada uno de los contrayentes. Se informa a Castillo (630-364194), quien acudirá a la Notaría lo antes posible. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Quiere poner a su nombre las propiedades heredadas de sus padres.Traerá toda la documentación de que disponga para acudir a la notaría para hecer el cambio de titular.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2012-08-06','Hablo con D. Francisco Javier (650-895050): xxx Está viviendo con su mujer, a pesar de la O. de Alejamiento vigente hasta octubre de 2012. YA NO SE QUIEREN SEPARAR. Su abogado, D. Jorge Juan Zarza (924-260087), no sabe nada de todo ello. Nos autoriza a informar al abogado, dado que aunque la curatela es patrimonial, existe una deuda pendiente con el bufete que no se puede pagar por el bloqueo de la cuenta de que ambos cónyuges tienen como cotitulares. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXLlamamos al Abogado pero el mesaje indica que el bufete está cerrado hasta el 3 de septiembre. No obstante, dejo el recado a un compañero para que le comunique que se ponga en contacto con nosotros. Nos comenta que seguramente D. Jorge estrá ya la última semana de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-08-07','Llamo al SSB. Mª Victoria, la T. SOcial, vuelve de vacaciones el lunes 13 de agosto. Llamarla para valorar el mejor momento para el traslado de Dª Antonia, una vez ya tenemos la autorización judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2012-08-08','-Aprobada la PF , con 189€ mensuales en 14 pagas. el primer pagto asciende a 1124€ con los atrasos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2012-08-07','José María Vicho tiene en cuenta a fecha 7 de agosto de 2012 3094 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2012-08-09','Conversación con Nieves, T. Social R. "Felipe Trigo". Dª María llegó ayer a las 13:45h, muy nerviosa y agitada, sin asear y pidiendo volver con su familia. Comió muy bien y ha pasado bien la noche. Cuando la ha ido a ver Nieves esta mañana estaba dormida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2012-06-11','Visita realizada a las hermanas Collado en Geryvida, tras su traslado desde la Residencia "El Conquistador" por cierre de esta el pasado mes de abril. Se encontraban participando en la actividad de gimnasia de la Residencia. Estaban muy enfadadas y nerviosas por haberlas llevado a esta nueva residencia en lugar de a su casa que "...es donde deberíamos estar, ocupándonos de nuestras cosas...y no aquí, que no hacemos nada ni pintamos nada..." La Comisión considera que un nuevo traslado en estos momentos NO ES OPORTUNO. Las dificultades económicas que Dª Dolores, en breve plazo de tiempo, va a tener para costear la plaza privada que ocupa en estos momentos no ha de ser la única consideración a tener presente para decidir dicho traslado, sino su bienestar y el seguir manteniendo la unidad familiar con su hermana. Por ello, creemos que la opción más adecuada es la de solicitar en dicha residencia plaza concertada por emergencia socila en le momento que se produzca una vacante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2012-06-11','Visita realizada a las hermanas Collado en Geryvida, tras su traslado desde la Residencia "El Conquistador" por cierre de esta el pasado mes de abril. Se encontraban participando en la actividad de gimnasia de la Residencia. Estaban muy enfadadas y nerviosas por haberlas llevado a esta nueva residencia en lugar de a su casa que "...es donde deberíamos estar, ocupándonos de nuestras cosas...y no aquí, que no hacemos nada ni pintamos nada..." La Comisión considera que un nuevo traslado en estos momentos NO ES OPORTUNO. Las dificultades económicas que Dª Dolores, en breve plazo de tiempo, va a tener para costear la plaza privada que ocupa en estos momentos no ha de ser la única consideración a tener presente para decidir dicho traslado, sino su bienestar y el seguir manteniendo la unidad familiar con su hermana. Por ello, creemos que la opción más adecuada es la de solicitar en dicha residencia plaza concertada por emergencia socila en le momento que se produzca una vacante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN ANTONIO'and edp.apellido1='EVERLISTA'and apellido2='LEONISA'),'2012-08-09','Visita domiciliaria realizada el pasado 9 de agosto en compañía de Silvia, T. Social de Valdelacalzada, y en presencia de Dª Mª José Jaramillo Sánchez, vecina y amiga. D. Julián se encuentra bien atendido por parte de su vecina, con cuya familia D. Julián mantiene una relación casi familiar, considerándolos él como sus sobrinos y nietos y viceversa. La casa está en buenas condiciones de habitabilidad, limpia y ordenada. Recibe el Servicio de Ayuda a Domicilio. El frigorífico está lleno. Es autónomo para su higiene y también hace su comida, aunque también Dª MªJosé le lleva la comida: estando allí le trajo la sopa para ese día y él ya tenía hechos unos garbanzos. Nos explicó cómo se duchaba, cómo hacía la comida y nos contó algunas de sus experiencias vitales. Esporádicamente se quedaba en silencio y empezaba a reírse sin motivo aparente por un instante, pero pudimos mantener con él una conversación coherente y animada durante toda la visita. En estos momentos, consideramos que D. Julián se encuentra bien atendido desde el SSB y por sus vecinos, disfrutando en estos momentos de un grado de autonomía suficiente que no hace necesario el tomar ninguna medida adicional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-08-10','-Hablo con Paula ( FEAPS CTRO. PENITENCIARIO) JESÚS ESTÁ EN EL MODULO 3 , POR EL MOMENTO SE ENCUENTRA BIEN . NOS SOLICITA QUE LE ENVIEMOS DINERO PARA LA COMPRA DE ROPA . SE LE ENVIARÁN MENSUALMENTE 100€ A SU CUENTA PECULIO , QUE EL CENTRO ADMINISTRARÁ A 25 € SEMANALES .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='VAZQUEZ'and apellido2='RODRIGUEZ'),'2012-08-11','Nos comunican del CSS de Mérida que D. Pedro ha sido trasladado a Urgencias del Hospital por presentar un episodio de desorientación y vómitos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2012-08-08','Se realiza visita domiciliaria a Almudena por parte de la CATEx. Al llegar a su casa nos dijo que esperásemos, que estaba terminando de depilarse: pudimos comprobar que lo había estado haciendo con cuchilla y un lavavajillas. La casa está prácticamente vacía: han desaparecido los muebles que había en los dormitorios y ella duerme en un colchón sobre el suelo y sin apenas ropa de cama. No tiene los roperos que antes había, su cama dice que se le rompió y la tiró, en otro de los dormitorios tiene un somier de 80cm como único mobiliario, apenas tiene ropa cuando antes tenía muchísima (solamente pudimos ver una maleta en el dormitorio, único lugar en el que podría tener algo de ropa). En la cocina apenas hay menaje en estos momentos: ni sartenes, ni ollas, tan solo un cazo, un molinillo y una batidora. El frigorífico desenchufado y vacío. La lavadora vendida (fuimos a ver al compardor para que la devolviese, el cual la tenía instalada en su casa y no puso inconveniente en devolverla, a cambio de los 70 euros que dijo haber pagado por ella). Los únicos alimentos que había allí eran un yogures dentro de uno de los armarios de la cocina. No estaba tampoco la mesa camilla que antes tenía, ni las sillas, ni la televisión: según ella se los rompió su tío la última vez que estuvo allí. Tenía la medicación en unos de los armarios de la cocina. Nos comentó que la ropa la tiró y que ahora su novio le debe 30 euros que le prestó. Cuando le dijimos que así no podía continuar, y que en nuestra opnión debería estar en un Centro como el CRR, se alteró bastante y empezó con las amenazas: "os voy a denunciar, voy a hacer que os metan en la cárcel como hice con mi tío..." A partir de este momento, no insistimos más en ese punto y volvió a tranquilizarse. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Pudimos hablar con su vecina, Dª Martina. Nos comentó que continuan las escaramuzas con su novio y la gente que viene, por las noches principalmente. "A mí me da pena y le he dado ropa que luego no le veo ponerse, va siempre desaliñada y yo le digo que por qué no se arregla un poco...". La han visto en los bares y jugando a las máquinas. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Estuvimos hablando también con Alberto, Psiquiatra del ESM de Don Benito. El considera que Almudena se mantiene estable, acude a sus consultas programadas y toma la medicación adecuadamente. Le informamos de la visita realizada y nos dió una nueva cita para Almudena el lunes 13 de agosto a las 12:20h, manteniendo la cita programada para septiembre ¿el 26? Pasamos nuevamente por casa de Almudena para darle la cita pero no parecía encontrarse en el domicilio, por lo que le dejamos la cita por debajo de la puerta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-08-13','Conversación con Mª Victoria, T. Social de Campanario. Valorar mejor momento para el traslado de DªAntonia. Lo comentará con la familia y nos llamará a en esta semana. xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx Alternativas: UHB de Mérida para valoración, diagnóstico y en su caso derivación a la Unidad de Psqicogeriatría del CSS de Plasencia (no hay plazas en estos momentos en la Unidad de Psicogeriatría de la Residencia "Felipe Trigo"). XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Llamada de Mª Victoria (13:30): cree que cuanto antes se haga el traslado mejor, pero no pdemosa contar con la colaboración de la familia porque, aunque están deseando que se resuelva esta situación, no se quieren implicar en la solución de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2012-08-13','Nos comunica Fernando (Apba. 3) que Pedro no ha podido quedarse en Calamonte porque el Hotel en el que se iba a quedar, como en ocasiones anteriores, ha cerrado. Sin la autorización de la CTAEx para cambiar de residencia volvió al Centro. Nos solicitan autorización para pasar del 13 al 17 de agosto en Calamonte, en el Hotel Romero (Josefa, 685-147427 y 671-682458), ya que la otra alternativa era la Casa de La Misericordia y no se ha podido concretar (solo disponían de plazas femeninas). Régimen: alojamiento y desayuno (42 euros IVA incluído). Lo llevará Fernando esta tarde y también lo irán a recoger. Comerá y cenará en el centro de Día, según se comprometió la Concejala. Tiene dinero para pagar el hotel, y en caso de que le faltase algo, lo abonarían cuando fuesen a recogerlo o nos mandarían la factura para pagarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-08-13','-tf. de la hna. de Jesús , Mª José : 677686398-634730990','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2012-08-13','-Nos llama Jose Ramón, inquilino con el que comparte piso en Badajoz ( 665311831) . La convivencia es insostenible, según él le roba comida , cosas , le insulta , amenaza... La he llamado a ella y lo niega todo , dice que es al revés , pero que no tiene miedo pq su novio se queda con ella todas las noches . El chico quiere que se vaya ella del piso y al revés , el contrato está a nombre de los dos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2012-08-14','Información de Fernando (Apba.3). Ayer muy bien todo, le acercamos al hotel, le concertamos la comida y cena en un bar centrico de su interes, tan solo 40 euros, que incluye comida dos platos mas refresco y por la noche refresco y bocadillo a elegir. Pedro así lo ha preferido. En principio por la noche lo acerca la policia local y por la mañana la compañera educadora de Calamonte. Por si alguien no pudiese hemos visto también la posibilidad de buscar un servicio de Taxi, le saldría unos 12 euros el viaje, esta opción la vemos correcta porque si algún día alguien no puede la necesita ya que el hotel esta a 3 o 4 kilómetros y tendría que atravesar la autovía. Por otro lado me han dado el numero de cuenta del hotel. Creo que lo mejor es que le hagáis vosotros la transferencia porque con el dinero que tenemos va andar ahí. Según el hotel son 42 euros por noche incluido el desayuno. por un total de 4 días. La transferencia hay que hacerla a XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Caja de Extremadura: 20099 0108 0300 7001 5665. Hotel Romero.XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Una vez hecha debemos mandar el justificante de transferencia a e-mail: director@hotelromero.com. Y después nos preparian la factura con los datos de Pedro Moreno. Si todo va bien el viernes tarde lo vamos a recoger. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Hablo con el Hotel y nos enviarán factura pro-forma para hacer luego la transferencia. Avisar al hotel (685-147427) una vez hecha la transferencia para que remitan la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2012-08-14','Visita de Carmen. Trae recibos del IBI, agua y basura de 2011. también recibo de Banco de Santander. También justificante de pago de los colchones (compró dos). NO ha visto al posible comprador de su casa como nos dijo en la visita anterior por estar de vacaciones. Sigue con la ambivalencia de vender la casa arreglarla, así como de comprar un piso en Mérida. Se le explica que mantener ambas casas es imposible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-08-14','Conversación Ana Isabel Tejero, T.Social (620-998979). Se comunica el próximo ingreso de Dª Antonia en Unidad de Medicina Interna para valoración por Neurólogo para descartar patología orgánica y, en su caso, interconsulta a UHB para diagnóstico de salud mental. SE INFORMA DEL DÍA EN QUE SE VA A PRODUCIR EL INGRESO: PRÓXIMO VIERNES 17 DE AGOSTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2012-08-14','-He intentado hablar con su psiquiatra , el Dtor. García Ordaz , pero no ha sido posible . Es del ESM de Valdepasillas , tf. 924218004 , quedo pte. volver a llamarlo para que nos comente cúando fue la última visita realizada y cómo se encuentra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2012-08-14','-Nos llama su hija Eva , tf . 654100037/603868304 solicita que traslademeos a su madre más cerca de su residencia para facilitar el acercamiento familiar . -Nos pondremos en contacto con R.M. Felipe Trigo para que una vez compensada lo tengan en cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2012-08-14','-hablo con la TS de RM para que nos comuniquen cuando esta señora esté estabilizada y no necesite la unidad de Psico para poder trasladarla a Caceres . Valorar psicogeriatrico de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-08-14','Se envía al 112 solicitud de traslado involuntario de Dª Antonia a la Unidad de Medicina Interna del Hospital de Mérida (S. Neurología) a realizar el próximo viernes 17 de agosto. Se omunica a Victoria (T. Social de Campanario) y a Anabel (T. Social Hospital de mérida).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2012-08-16','Se entrega solicitud de plaza pública a María León para tratmitación vía urgencia. Una vez llegue el Informe Médico en el formato de solcitud se enviará a los Servicios territoriales de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2012-08-16','Conversación con Hortensia, T. Soc. de Cañaveral. NO existe indicio alguno de que Dª Mª Cabezón sea tutora de su hija Eva María, tal como ha consultado la T.Social en el Juzgado de Cañaveral. En llamada al Juzgado Nº 2 de Cáceres, tampoco existe constancia de dicha situación. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Paloma, la hija de Fª María que vive en Madrid (91-8865966 y 667-647955) ha llamado al SSB manifestando estar de acuerdo con la medida tomada por esta Comisión de ingresar a su madre en una Residencia. Igualmente considera sería muy inoportuno ceder a la pretensión del resto de sus hermanos, con los cuales no quiere tener contacto alguno, de acercar a su madre a otro Centro más próximo a Cañamero.Se presta a apoyar a la Comisión en lo que esté en su mano. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Hortensia considera que Dª María va a mejorar muchísimo, y con rapidez, en el Centro, pero no cree que dicha mejoría pueda llegar a suscitar una posible recuperación de la Capacidad, por cuanto cree que Dª María siempre necesitará apoyo para su vida cotidiana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2012-08-14','Se escapa del CSS de Plasencia. Hablamos con el CSS y con la madre, Dª Julia. Comunicaran al CSS si llega a su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2012-08-16','Conversación con Rosa (CSS de Plasencia): Avisaron los padres que había llegado a su casa y ellos mismos lo llevaron nuevamente al CSS. Se ha planteado la posibilidad de, dado que sus "escapadas" parecen deberse a su necesidad de ver a sus padres, programar una salida mensual con la autorización de la CTAEx. Respecto a esto, que ya también hablamos con su madre, la CTAEx no se opondrá a dichos permisos si los profesionales que atienden a José Mª consideran que son beneficiosos para él. Como objección: que no coincida con su hermano en dichas salidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-08-17','SE realiza traslado y posterior ingreso de Dª Antonia en la UHB de Mérida para valoración y diagnóstico. En función del mismo, asignar recurso residencial. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Participaron en el traslado Cruz Roja, Guardia Civil, Médica y Enfermero del Centro de Salud y Policía Local. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX Pendiente realizar limpieza en profundidad de la vivienda. La T. Social, Victoria, buscará empresas en la zona que se puedan encargar de ello y nos enviará presupuesto. Sería conveniente que CTAEx estuviese presente para valorar qué cosas se pueden tirar y cuáles no (documentación, efectos personales, etc.). XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX De la vivienda sacamos unas piezas ¿de oro? que están en la CTAEX, un rosario y ropa que entregamos a Anabel, T. Soc. del Hospital de Mérida y algo de documentación que encontramos en una caja y que hay que revisar. XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-08-20','Visita a Dª Antonia en la UHB de Mérida. Conversación con el Dr. Alí. Dª Antonia padece de sordera (diagnóstico que no aparece reflejado en ningún informe del expediente) y carencia total de memoria reciente, lo que le lleva a vivir una época naterior, como si tuviera 60 años: cuenta experiencias de cuando tenía esa edad, con total detalle y coherencia, pero no recuerda lo que se le ha preguntado hace unos minutos. Alí enviará Informe clínico, valorándose la posible derivación a la Unidad de Psicogeriatría del CSS de Plasencia. Se le pide que por Interconsulta con Neurología se valore una posible demencia. Relaizará esa petición. Dª Antonia insiste en querer marcharse otra vez a Villanueva (no nombra Campanario).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2012-08-21','Conversación con Victoria (T. Soc. Campanario). Mañana acudirá una empresa de limpieza a la vivienda con ella para hacer un presupuesto y nos lo enviará a la Comisión. El día de la limpieza estará presente la Comisión, para valorar efectos personales o documentos que no se deban tirar. Nada podrá ser retirado de la vivienda sin autorización de la Comisión, ni se autorizará a familiares su presencia en la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CARDENAS'and apellido2='CARMONA'),'2012-08-21','Se deriva al Servicio de Urgencias del Hospital de Mérida para valoración.','2');
