insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='PEREZ'and apellido2='GARCIA'),'2012-08-23','-Sigue residiendo en el hogar Siloé de Jerez de la Frontera. Tuvo un accidente en la misma y se va a negociar indemnización con Maphre . Quedamos pendiente que el director nos envie la documentación para firmarla. Lo que perciba de la misma se ingresará en su cuenta y se administrará deste CTAEX , en ningún caso irá a la cuenta del H. Siloé , como consultaba el director.','2');
