insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='FERNANDEZ'and apellido2='VILLANUEVA'),'2012-09-18','-Nos comunican desde el CSS Plasencia que el marido ha fallecido , no tenian contacto en los ultimos 40 años. Existe una casa en común en el País Vasco donde residen todos sus hijos , tb con enfermedad mental , han decidido dejarle la casa en usufructo a una de las hnas. ,no necesita el notario ningún documento y nosotros aceptamos la idea , esta señora está en la Unidad de psico , sin posibilidad de externalización y la hija se hace cargo de todos los gastos. De otra forma , la herencia sería gravosa para Juana .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2012-09-19','Citados en consulta de Oncología con la Doctora Lupian nos informa que la respuesta al tratamiento de quimioterapia ha sido positiva, tiene que teminar con el sexto ciclo y posteriormente valorar la posibilidad de una cirujia mediante pruebas objetivas, y teniendo en cuanta la edad del paciente. Desde la CTAEX se comunica a la medico que asumimos los criterios facultativos y si consideran que el mejor tratamiento pasa por la intervención quirurgica, desde aquí firmaremos el consentiento informado. La doctora manifiesta que al comienzo del tratamiento Jose Maria muestra desacuerdo ante una intervención quirurgica. Quedamos pendientes de resultados de las prubas.','2');
