insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2012-11-28','Servicio Jurídico de Santander Consumer. Susana Doniz (902-733866). PROPUESTA: Acuerdo extrajudicial para, del saldo deudor principal de 3485.11 euros, realizar una QUITA del 15%, quedando a pagar 2963 euros. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Juzgado de 1ª Instancia e Instrucción nº 1 de Cáceres. En este Juzgado se sigue Procedimiento de Ejecución de Títulos Judiciales nº 543/2008. Se consulta a D. Fernando Montero, Secretario Judicial: es necesario solicitar autorización judicial mediante procedimiento de Jurisdicción Voluntaria. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Beatriz, Secretaria del Servicio de Ejecución: nos remitirá relación de procedimientos de embargos. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Susana Doniz: hará la propuesta a su servicio jurídico y, si es aceptada, contamos con 20 días para realizar el pago(máx. 30). Se insiste en la posibilidad de que estos plazos sean más flexibles dada la preceptiva autorización judicial. Nos enviará dicha propuesta por correo electrónico para adjuntar a nuestra solicitud al Juzgado.','2');
