insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2012-10-08','Información recibida del CRR de Plasencia en relación con la Tutelada: Concha Alejandro Durante la tarde del Jueves Concha fue agredida por otra usuaria del CRR, la agresión consistió en agarrarse entre las dos, en el caso de Concha fue agarrada del cuello. Lo que desencadenó esta agresión fue que durante mucho tiempo Concha ha ido comentando con los otros usuarios del CRR y con otras personas con las que se relaciona en Plasencia, que la usuaria agresora es Lesbiana (esto parece ser que es invención de Concha), la compañera de residencia no soporta que la llamen así. Cuando detectamos esto hicimos que Concha pidiera disculpas a esta persona, pero evidentemente el rumos ha seguido creciendo, es en esa tarde del jueves cuando alguien ajeno al recurso le pregunta si es cierto lo que se dice de su condición sexual, acto seguido busca a Concha y se produce la agresión. Los profesionales que estaban en la tarde las separan y se avisa al 112. Aparece Policía Nacional y ambulancia medicalizada, la doctora que viene a la urgencia es precisamente la que, en atención primaria, atiende a Concha y a la otra usuaria. Se realiza un parte de lesiones de Concha, donde se especifica que no hay lesiones, a cada una de ellas le administra un lorazepan, por que las dos se encuentran nerviosas. La doctora habla con las dos y se marcha, antes de irse comenta al turno de tarde que ella tiene la obligación de informar a los juzgados cuando ocurren estas situaciones, si bien es cierto que al no existir ninguna lesión probablemente se archive. Desde el CRR creemos que el incidente tiene que quedar aquí y, sobre todo, por la parte que le toca Concha, creo que entrar en proceso legal: denuncia, juicio de falta… no lleva a ningún sitio en este caso, las dos han pedio perdón en público, Concha a desmentido el rumor diciendo que es invención suya y la otra persona reconoce su error por la agresión, reconoce que fue un arranque de ira y disculpa a Concha. Si nos llega del juzgado o la policía alguna información o notificación os la hago llegar.','2');
