insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2012-10-26','Consulta al Juzgado de Logrosán. +++Podemos solicitar la documentación relativa a las Ejecutorias que tiene pendientes D. Antonio. +++Fiscalía ha solicitado ingreso en Centro adecuado para D. Antonio de forma permanente, petición que ha quedado en suspenso por estar en estos momentos cumpliendo ingreso voluntario en CSS, pero que se retomará una vez dada el alta a los seis meses de estancia en UME (dan por sentado que va a estar este tiempo). +++Proponen que, a través de Gabinete Jurídico se solicite al Juzgado una modificación de la capacidad en el sentido de que sea una Tutela completa, pudiendo entonces solicitar al Juzgado autorización de internamiento involuntario en Centro adecuado. *********************************************************** Lo preferible sería que él aceptase dicho internamiento de forma voluntaria, tal como el Dr.Agapito Herrero, su psiquiatra, le ha propuesto, sin aceptar esta posibilidad. Por otra parte, ya desde el propio CSS se ha solicitado plaza para Piso Tutelado.','2');
