insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2012-10-26','Dª Josefa ingresa en la UHB del Hospital Virgen del Puerto de Plasencia (fax 29-10-2012. Desde el día 25, nos informan desde Asoc. "Vera", Dª Josefa no quiere tomar la medicación ni comer. Tampoco atiende a razón alguna: "Solo dice que quiere marcharse y que no quiere hacer nada, que quiere suicidarse para irse de aquí..." (fax 26-10-2012)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2012-10-30','Se celebra "Juicio" rápido por "delito de amenazas en el ámbito familiar" contra D. Ildefonso en la persona de swu hermana Dª Consolación García Rodríguez (ver Sentencia 41/12 de 30 de octubre), quien estaba viviendo con él en su piso desde el pasado mes de septiembre (sin haber sido comunicado a CTAEx). FALLO: CONDENA a +++38 días de trabajos en beneficio de la comunidad. +++privación del derecho a la tenencia y porte de armas durante 8 meses. +++Orden de Alejamiento no inferior a 200 metros de su hermana (incluye cualquier tipo de contacto) durante 4 meses. +++costas. ILDEFONSO acepta la Sentencia, consciente de que ello supone el reconocimiento de los hechos QUE ÉL EN TODO MOMENTO NIEGA, pero no aceptar la misma significa, según su abogado D. Manuel David Rodríguez Holguín (610-794230. Fax: 924-301535. Correo: 3009@ICABA.COM) ir a juicio y exponerse a pena de prisión. *********************************************************** Ildefonso no quiere dejar a su hermana y su sobrina de 5 años en la calle: está dispuesto a seguir pagando el alquiler (no quiere rescindir el contrato y ponerlo a nombre de su hermana, asumiendo cualquier desperfecto o problema en la vivienda). Se irá a vivir de momento con sus padres en Puebla de sancho Pérez y tratará de cumplir los servicios a la comunidad para dicho Ayuntamiento. ILDEFONSO: 675-864684 (tiene las llamadas entrantes restringidas) VIGILANCIA PENITENCIARIA: 924-238272','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2012-10-31','Conversación telefónica con Escalona (Gabinete Jurídico): Se puede solicitar la modificación de la capacidad aportando los correspondientes informes psiquiatricos, fundamentalmente, pero también informe social. Se remiten a gabinete para que se tramite la petición. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Rosa (CSS Plasencia): consideran que D. Juan no debe salir de alta mientras se tramita la modificación de la capacidad, aunque tampoco se tiene previsto agotar los seis meses de UME. Su opción es, mientras se sustancia la modificación de la capacidad, proponer al juzgado que, como medida cautelar, autorice la permanencia de D. Juan en el CSS. Nos enviarán los Informes Psiquiátricos y Sociales que justifiquen la modificación de la capacidad, para después, enviarlos a Gabinete Jurídico para que la solicite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='ESPINO'and apellido2='ROMAN'),'2012-10-31','Conversación con Rosaura, T.S. de Salorino. Tiene en el despacho a Dª Josefa Carrasco Román, prima de Dª Dionisia. Tiene documentación bancaria que nos quiere hacer llegar. Al parecer la empresa que gestionaba la Residencia (Geriex, S.A.) hizo cobros indebidos a Dª Dionisia, pero no existe posibilidad en la Residencia de averiguar a qué se debieron dichos cargos. Nos enviará esa documentación y se informará al Juzgado por si pudiera haber algún cobro indebido. Dª Josefa se "hizo cargo" de las cartillas en 2010 " a petición" de Dª Dionisia.','2');
