insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2012-11-05','Llama Antonio, hermano de Aurora. Dice que ha sacado 500 euros este mes y se los ha dado a alguien. Dice que en diciembre la ha citado el médico forense para ¿remover? la tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2012-11-05','Llamada telefónica: D. Francisco (607-714450) necesita 350 euros para saldar una deuda con un tal Miguel ¿? por jugar a las máquinas.. Dice que ha empezado a Jugar a las máquinas ¿?. Va a ir al Médico para decirle que le ayude... Su médico es D. Julián Ortega (924-843801): le ha contado la posible ludopatía que "de repente" padece y las pastillas que tomaba ¿para dejar de fumar? Su médico le ha dicho que son incompatibles con el tratamiento que sigue y le ha dado el teléfono de la ADAT (924-811281). No le ha referido ningún tipo de amenazas por parte de terceras personas. El Dr. Ortega no ha notado nada diferente en D. Francisco respecto a consultas anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='GARCIA'and apellido2='SANTOS'),'2012-11-05','Se envía carta al Juzgado de 1ª Instancia Nº 1 de Don Benito informando del procedimiento para reclamar la indemnización de la Sentencia de 15 de julio de 2009, del Juzgado de lo Penal Nº 1 de Don Benito.','2');
