insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2012-11-06','Conversación con D. Francisco. Jura que las amenazas que me contó ayer son ciertas y que está dispuesto a llamar a ADAT esta misma mañana. Se le insiste en que esta situación no se debe repetir y que, si tiene algún problema en este sentido debe avisarnos lo antes posible.','2');
