insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='CINTA'and apellido2='GONZALEZ'),'2012-11-07','Acudimos a la consulta de oncología en el H. "Virgen del Puerto", Plasencia. Diagnosticado de adenocarcinoma de páncreas con metástasis a peritoneo e hígado (pendiente por parte de Raquel de envío de informe desde Mensajeros de la Paz (Nuñomoral). Esperanza de vida: muy corta. A la espera de ser citado por el Servicio de Cuidados Paliativos: tendremos que ir a dicha cita como tutores (si no pudiese desplazarse a Plasencia sería en Nuñomoral).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2012-11-08','Visita en CSS de Plasencia. José María se encuentra bien, contento de estar en su tierra. Dice que dejó en "Los Robles" un walkman que le prestó a un compañero (Rafael Sanz Amado), 13 cassettes y una "cartuchera" con tres CDs','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2012-11-08','Llega por FAX de la Audiencia Provincial notificación de Ejecutoria 25/1994: se le ha retenido el pago de la PAC, 1840.32 euros.Por parte de CTAEx no hay ninguna alegación que hacer Ser comunica al SSB de Siruela para que lo comuniquen a D. Francisco (se envía por fax al 924-626377). Hablamos también con D. Victoriano. C. salud: 924-626180. Médica de Familia Dra. Pilar Vilaplana. cita para el oftalmólogo en Villanueva-Don Benito. .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2012-11-08','-Nos llaman de la RM Coria , allí sólo entran por dependencia y solo hay plazas concertadas para asisitidos con lo que no cumple requisitos para ella. Está pte. su valoración por dependencia , cuando la tengamos y dependiendo de su grado y nivel subirselo a May para ver si hay otras RM donde pueda ser trasladado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BENITO'and edp.apellido1='TEMPLADO'and apellido2='DURAN'),'2012-11-08','-Le va a ser concedida plaza en Felipe Trigo para ser trasladado . Pte. de la resolucion .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2012-11-07','Visita a D. Juan en el CSS de Plasencia. hablamos con el Dr. Agapito Herrero, quien nos entrega Informe psiquiatrico en el que se aconseja su permanencia en el CSS. Se considera oportuno solicitar solicitar ampliar la incapacitación a una tutela completa para mantener el ingreso con la correspondiente autorización judicial. Simultáneamente a la solicitud para modificar la capacidad, solictar autorización de internamiento en Unidad de Larga Estancia. No se considera oportuno su retorno a su casa. Se aporta también Informe Social. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ D. Juan no quiere volver a corto plazo a su casa porque -dice- le han amenazado de muerte. Se le propone que considere el CSS como un "hotel" del que podrá salir de visita cuando se considere oportuno "para ver cómo está mi casa, hablar con los amigos del pueblo y luego volver aquí" -continúa el mismo-. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Pendiente hablar con Escalona para solicitar el cambio de capacidad y la autorización de internamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2012-11-12','-INGRESA EN APROSUBA 10 - AZUAGA CON AUTORIZACION JUDICIAL DE INTERNAMIENTO NO VOLUNTARIO . EL TRASLADO LO HIZO LA HNA. YA SE HA COMUNICADO EL INGRESO AL JUZGADO .','2');
