insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2012-11-14','Ingreso voluntario de D. Ildefonso en la UHB del H. de Mérida. Psiquiatra: Dr. Alfredo de La Rubia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2012-11-14','Conversación con la Dra. Consolación Sánchez. También considera oportuna la ampliación de la incapacidad y la necesidad de ingreso en Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2012-11-16','Visita domiciliaria realizada ayer, 15 de noviembre, en la que estuvimos presentes D. José Antonio, Dª Josefa (madre), Manuela Calderón (T. Social SSB de Higuera La Real) y Nelly (Técnico del CRPS de Zafra que visita a la familia todos los jueves). Contenido de la visita: Se informó del papel de CTAEx como curadores de D. José Antonio y del contenido de la Sentencia de incapacitación, así como de las posibles consecuencias que, de no cumplirse la misma en los términos que en ella se indican, especialmente en lo referido al seguimiento del tratamiento, se podrían producir. ******************************************************** Dª Josefa lleva muy mal las voces y la forma de hablar en la que se dirige a ella su hijo. Por otra parte ella parece también bastante inflexible con todo aquello que hacve su hijo y que, en su opinión, no debería hacer. Todo ello lleva a contínuas discusiones entre ambos. durante la visita, la madre se quejó de que su hijo le había puesto la TV en el pasillo (como así era) y no quería quitarla. Le propusimos varias veces ayudarle a trasladarla a su habitación, negándose en todo momento, a pesar del riesgo para ambos por lo cables extendidos por el suelo, uno de los cuales tenía una clavija en malas condiciones. ********************************************************** E.S.M. de Zafra. Por propia voluntad, D. José Antonio ha empezado a acudir este verano nuevamente a Salud Mental: "...No me encontraba bien..." Tiene nueva cita el próximo 28 de noviembre. ********************************************************* Manejo del dinero:según comentó, sus gastos son los relativos a la compra de prensa y revistas(3 periódicos al día y 1 ó 2 revistas), Gol TV (25 euros/mes) y los cafés que se toma en el bar. Calculamos unos 160 euros/mes. D. José Antonio estuvo de acuerdo en limitar la cuenta para que puesa sacar 40 euros semanales (el quiere poder sacar 4-5euros diariamente como hasta ahora).Se empezará esta limitación a partir del 1 de diciembre. *********************************************************** Consultorio Local. Mantuvimos una entrevista con el Médico de Familia de D. José Antonio, el Dr. José Manuel Cabezón Pons (Consultorio: 924-727142. Corporativo: 43923). Manuela (Enfermera del Consultorio). Nos confirmó la derivación al ESM de Zafra en julio de este año y la próxima cita para el día 28 de noviembre. Total colaboración para supervisar el seguimiento del tratamiento, cumplimiento de las consultas programadas, etc. Derivará a D. José Antonio a traumatología para valorar su lñesión en mano izda. y posterior rehabilitación. D, José Antonio ya estuvo en un Fisioterapéuta "de pago" porque no quería de la Seguridad Social. Luego dejó de ir y, durante la visita, se llegó a su compromiso de acudir a su Médico para quew lo derivara a Traumatología. ********************************************************** Plazo para valorar el seguimiento del tratamiento, asistencia a consultas de Atención Primaria, ESM, traumatología y control del gasto: 2 MESES. En caso de que no se cumplan adecuadamente estos requisitos se pondrá en conocimiento del Juzgado de 1ª Instancia e Instrucción de Fregenal de la Sierra para solicitar internamiento no voluntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='FRUTOS'and apellido2='DORADO'),'2012-11-14','D. Ignacio ha sido derivado a la UME del CSS de Mérida. Según evolución podría pasarse a Larga Estancia o bien, si su evolución lo permitiese, a Centro Residencial de Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2012-11-16','Ley Dependencia. Apertura: 24-01-2011. Valoración: G1,N1. Los expedientes con este G y N están paralizados si su valoración fue posterior al 31 de diciembre de 2011. Esperamos confirmación. hablar con Nati, Jefa de Sección Dependencia de la zona de Zafra (924-556010).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BENITO'and edp.apellido1='TEMPLADO'and apellido2='DURAN'),'2012-12-16','-SERÁ TRASLADADO LA SEMANA QUE VIENE DE LA RESIDENCIA HERNANDO DE SOTO DE JEREZ DE LOS CABALLEROS A R.M. FELIPE TRIGO . EL TRASLADO LO HACEN CON TTE. DE LA RESIDENCIA Y LO ACOMPAÑARÁ LA PSICÓLOGA . COMUNICARÁN CUANDO SE HAGA EL TRASLADO.','2');
