insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2012-11-19','Conversación con Dª Cristina, sobrina de D. Pedro. Desea seguir manteniendo el cuidado de su tío, a pesar de la propuesta de considerar por nuestra parte la contratación de un servicio que se encargue de sus cuidados. Se le informa nuevamente que los 650 euros que se le dan es todo lo que se le puede enviar mensualmente. Con D. Pedro tratamos de hablar, especialmente del consumo de tabaco mensual que, según su sobrina, supone 300 euros. No fue posible llegar a ningún acuerdo con él porque, enfadado como estaba, insitía en que " mañana mismo iré a ver al Juez para que os quite la tutela ".','2');
