insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2012-11-26','-nos comunican del ESM de Jerez que en el mes de noviembre no ha querido ponerse el inyectable. Archivado en su expte. la comunicación. Si para el mes que viene vuelve a suceder se comunicará al juzgado para que adopte las medidas oportunas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2012-11-27','DILIGENCIA VISITA EN UHB, SOLICITADA POR EL Dr. ALFREDO De LA RUBIA. Fecha: 27 de noviembre de 2012 Intervención: Se prevé el alta de Ildefonso dentro de unos días, una vez que sepamos, por parte de SS Penitenciarios, cómo se va a cumplir la Sentencia del Juicio celebrado en Mérida el pasado mes de octubre. Ildefonso reconoció el consumo de cannabis previo a este último ingreso, consumo que, según su testimonio, no le supuso gasto alguno porque se lo proporcionó su hermana. Preguntado por su Psiquiatra si se veía con capacidad para afrontar el alta volviendo a su piso, Ildefonso respondió que sí. Una vez dado de alta, deberá pasar una supervisión semanal en UHB a propueta de Alfredo de La Rubia, propuesta que Ildefonso aceptó.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2012-11-27','DILIGENCIA REUNIÓN EN UHB. Fecha: 27-11-2012 Motivo.....: Situación de la Tutelada Dª Mª Luisa Lucas Lucas Reunidos: · Alfredo de La Rubia, Psiquiatra. · José Gómez, Psiquiatra. · Maribel, Psiquiatra CSS de Mérida. · Asunción Cabrera, Psicóloga CSS de Mérida. · Pedro Gracia, CTAEx. Actualmente Luisa se encuentra ingresada nuevamente en la UHB de Mérida, por reiteración de su comportamiento autolesivo. Se considera, por parte de sus psiquiatras, que todos los intentos llevado a la práctica para mejorar su situación no han dado los resultados deseados, ni los tratamientos farmacológicos, ni los psicológicos. Por ello, y dada la gravedad del comportamiento de Luisa hacia sí misma, que la pone en situación de grave riesgo para su vida, se considera oportuno plantear como siguiente paso la alternativa de la psicocirugía, aplicando la ténica de electrocoagulación en la zona del cerebro que controla ese tipo de comportamiento. Dicha alternativa se va a llevar a estudio para valorar la viabilidad de la misma. Desde CTAEx, si el dictamen médico es favorable a dicha intervención, y los beneficios de la misma son claramente superiores a los riesgos, no habría oposición a la misma. No obstante, previa a la intervención, se dará conocimiento de la misma al Juzgado de 1ª Instancia e Instrucción Nº 4 de Mérida y a la familia de Luisa. En caso de que la familia se opusiera a la intervención, si bien la responsabilidad es de la Comisión Tutelar, se informaría al Juzgado de dicha negativa. Una vez estudiado el caso por parte de los profesionales sanitarios para ver la voiabilidad de la intervención, se remitirá Informe Clínico a la CTAEx que ésta pondrá en conocimiento del Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2012-11-26','A Mª Pilar le llaman Maria . Ha fallecido la Sra. con la que vivia y se ha ido a la casa familiar con los hnos. Va a acudir al Ctro de Dia de la localidad unas horas , ellos hacen domiciliación bancaria . Se va a contratar a una auxiliar de ayuda a domicilio con la que empatiza a través de la empresa " el angel " para que la acompañe 3 horas al dia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2012-11-28','Beatriz, Secretaria del Servicio de Ejecución del Juzgado de 1ª Instancia e Instrucción nº 1 de Cáceres: nos remitirá relación de procedimientos de embargos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2012-11-29','Conversación con Consolación, del SCOPC (Servicio de Coordinación del Procedimiento Civil) del Juzgado de 1ª Instancia Nº 4 de Cáceres (927-620407/8. Fax: 927-620409) El informe remitido por fax el pasado día 16 de noviembre se le ha pasado a Fiscalía junto con el Inventario (de 17 de julio) para que lo informe conjuntamente. Nos enviarán la respuesta del juzgado, cuando éste la emita, por fax y correo ordinario. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Raquel ("Adelanta"): le ha llegado a Pilar, la mujer de Gabriel, resolución de pago de la Prestación Vinculada al servicio: son alrededor de 7000 euros con los que se podría saldar la deuda contraída con la empresa y continuar con el Servicio, comenta Raquel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2012-11-29','Conversación con Rosa, CSS de Plasencia (927-428800). José Antonio llegó bien, aunque se mostró algo nervioso al reconocer el lugar en el que ya había estado. Habló con su padre y hermano por teléfono... Su Psiquiatra es el Dr. Agapito Herrero. TELÉFONO DE CONTACTO EN UME para hablar con José Antonio :927-428801.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2012-11-29','Conversación con Rosa, CSS de Plasencia (927-428800).Jorge llegó bien del viaje y no planteó problema alguno. Su Psiquiatra es el Dr. Agapito Herrero. TELÉFONO DE CONTACTO EN UME para hablar con Jorge:927-428801.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2012-11-28','Trámites con el Depósito de Vehículos de Badajoz. Julián, Oficial del Depósito (924-274943). Requiere:certificado de Jefatura de Tráfico, documentación del seguro de coche, que se autoriza hoy a la entidad bancaria para que lo pague (ya ha remitido el justificante de pago) y se le autoriza reintegro extrordinario para el pago de la multa y la retirada del vehículo, además de 20 euros para gasolina. Según conversación con Francisco, dispone de toda la documentación necesaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2012-11-29','Conversación con Yolanda. Llama muy alterada, llorando, porque después de ir a por el coche no se lo han dejado sacar del depósito (ayer por la tarde). Había algún problema con la ITV (pendiente de pasar). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Francisco. Me comenta que ha estado otra vez hoy en Tráfico, que tiene que pagar las tasas de la ITV y que "pasa" del coche, que "ya está harto" y que "ya no quiero el coche...". Además, no encuentra la documentación del mismo porque la ha debido perder, según dice. No quiere pedir copia a Tráfico: " he perdido el coche y ya está..." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Julián, Oficial del Depósito. Le comento la situación y quedo con él en que Francisco Javier vaya mañana a hablar con él para solucionar el tema y tratar de evitar que durante los trámites para recuperar el coche no tenga que pagar las tasas de estos días. Llamo a Francisco para comentarle que debe ir mañana a hablar con Julián. Quedamos en ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2012-11-29','Conversación con Juan. Dice que está en Guadalajara con su hermana Encarnación, con la cual también hablamos. DEMANDA: DINERO PARA ROPA. ALTERNATIVAS (tratadas con su hermana): que se la compre ella, remita las facturas y pago por trasferencia (NO SE LO PUEDE PERMITIR); acudirá a una tienda de la que es clienta, pedirá presupuesto de lo que necesite y nos lo remitirá (se proporciona el número de Fax). Nos pondremos en contacto con el comercio para, una vez emitida factura, hacer la trasferencia a la cuenta que nos indique. Según Juan, a fecha 26 de noviembre, su saldo en cuenta es de 1096 euros (pendiente de confirmar por nosotros, pediremos consulta de saldo). Se limita el gasto a 200-250 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2012-11-30','Conversación con Antonio García,(EALEX:696-749707). PERMISO DE NAVIDADES: NO se autoriza la salida de Daniel a casa de su abuela materna, Dª Mª Emilia Rangel, de la forma solicitada.SE AUTORIZA DE FORMA INDIVIDUAL salir los días 25 de diciembre, 1 de enero y 6 de enero a comer a casa de su abuela, quien lo recogerá a las 13 horas y lo volverá a llevar al piso a las 17 horas. Cada autorización queda condicionada a que la/las anteriores hayan resultado beneficiosas para Daniel. COMENTA Antonio que las visitas de los jueves se han retomado en septiembre, cumpliendo la abuela todas las indicaciones que desde EALEX se le han hecho. Al parecer, la abuela se ha separado del marido y ya no viven juntos (¿?). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Juicio aplazado el 25 de septiembre. Dice Antonio que la fecha que le han comentado desde el juzgado (por teléfono) es el 23 de enero a las 10:30h. LLAMO AL JUZGADO: SE CONFIRMA FECHA Y HORA.Enviarán citación por fax y correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2012-11-30','Conversación con Julián, Oficial del Depósito de Vehículos de Badajoz. Francisco Javier recogíó ayer con Yolanda, su mujer, el vehículo. (Él tiene intervenido el carnet hasta mediados de 2013)Ha pagado la ITV y está pendiente de pasar la revisión (la ITV la tiene caducada desde 2010). POR EL DEPÓSITO DEL COCHE solamente LE HAN COBRADO 243 euros de los más de 500 que debía de abonar.','2');
