insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2012-12-12','_ Se ha solicitado PNC , Sole la TS de la Luz queda encargada de enviar un cdo. del centro que nos piden . Luego optaremos por PNC y dejaremos la PF . Cuando llegue la resolucion de la PNC avisar a Sole para que haga el cambio de la tarjeta sanitaria.','2');
