insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-12-18','Nos llega Cédula de Requerimiento de Pago del Juzgado de lo Penal Nº 1 de Badajoz: 6000 euros. Dejo mensaje telefónico para hablar con el abogado de Jesús, D. José Antonio Casado (924-235083).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2012-12-20','- Están negociando PIA de dependencia , al estar curatelado no podemos intervenir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='LOPEZ'and apellido2='PILARES'),'2012-12-13','Traslado e ingreso de Dª María en el CRM "Felipe Trigo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='LOPEZ'and apellido2='PILARES'),'2012-12-19','Visita realizada a Dª María por parte de CTAEx. Se encuentra bastante bien, pero no era esto lo que quería: "Yo quería una casita para mí...". Ha establecido una cierta relación con otra reidente, Dª Enriqueta, con la que parece congeniar. "Aquí ya no tengo frío, eso sí..." -dice-','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2012-12-19','Visita a la casa de Dª Carmen en Valdecaballeros, donde nos reunimos con el constructor, D. José Antonio Belmonte. Se le encarga la reconstrucción de la cubierta por el presupuesto indicado (2645 euros), al que habrá que añadir unos 100-150 euros más por la instalación de un canalón. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ El vecino de Dª Carmen estaba limpiando el solar aledaño, el afectado por las humedades. Quería que, a medias, nuestra tutelada levantara una pared medianera nueva sobre la que él quiere edificar, superando la altura de la cubierta de la casa de Dª Carmen. Respecto a la legalidad de esto, el constructor comentó que se podía levantar hasta 1.5 m por encima de la otra vivienda, pero advirtió al vecino de que esa obra necesitaba permiso y un proyecto de un arquitecto. Desde CTAEx se informó al vecino de que en esa obra no tenía nada que ver Dª Carmen: nosotros nos íbamos a limitar a la reconstrucción de la cubierta y aislamiento para no perjudicarle a él. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se le pidió al constructor que hiciese otro presupuesto para reformar la planta baja de la casa, ya que en la última entrevista que tuvimos con Dª Carmen y Mari Ángeles en los Pisos Supervisados, aquella quería seguir manteniendo la propiedad para acudir allí cuando deseara.D. José Antonio nos enviará el presupuesto con un plano de la reforma para exponerlo a Dª Carmen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2012-12-19','Visita domiciliaria a Dª Almudena. Había recibido el somier, el colchón y la almohada. Faltaba la ropa de cama. Hablé con Tamara, Delegada de Apoyo, quien se encontraba en la tienda "El Pavo" de Vva. de la Serena.Hablé con la encargada para que le entregaran la ropa de cama a Tamara asegurando que se le haría la transferencia a la cuenta indicada por la tienda. Quedamos en que así se haría. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ La casa de Almudena está cada vez más vacía: la mesa camilla había desaparecido porque "se había roto"; dos sillones que había allí "los trajo mi tío que los encontró en la basura"; el colchón de matrimonio en el que dormía, absoluntamente antihigiénico, estaba en el suelo al lado del somier y colchón nuevos (me dijo que llamaría al Ayuntamiento para que lo recogiera)... Me dijo que ella prefería un colchón de matrimonio "Porque ahora Miguel Ángel -su "novio"- pasa las noches conmigo. Así me siento más protegida. Pero por el día no se queda aquí...". Cuando ya me marchaba, apareció Miguel Ángel en la puerta. Almudena me pidió 150 euros para estos días, comprarse ropa, etc. Enseguida Miguel Ángel me pidió 300 "porque tienen muchos gastos". +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Me reuní con Alberto, Psiquiatra del ESM de Don Benito que lleva el caso de Almudena. Él no ve variación alguna, ni motivo para ingreso involuntario. La próxima cita la tiene en febrero y está en contacto con nosotros por si no acude, especialmente ahora que ya no vamos a contar con la colaboración de los Delegados de Apoyo de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='FRUTOS'and apellido2='DORADO'),'2012-12-21','Visita domiciliaria junto a D. Ignacio y Mª Eugenia (CSS Mérida).(Hay que descargar las fotos del móvil). Hablamos con Nieves, T.Social del C.Salud: hablará con Marta, del SSB, para ver la disponibilidad de vivienda de alquiler social para D. Ignacio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2012-12-27','-Nos comunican que Ramón se ha puesto el inyectable esta semana , de todas formas , se solicitó auxilio judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2012-01-02','- Hago escrito solicitando a Infancia y Familia mantenimiento de plaza en el piso de EALEX en Badajoz hasta la finalización del curso académico en el CEE los Angeles. -Solicito plaza en Centro de Discapacidad para que en Junio se proceda al traslado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2012-12-19','Llamo varias veces al teléfono de D. Antonio Casado Falcón (924-235083)entre el 19 y el 21 de diciembre, dejando otros dos mensajes en su contestador. Doy aviso a las compañeras los días que estoy de viaje por si llama a la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2013-01-03','Llamo nuevamente al despacho del abogado pero sigue saltando el contestador. En esta ocasión no dejo mensaje. Llamo al Juzgado de lo Penal 1 de Badajoz, pero tienen el mismo teléfono.Me aconsejan nuevamente hablar con el abogado sobre el tema de la responsabilidad civil y los 6000euros antes de hacer ninguna otra cosa. Llamo al Colegio de Abogados (924-230333)para que me den algún otro teléfono de localización, pero no cogen el teléfono. Seguiré intentándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCAS'and edp.apellido1='DIAZ'and apellido2='VAZQUEZ'),'2013-01-03','Llamada en relación al Informe de fecha 12-12-2012 emitido por Ana Belén, Directora y Psicóloga del CAMP. La chica actualmente está de vacaciones de Navidad con su familia. Se le ha pedido, de acuerdo con la familia de la chica, un cambio de recurso para ella. Se volvieron a pegar hace una semana, antes de vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='LOPEZ'and apellido2='PILARES'),'2013-01-03','Llamada de Teresa, T.Social del "Progreso", para interesarse por Dª María. Se le informa del ingreso en "Felipe Trigo" y de la visita realizada por CTAEx el pasado 19 de diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MAURO'and apellido2='PEREZ'),'2012-12-13','13 y 14 de diciembre. Ana Belén, Directora del CAMP, la CTAEx y Visitación Muñoz (Sepad)realizamos gestiones para el ingreso de Dª Isabel en el Hospital de Don Benito, al habérsele detectado una enfermedad de declaración obligatoria (EDO). Desde CTAEx se pidió autorización de ingreso para evitar contagio, comunicnándolo al Juzgado y Fiscalía de Villanueva de la Serena, indicándosenos que no era un motivo para dar una orden judicial de ingreso involuntario. Las gestiones realizadas posteriormente entre las personas antes referidas y la Dirección del SEPAD finalizaron con el ingreso de Dª Isabel en el Hospital Don Benito-Villanueva el día 14 a las 20.30 horas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DIAZ'and apellido2='RODRIGUEZ'),'2013-01-04','Pilar, T. Soc. del CSS de Plasencia nos comunica el fallecimiento de Dª Isabel hace una hora. Descanse en Paz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2013-01-04','Lola Bernal, T.Social SSB de Siruela. D. Francisco no acudió a la cita de dermatología que tenía pendiente. Actualmente a la espera de ser citado para oftalmología. Nos avisarán cuando sea esa cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2013-01-04','Conversación con José Antonio (Asociación Vera). Dª Josefa se encuentra en casa con su familia, tras el alta hospitalaria del CSS de Plasencia (tenemos informe de su estado de fecha 4 de diciembre y entrada el 12-12-2012)que no fue comunicada a esta Comisión. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Rafael (hermano de Josefa/ 620-143379): dice que su hermana no está mal, que no quiere volver al Centro y que se puede quedar allí con ellos...pero que necesitaría que le enviásemos dinero para "sus gastos". COMUNICAR AL JUZGADO ESTA SITUACIÓN. LLAMAR A CSS PARA PEDIR INFORME DE ALTA Y VALORACIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2013-01-08','Llamada de D.José Tello, sobre venta de finca. Se le comunica que hemos decidido no vender ninguna finca en estos momentos ya que la hermanas Collado no lo necesitan actuyalmnenbt. Llegado el caso, la Comisión contaría con D. José Tello para la opción de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2013-01-08','Llamada de D.José Tello, sobre venta de finca. Se le comunica que hemos decidido no vender ninguna finca en estos momentos ya que la hermanas Collado no lo necesitan actuyalmnenbt. Llegado el caso, la Comisión contaría con D. José Tello para la opción de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2013-01-08','Llamada de Mª Cielo, T. Social del CRPS de Zafra. Por cuestiones presupuestarias ya no puden hacer visitas domiciliarias. D. José A. no está recibiendo atención psicosocial en este momento porque está pendiente su derivación desde el ESM de Zafra. Acudió a la consulta del 28 de noviembre pero la derivación no ha llegado. Lamar al ESM de Zafra para ver qué pasa con esa derivación, una vez leído el Informe Social que ha enviado Cielo por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2013-01-02','Mariví, T.Soc. del CSS Plasencia. Incidencia de José Mªel pasado 25 de diciembre. Una de las auxiliares lo vió en la calle montando en autobús. Él inicialmente lo negó, pero al final lo reconoció. Además es el que ha traído ...... que ha fumado junto con con otros dos internos, que también han dado positivo. José Mª va a pasar a UME. Al parecer no ha sido la primera vez que dice haber salido del Centro. Se le informa de las consecuencias que le pueda ocasionar si sigue con el mismo comportamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='SERRADILLA'and apellido2='CANO'),'2013-01-09','Se envía respuesta a la petición del Juzgado de 1ª Instancia Nº 4 de Plasencia acerca de la opinión de esta Comisión sobre la remoción del cargo solicitada por su sobrina Dª Raquel Sanromán Serradilla. SE envía por fax dicho informe y por correo ordinario el Informe y documentación adjunta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2013-01-09','Conversación con Rosa, CSS PLasencia. Nos dice que desde CTAEx se autorizó el alta médica (¿?) para que se marchara con su familia (no exite tal documento). Nos enviarán informe de alta y comunicaremos al Juzgado Nº 3 de Plasencia la situación, solicitando autorización para retornar a Vera. Consulta con el nº 4 (quien autorizó el internamiento en el CSS, Nº 674/2012): comunicar al Juzgado nº 3 la situación solicitando en ese mismo documento autorización para retornar a Dª Josefa a "Vera"..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2013-01-09','Rosa (CSS Plasencia).Ayer le dieron alta en UME ("le quitaron el pijama"). A las 21h, tras la cena, deapareció y se le vió en Plasencia a las 22h. Al parecer saltó la valla. Él lo niega, así como también niega el consumo de tóxicos.No obstante, en exploración rectal consentida por él, se descubrió lo que parecía hachís, en pequeña cantidad. Nos enviarán incidencia más informe de médico para ponerlo en conmocimiento del Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2013-01-11','Se modifica la orden semanal de reintrego de 100 euros, pasando a ser de 120 a partir de la semana del 14 de enero (a petición de Mª Ángeles, Pisos Supervisados). Igualmente se autoriza en esta fecha reintegro extraordinario de 90 euros para reparación de gafas (enviarán factura).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2013-01-09','Se envía a la Comisión por fax informe de incidencias de Coral, solicitando valoración de la adecuación de CAMP "Ntra. Sra. de las Cruces" a las circunstancias de nuestra tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA MERCEDES'and edp.apellido1='GONZALEZ'and apellido2='YORK'),'2013-01-10','Se recibe comunicación del Juzgado de 1ª Instancia e Instrucción Nº 1 de Cáceres informando de su inhibición en favor de los juzgados de Plasencia, a raíz del envío del Inventario de Dª Manuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2013-01-10','Nos envía ayer Cédula de Requerimiento del Juzgado de primera Instancia 3 de Amposta (Tarragona: 977-280503 y fax 977-280506), Procedimiento Cuenta del Procurador 826/2012. Se hará trasferencia a la cuenta de Banesto nº: 22562815000008082612. Debido a que se ha pasado el plazo para alegaciones, no es posible impugnar dicho pago. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++También ayer nos envía copia de multa pendiente de pagar. Hablo con Tráfico y debe pagar 800 euros. Se deben pagar por correos o a través del Banco Santander (No es posible por transferencia). (Tráfico: Pedro 060) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Nos enviará recibos pendientes de pago de la Comunidad, de luz y de coche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2013-01-09','Placeat (Tamara, Psicopedagoga. 927-410152, 927-421950) informa de incidencia en las vacaciones de Navidad 2012 con su familia en Nuñomoral del 21 de diciembre al 02 de enero: su madre y una vecina lo volvieron a llevar a casa el día 24 de diciembre porque al parecer, la pareja de la madre amenzó a ésta con irse de casa si Carlos permanecía en ella. VALORAR LOS DÍAS QUE CARLOS PUEDE IR A CASA EN OTROS PERIODOS VACACIONALES E INCLUSO PLANTEAR LA CONVENIENCIA O NO DE QUE PUEDA ACUDIR A ELLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-01-11','Se recibe fax del Juzgado de 1ª Instancia nº 002 de Coria acordando la firmeza del auto 183/12.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2013-01-11','Conversación con OTI, T.Soc. IMSS Badajoz (924-210098). Consiguió contactar con el padre de Dª María, D. Enrique Murillo Carpìo (c/. general Palafox nº 6-1º D) , pero éste le dijo que no sabía nada de su hija "ni quería saber". Estábamos a la espera del fax indicado en la incidencia anterior. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Contacto con IMSS de Cáceres. Isabel, T. Soc. (927-255767). Es Ángélica la compañera que lleva el caso (estará el lunes). Confirma la dirección de la madre, Dª Soledad Delgado Solís y nos da su móvil (658-889091). En Información telefónica nos dan el siguiente fijo (en el que no contestan): 927-246523.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2013-01-29','Tras conversación teléfonica con Iberdrola con el fin de dar de alta la instalación eléctrica de la casa de la tutelada nos comunica que para ello se necesita instalador particular para que realice Boletín ( Certificado de Instalación Eléctrica) junto con el nº de cuenta de doña Carmen. Posteriomente hay que ponerse de nuevo en contacto con Iberdrola. Se realiza gestión para conseguir instalador. El Ayuntamiento nos proporciona un número de teléfono de instalador (Sergio 618025267) y éste está dispuesto a realizarlo. Quedamos con la tutelada nos facilitará la llave del domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-01-04','Contactos sucesivos entre hoy y el 11 de enero con Tesorería de la Junta sobre deudas de D. Gabriel y su cónyuge DªPilar garcía Santos. Contacto: Mª José Remedios, Prado (65497) y Mariano (65382). Con los dos últimos no se ha podido contactar: hay que preguntar si existe alguna posibilidad de condonación de las deudas contráidas por el matrimonio. Mª José lo consultó, indicando que habría que dirigirse a cada organismo deudor para comprobarlo. Se comenta todo el asunto con Yolanda Manzanedo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2013-01-04','Contactos sucesivos entre hoy y el 11 de enero con Tesorería de la Junta sobre deudas de D. Gabriel y su cónyuge DªPilar garcía Santos. Contacto: Mª José Remedios, Prado (65497) y Mariano (65382). Con los dos últimos no se ha podido contactar: hay que preguntar si existe alguna posibilidad de condonación de las deudas contráidas por el matrimonio. Mª José lo consultó, indicando que habría que dirigirse a cada organismo deudor para comprobarlo. Se comenta todo el asunto con Yolanda Manzanedo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTINA'and edp.apellido1='LOPEZ'and apellido2='CASTAÑARES'),'2013-01-15','Se recibe en la CTAEx Providencia del Juzagado de 1ª Instancia e Instrucción Nº1 de Villanueva de la Serena ACEPTANDO la decisión de inhibición del Juzgado de 1ª Instancia e Instrucción Nº 1 de Navalmoral de la Mata.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MAURO'and apellido2='PEREZ'),'2013-01-15','Correo-e enviado por Ana Belén, Directora del CAM, respecto a Dª Isabel Mauro. Debido a que no podemos cambiar sus habitos de vida he intentado mejorarlos, es decir, durante el fin de semana como desde las 13.30 hasta las 21.30 tengo un guardia de seguridad hemos conseguido que respete el horario del centro y que por la tarde en vez de salir a las 14.00 despues de comer como acostumbra ella, salga a las 17.00 gracias a la seguridad puesto que ella si que le tiene respeto a los policias. Ha llegado el lunes y he intentado explicarle que debe respetar las normas incluidas los horarios de entradas y salidas del centro, por tanto se escapo, pusimos la denuncia porque estuvo desaparecida todo el dia y a ultima hora de la tarde me la encontre en la parada de autobuses. Lleva una semana diciendo que cuando cobre el 1 de febrero se va a ver a su hermano a Molina de Aragon y luego a Barcelona','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2012-07-03','Informe Social de Consuelo, T.Soc. SSB: situación estable desde el alta en UME de Mérida. Sin incidentes con su padre ni con vecinos. Cumple tratamiento y reciben el SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2013-01-15','Notifican desde el CSS de Mérida un nuevo ingreso de Dª Mª Luisa en el Servicio de Urgencias del Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2013-01-17','Conversación con Prado (Tesorería Junta: 65497). Gabriel ha terminado de pagar la deuda con Tesorería. Pendiente con OAR (Diputación Cáceres) 8308.97 euros. Desconoce si se puede condonar deuda, pero no se ha hecho en otras ocasiones. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Pilar García Moreno NO tiene deuda ninguna que aparezca en la base de Tesorería. Se le han ingresado en noviembre 3129.36 euros como primer pago de Dependencia, que se han destinado a pagar parte de la deuda con "Adelanta" (pendientes unos 4000 euros). Se le dice a Raquel que debe enviar las facturas al SEPAD. Un segundo pago de Dependencia de 3851.52 euros está pendiente de pago(en fase de autorización).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2013-01-17','Informan de alta en el Hospital a fecha de hoy, 17-01-2013','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='DIESTRO'and apellido2='MORENO'),'2013-01-16','Ingreso en S. Urgencias del Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2013-01-18','LLamada de Mª Teresa, familiar de Daniel: Daniel estuvo con su madre ayer llamando a mi abuela que está ingresada en la residencia, molestándola sin parar. Pide que evitemos esas llamadas y que tengamos en cuenta la Orden de Alejamiento existente entre Daniel y su madre. Llamo a Antonio García de EALEX y me comenta que ayer Daniel no salió: solo sale los lunes y miércoles al taller que hay cerca del piso y cuyo trayecto hace solo. No cree que en ese trayecto haya podido contactar con su madre, entre otras cosas porque ni ha llegado tarde al taller ni ha vuelto al piso fuera de hora tras su participación en aquel. Antonio enviará Informe de lo ocurrido en Navidades durante el permiso concedido a Daniel para pasar el día 25 de diciembre con su abuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2013-01-18','Juan Pedro Martín (Téc. PIA Zafra:924-555480). Propuesta: prestación de 300 euros/mes (pendiente de aceptar por parte de José Antonio). Cuando lo acepte, nos lo comunicarán y tratarán de avisarnos cuando reciban la Resolución de pago retroactivo. Inicialmente, la empresa accede a adelantar el dinero. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ESM de Zafra: hablo con María, T.Social. Hablará con el Dr. Francisco Zamora para, si lo considera oportuno, derivar lo antes posible a José Antonio al CRPS de Zafra. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TERRON'and apellido2='BLANCO'),'2013-01-21','Ingreso en Hospital de Mérida el día 19 de enero y alta del 20 de enero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='FERNANDEZ'and apellido2='VILLANUEVA'),'2013-01-21','Mila Velasco, T.Soc. Centro Salud Mental de Bilbao.(994-007706).Pza. Zumarraga s/n 48006. Bilbao. Centralita 994-001100. Laura Davila Fernández, hija pequeña, le cederían el usufructo de la hermana fallecida, pero necesitan el consentimiento de Dª Juana: poder notarial para ceder el usufructo y aurtorización para que el dinero existente (4800 euros se destinen exclusivamnete al mantenimiento del inmueble (vivienda de protección oficial en propiedad). Enviará copia del testamento para pasarlo nosotros a gabinete','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2013-01-21','Esmeralda, Directora Novaforma (927-629107). El pasado 13 de enero: ¿intento autolítico? Su hermana Josefa informó a la directora de una intervención del 112 el pasado 4 de noviembre de 2012, según parece al estar bebido y armando escándalo en la calle. Tratamos de confirmar dicha intervención llamando a: 112, no hay tal intervención en esa fecha ni en las próximas a ella; C. Salud de Vva. de La Serena, tampoco se envió desde allí ninguna ambulancia; Cía de Ambulancias "La Serena", tampoco hay registrada salida alguna en esa fecha a La Haba. Se comunica resultado de estas averiguaciones a Esmeralda: Felipe en todo momento ha negado la versión de su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2013-01-21','Llamada de Francisco Cuevas (607-714450): su hermano lo ha echado del piso por amenazar a la vecina. Llamo a Francisco: dice que quiere buscar un piso de alquiler, pero le parece bien que hable con su hermano para tratar de arreglar el problema, comprometiéndose a no tratar con la vecina. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a su hermano Antonio, pero no lo localizo (924-840841 y 667-955006).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2013-01-22','Rosa quiere ingresar en Llerena porque se encuentra mal. Miguel considera que puede ser una llamada de atención previa a una nueva explosión conductual y consulta que si vemos bien en CTAEx dicho ingreso. Ellos lo consideran procedente, por lo que nosotros también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2013-01-18','Conversación con la madre de María, Dª Soledad Delgado (927-246523 y 658-889091). Su hija está en Badajoz, trabajando en Telepizza. Se etá preparando las oposiciones a militar. Hasta septiembre estuvo yendo al ESM de Valdepasillas, con el Dr. Samino y la Psicóloga Beatriz López. EL TELÉFONO DE MARÍA ES EL 653-514284. NO LLAMARLA HASTA TENER INFORMACIÓN DE LOS COMPAÑEROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-01-30','En el día de ayer se tomó declaración a Mª Ángeles por el procedimiento el que está incursa por el tema de las estafas. El próximo día 7 de Febrero a las 10:00 horas será examinada por el médico-forense en Badajoz (procedimiento abreviado 0003336/2012). Nos ponemos en contato con el Juzgado de 1ª Instancia Nº 4 de Badajoz para pedir información sobre un cambio de curatela a tutela, ya que pensamos que al agravarse sus problemas de conducta y realizar los actos delictivos citados se cree oportuno cambiar la curatela por una tutela por no considerar la curatela sufiente.Me dicen que el procedimiento a seguir es que el gabinete juríacon un avez se conozcan los resultados del examen forense solicite la tutela. Además en el día de hoy nos llega un comunicado de la Dirección General de Función Pública, RRHH e Inspección, que han dejado en el buzón de quejas y sugerencias, D. Manuel Angel Vaz y D. Juan José Ramírez (vecinos de Mª Ángeles) para quejarse por los robos, la celebración de fiestas nocturnas en su domicilio y las continuas discursiones y peleas con su pareja. Se llevará el seguimiento de los procedimientos judiciales abiertos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2013-01-30','Mª del Carmen se persona en el despacho para informarnos que no va a dejarnos la llave de su domicilio porque quiere ir ella o en su lugar Pedro, se le informa que ella no puede ir sola y que Pedro se encuentra enfermo, decide que esperará a que se incorpore Pedro, a pesar de que no podrá ir a su casa en carnavales por la proximidad de las fiestas. Dice que lo acepta. Nos ponemos en contacto con el instalador para expresarle la situación y avisarle en otro momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2013-01-30','Contactamos con la Trabajadora Social del centro ASINDI que nos comunica que Mª Isabel tiene revisión ginecológica en el mes de febrero, por recomendación del profesional deben hacerle un cambio de método anticonceptivo por motivos de salud, necesitan nuestra autorización, nos enviarán el consentimiento informado junto con el informe favorable de la ginecóloga para autorizarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2013-01-31','Tiene entrada diligencia de ordenación del Juzgado de 1ª Instancia nº 004 pide comunicación de la CTA desde la fecha en que se encuentra el incapacitado en el Centro Residencial "Ntra. Sra. de la Salud" y si actualmente se encuentra residiendo en el mismo. Se le remite oficio informando que José Antonio no está en este centro sino en el Centro Residencial "Ntra. Sra. de las Cruces" en la Avd. Alonso Martín 16 de Don Benito desde el 28/12/2005','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2013-01-30','Se recibe llamada desde el Psiquiátrico Penitenciario preguntando si el informe que se pide desde la CTA desde qué aspectos interesa saber del tutelado. Se le comunica que sobre las cuentes del mismo. También nos informan que se la intentado hacer la Tarjeta Individual Sanitaria de la Junta de Extremadura y se han enterado que carece de cobertura sanitaria. Se pide información a Seguridad Social y se constata que está en situación de alta y que nos remitirán una copia sellada para enviar al Psiquiátrico Penitenciario de Sevilla.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2013-01-30','Se recibe escrito del Administrador de Fincas de los Locales que el tutelado tiene en Valencia para que se pase a recoger las nuevas llaves del acceso a la comunidad a la mayor brevedad posible. Se llama a la empresa que lleva la administración de fincas y nos comunica que para los locales no hace falta puesto que no se tiene acceso a las viviendas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2013-01-30','Se reibe llamada de la TS del Centro para saber si necesitan autorización de la CTA para solicitar CPR de Plasencia. Si lo ha decidido el psiquiátra no hace falta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2013-01-29','Tienen entrada ofico CADEX informando que el grado de discapacidad definitivo es del 65%','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='FRUTOS'and apellido2='DORADO'),'2013-01-31','Contacta con nosotros la t.s. del Hospital Psiquiátrico de Mérida para comunicarnos que Ignacio lleva 3 meses en la UME, se ha recuperado y sólo necesita seguimiento pr parte de salud mental, que debe cambiar de recurso, lo más idóneo en su situación es solicitar plaza en la residencia de mayores Felipe Trigo de Villanueva de la Serena, se tramitará lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-02-01','Se habla con el Fiscal D. Miguel para informarnos sobre la demanda de modificación del alcance de la incapacitación que se quiere llevar hacer y si se puede realizar en breve dado que tiene cita con el Médico -Forense el proximo día 7 de febrero. Don Miguel opina que deberíamos hablar con él para ver si se puede pronunciar más allá de la mera imputabilidad y si no accede deberíamos motivar tal modificación con informes médicos y psicológicos que nos indiquen que la situación ha cambiado desde que se curateló a Mª Angeles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MAURO'and apellido2='PEREZ'),'2013-02-04','Nos comunican desde el centro Las Cruces de Don Benito que Isabel se ha ecapado y se ha ido a Andújar con su familia, su madre y hermana lo han puesto en conocimiento de la Comisaría de la localidad. Se realizará el traslado de nuevo al centro a través de Cruz Roja y la policía le acompañará a su domicilio para recogerla.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-04','Nos comunican desde APROSUBA 10 de Azuaga que Sara ha provocando distintos incendios en el centro con el correspondiente riesgo para ella y el resto de residentes y personal que la atiende. Me pongo en contacto con el Hospital Psiquiátrico de Mérida y me dicen que la lleven a urgencias de Llerena y la ingresen en la Unidad de Agudos, allí valorarán si debe estar allí o derivarla a Mérida. Hablo con Juan (gerente ) y quedamos en que lo pondrá en conocimiento del personal y con lo que decidan nos comentan. A última hora de la mañana, llama Juan y me comunica que el médico de familia les deriva a urgencias de psiquiatría del Hospital de Llerena por tratarse al parecer de un brote psicótico, mañana contactaremos de nuevo par ver evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='ESPINO'and apellido2='ROMAN'),'2013-02-04','Me llaman de Dependencia de Cáceres (Mª Ángeles 927004390) para consultar si solicitan a Dionisia recurso residencial en residencia pública a través de dependencia, ya que, tiene grado y recursos económicos suficientes para ello. Actualmente está residiendo en la Residencia de Mayores Vírgen de Guadalupe de Membrío pero no está acreditado. Se decide que solicite plaza en los cuatro centros más cercanos a su localidad, nos comunicarán la concesión de la plaza para dar el consentimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2013-01-31','Se envía documentación para solicitud de tratamiento psicológico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2013-02-05','Se habla con el juzgado para comunicar que estaremos presentes el día 6 de Febrero para la división de herencia (procedimiento 0000698/2012), ya que, no estamos de acuerdo. Su hermanastro dice que es el único heredero y que Carmen no es hija de su padre. Se solicitará asistencia jurídica gratuita para demostrar la filiación de ésta y la partición de la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2013-02-05','Se recibe llamada de Blanca la TS del Psiquiátrico de Mérida para ir a visitar la casa que tienen en Fuenlabrada de los Montes puesto que quiere vivir en ella. Revisado expediente se observa una casa que está en ruinas. Se llama al SSB para que nos informe sobre este tema. La persona que lleva el catastro no llega hasta dentro de 15 días por lo que decidimos posponer el viaje hasta saber con certeza el domicilio de que dispone.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MAURO'and apellido2='PEREZ'),'2013-02-04','Nos comunican desde el centro Las Cruces de Don Benito que Isabel se ha ecapado y se ha ido a Andújar con su familia, su madre y hermana lo han puesto en conocimiento de la Comisaría de la localidad. Se realizará el traslado de nuevo al centro a través de Cruz Roja y la policía le acompañará a su domicilio para recogerla y devolverla al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-05','Contacto con el diraector de APROSUBA 10 me informa que Sara está ingresada en la Unidad de Psiquiatría del Hospital Infanta Cristina de Badajoz, derivada desde el Hospital de Llerena, ya que, en éste no había plaza, permanecerá ingresada varios dias a la espera de evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CELESTINO'and edp.apellido1='RINA'and apellido2='ALEGRE'),'2013-02-06','La madre de Celestino murio en diciembre de 2012 y se ve posibilidad de pedir pensión de orfandad. Ya se ha intentado en otra ocasión pero se quedó pendiente. Esther TS del centro informa que hay unos familiares que han solicitado la tutela a Fiscalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-06','Contacto con el psiquiatra que está tratando a Sara y me comenta que va ha permanecer ingresada bastante tiempo, está estabilizada pero necesita un tratamiento a largo plazo. Será derivada al Hospital de Llerena cuando tengan cama por pertenecer a este área de salud. Se valorará si posteriormente necesita ingresar en la UME. Se comunica al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MAURO'and apellido2='PEREZ'),'2013-02-05','A travás de Cruz Roja se recoge a Isabel en el domicilio familiar de Andújar acompañados de la Policía Nacional. Se contacta con el centro y nos confirman que ha llegado bien y se encuentra tranquila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2013-02-07','Se tiene conocimiento que el piso está puesto para venta y que no solo es propietario Francisco Javier sino sus dos tíos. Se busca en el expediente el nº de teléfono de la tía con la intención de ponernos en contacto con ella y comunicarle que el señor que quiere arrendarlo también esta dispuesto a comprarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2013-02-07','Tras la solicitud del padre de Iván para que vaya a pasar los fines de semana al domicilio famiiar con él y sus hermanos, se realizan contactos con el centro donde nos informan que Iván está de acuerdo y ellos también lo creen oportuno. pero que no saben cuantos fines de semana al mes. Joaquín me comenta que son todos los fines de semana. Me enviarán desde el centro la autorización y la firmará la CTAex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2013-02-07','Se contacta con el centro (APROSUBA1) para comunicar la citación de Rosa Mª a testificar en el juicio contra Jorge Toro Fernández, les informo que yo le acompañaré como representante de la CTAex y un trabajador por parte del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2013-02-07','El 24/01/2013, estando ingresado en la UME agredió a otro paciente al cuál le causó lesiones (brecha en la cabeza), se emitió un parte de lesiones que se pedirá en caso de que sea necesario. El 04/02/2013 se le echó de menos a la hora de la cena, aunque como ha relatado otro interno que le acompañó se fugaron del centro sobre las 19:00 horas y volvieron a la 1:30 de la madrugada del 05/02/2013. Por este motivo se le ha internado de nuevo en la UME que está más controlado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2013-02-07','Se recibe la tarjeta sanitaria actualizada de Jesús, contacto con la t.s. del Centro Penitenciario de Badajoz quien me dice que próximamente va a ser trasladado a otro centro más idóneo a sus características, por lo que se decide enviarle a ellos una copia y cuando se realice el traslado se enviará al nuevo centro la tarjeta original.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2013-02-08','Contacto con el abogado de Francisco (Pablo)para preguntar si se sbe algo del juicio de la partición de herencia, me comunica que han presentado la dociumentación solicitada por el juez y que están a la espera de la citación, cuando conozcan la fecha nos lo hará saber.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2013-02-11','Hablo con la t.s. del SSB de Plasencia para preguntar por el estado de salud de Francisco tras la intervención quirúrgica de su brazo, quedamos en enviarme toda la documentación de tipo sanitaria que tenga en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2013-02-07','Contacto con un familiar del tutelado (Luis tío y copropietario del inmueble), y me dice que no quiere alquilarlo sino venderlo, le pongo en contacto con la persona interesada (Javier)y se decide que se va a tasar y después se ponfrá el precio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2013-02-15','Se realiza oficio adjuntando toda la documentación que faltaba para solicitud de centro de discapacidad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2013-02-15','Envia la trabajadora social dos presupuestos de servicios Asistenciales a Domicilio y decidimos contratar al más económicos ya que ambos prestan los mismos servicios. La empresa se llama Servicios Asistenciales FESNA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2013-02-13','José Mª quiere conocer a sus tutores y nos pide que quiere salir a comprar ropa. El quiere 20€ a la semana y se le informa que a través de la TS del Centro debe hacer su petición. Nos enseña sus gafas nuevas que ha comprado y manifiesta que aún no las ha pagado. Tiene pendiente un juicio porque se ha pegado con su hermano. Le comunicamos que su madre ha llamado a la Comisión para preguntar por él. Nos reunimos con su psiquiatra, el doctor Sevilla. Informa que no le consiente sus faltas ya que opina que está muy "mimado". Informa que cuando no se sale con la suya la lía y hay que tener cuidado y no darle tanta confianza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2013-02-13','Se realiza visita al Psiquiátrico y José Mª quiere que vernos. Nos manifiesta que quiere recuperar un walkman unos CD de rumbas y una cartuchera de CDs que se dejó en el último centro donde estuvo en el de los Robles en Burgos. Refiere que se ha escapado pero porque necesitaba fumarse un porro ya que tenía estrés pero que voluntariamente vuelve. Su psiquiátra el doctor Herrero nos informa que está sin salidas porque pegó a otro paciente. Padece esquizofrenia paranoide pero ya vino diagnosticado de su último centro, de momento el no ha visto los síntomas. También tiene un retaso mental leve.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2013-02-13','Visitamos el CSS Plasencia para reunirnos con los profesionales que trabajan con Juan. Le comunicamos que existe un auto en el cuál el juez dictamina que debe quedarse en el centro hasta que se resuelvan sus problemas judiciales. Pasará a la Unidad de Larga Estancia que tiene que sufragar los gastos de la misma y no podrá volver en manera inminente a su domicilio. Juan se niega a todo ésto y pide le comuniquemos al juez su propuesta de irse a su casa, amenanzando con quitarse la vida si lo manteníamos ingresado en el centro. Decidimos que aunque no cumple criterios médicos para continuar ingresado en la unidad en la está, seguirá allí para estar más controlado, se toma bien la medición y no da problemas mientras tanto hemos llegado a un acuerdo con Juan para que si cambia de actitud se le dará permiso para pasar un finde semana en su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2013-02-18','Se mantiene conversación telefónica de la Trabajadora Social del SSB pidiendo que hagamos visita a nuestro curatelado porque está muy descontrolado y su madre no entiende porqué la Comisión lleva las cuentas de su hijo. Nos ponemos en contacto con médico de cabecera e informa que no se pone inyección para su esquizofrenia y esto provoca esta situación. Posteriomente en conversación con se Sepad ZAFRA le ha concedido una ayuda para la dependencia de 300 € pero quieren sirva para que un Terapéuta Ocuapacional que trabaje con el, necesitan ver como se articula todo esto. Le paso con Marisa para que gestionen el pago. Posteriormente la TS confirma que sí se lo ha puesto','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-18','Sara continúa ingresada en la UHB del Hospital Infanta Cristina de Badajoz, se encuentra estable pero por criterio médico continuará en esta unidad hasta que el psiquiatra Dr. Guisado (924218100)considere que se encuentra bien. Desde el centro le han relatado todos los hechos ocurridos y la conducta de Sara por lo que se prevee que la mantendrá ingresadaun tiempo. Se autoriza a la sección de acceso a recursos (Manuela) para pedir un cambio de perfil al CADEX. motivando la imposibilidad del centro para atender las necesidades de Sara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2013-02-12','Mantenemos una reunión en APROSUNA 8 Montijo con Sara y los profesionales que trbajan con ella para tratar el tema de su deseo de vivir de manera independiente con su paraja Miguel Ángel. Ella misma pide supervisión por parte del centro y si se independiza perderá la plaza en el piso tutelado. Llegamos al acuerdo de que el centro dispone de dos plazas en piso sin ocupar por lo que Miguel Ángel puede solicitar plaza y vivir con Sara en un anexo del piso. Lo comentamos con Manuela y accede, se comunica al centro el cuál hablará con la fmailia de Miguel Ángel para pedir su consentimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='FRUTOS'and apellido2='DORADO'),'2013-02-18','Solicitada plaza en Felipe Trigo de Villanueva de la Serena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2013-02-15','Asistencia al juicio: Procedimiento 733/2012, contra Jorge Toro Fernández, por abusar, maltratar, amenazar, prostituir, ect. a varios usuarios/as del centro, Rosa, nuestra tutelada, testificó, ya que, en alguna ocasión había presenciado estos hechos que se han repetido durante aproximadamente 2 años. Estuvo acompañada por la trabajadora social de la CTAex, la directora y el psicólogo de APROSUBA 1 y unos profesionales de la Fundación Carmen Pardo- Valcarce de Madrid, de la Unidad de Ateción a Víctimas con Discapacidad Intelectual, los cuales llevan su defensa. Además también estuvo presente el padre de Rosa. Se mostro algo nerviosa pero cuando salió comentó que había relatado los hechos como habían sucedido, al igual que los otros tres usuarios del centro que declaraban el mismo día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIO'and edp.apellido1='CARRETERO'and apellido2='HERNANDEZ'),'2013-02-19','Se tramita el ingreso en centro de personas con discapacidad, ingresará mañana día 20 de febrero en el Centro: Asociación Mensajeros de la Paz de Nuñomoral, se realizará el traslado por Cruz Roja, irá acompañado de personal de Novaforma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-20','Solicitada PF ya reconocida a su nombre pero que debe estar a nombre de la CTAEX para lo cuál, se ha enviado una solicitud para situaciones especiales y adjuntado la documentación pertinente. Con repecto a la Orfandad se manda un escrito para cambiar la titularidad y nº de cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CAYERO'and apellido2='AGUILAR'),'2013-02-20','Solicitada un cambio de cuenta bancaria en su pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2013-02-18','Rosa es ingresada en la Unidad de Agudos del Hospital de Llerena por prescripción del psiquiatra de guardia por una crisis en el centro y agravamiento de sus problemas de conducta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2013-02-20','Contacta conmigo Miguel (APROSUBA 1) para informarnos que han visitado en el hospital a Rosa, la médico-forense y la juez de Llerena y han decidido dar el alta de manera inminente por no cumplir criterios médico para cntinuar en Agudos, necesita un recurso específico, a pesar de la negativa de la psiquiatra. Contactamos con ella y también con el juzgado. Se solicitará un cambio de perfil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2013-02-20','Me llama Mª Eugenia dEL css DE Mérida, la médico somática pregunta que el tutelado tiene un cáncer y necesita un intervención quirúrgica. Se envia el consentimiento informado y el informe del psiquiatra informando que José Mª no tiene poder de decisión, ya que él se niega a ser intervenido. Se envía todo al Hospital Infanta Cristina de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FRAILE'and apellido2='EXPOSITO'),'2013-02-11','Se le otorga plaza en el Centro La Providencia en Ribera del Fresno, se realizará el traslado próximamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2013-02-21','El juzgado autoriza el ingreso de Rosa en la Unidd de Agudos del Hospital de Llerena, según criterio de la psiquiatra la mantendrá unos días, posiblemente hasta la semana que viene para estabilizarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2013-02-21','Me comunica el psiquiatra que en breve dará el alta a Juan por no cumplir criterios médicos para mantenerlo de manera no voluntaria en la unidad eun la está. Quedamos en que desde el centro se encargarán de que cuando llegue a su casa se le controle el tema sanirario por parte del centro de salud y nosotros nos encargamos de contactar con SSB, conocidos y familiares y haremos un visita para ver en qué condiciones ee encuentra la vivienda de Juan. Halamos con él tanto el psiquiatra como y yo para explicarle claramente que si comprobamos que las condiciones son las idóneas se irá a su casa pero que si se ve envuelto en algún problema grave que se pedirá al juez un internamiento involuntario, que debe tomarse la medicación y tener una conducta correcta, que comprobaremos con las visitas de seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2013-02-22','Contacto con Dolores (amiga de la familia, tfno. 625030078), quién me verifica que está de acuerdo en que Eulalia la visite los sábados alternos. Se autorizará al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GALLEGO'and apellido2='CALDERON'),'2013-02-22','María es propietaria de una casa en Monesterio que tenía alquilada,, a fecha 31 de enero, los inquilinos han dejado la vivenda, han pagado todo y las llaves las tiene la inmobiliaria. Contacto con la inmobiliaria Fincasurex ( José tfno. 924516452), nos mantendrá informado de las gestiones que se realicen con un nuevo alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL GONZALO'and edp.apellido1='MORENO'and apellido2='GOMEZ'),'2013-02-21','Ha llamado Salud, la novia de Ángel, para saber si vamos a ir o no al Ayuntamiento de Santa Olalla porque Pedro había quedado con ella y con Ángel y una abogada. Salud cuenta que cree que Ángel tenía muchos problemas con la Guardia Civil porque se ponía muy nervioso cuando los veía y que semanas atrás los detuvieron en el punto cero de Sevillapor unos cheques falsos de Ángel (a ella también como cómplice) por valor de 3600 € aproximadamente. Él lo negó y decía que el dinero se lo enviaba Pedro. Para ponernos en contacto con ella, llamar al Ayuntamiento de Santa Olalla de Cala al teléfono de la Trabajadora Social Sara 959 190 175. Ext 3','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-25','Me llama el Dr.Guisado (psiquiatra Unidad de Agudos de Badajoz), para comunicarme que Sara será dada de alta en el día de hoy, por estar estable y con una conducta normal, me envía informe de alta. Contacto con Beatriz para decírselo y para que comunique a Manuela la incorparación a su plaza en ARPSUBA 10.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2013-02-25','Me comunica Miguel (psicólogo) que van a darle el alta a Rosa en el día de hoy, que se encuentra estabilizada pero muy triste.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2013-02-25','Se tiene conocimiento de que Josefa está residiendo con su hermano y el Centro Vera nos indica que aún mantienen la plaza. El SEPAD necesita conocer su domicilio actual para valorarla. Se realizará el miércoles 04/03/2013 visita a la unidad familiar del hermano en Valdeobispo para valorar la permanencia de Josefa en su entorno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2013-02-25','Se tiene conversación con Toñi, del Instituto de Medicina Legal, 924286802 poruqe le han pedido que valoren la situación de violencia hacia su madre. La madre no se ha personado en las dos citaciones (10/12/12 y 18/2/13)pues la progenitora no está en condiciones de trasladarse. La violencia del hijo a la madre existe, la insulta, la empuja, pequeñas agresiones, modos despreciativos... tienen ambos una relación disfuncional. El aparte de la inyeccción tiene más medicación que no está tomando y el resultado es una situación explosiva. Por otro lado quieren estar juntos. La CTA tiene responsabilidad en el tema sanitario por lo que decidimos visitar en breve la situación. Ver la posibilidad de con el Terapéuta Ocupacional de Dependencia pueda controlar medicación y quedarse en el medio, sino fuera así proponer Centro. Quedamos con Toñi que informaríamos de los resultados de la visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-04','Me llama el director de APROSUBA 10 de Azuaga y me comunica en los últimos meses Sara ha propiciado varios incendios en el centro, con el correspondiente peligro para su integridad física y la dcel resto de residentes y personal del mismo. Al tratarse de hechos tan graves, decidimos que la lleven a urgencias de psiquiatría del Hopital de Llerena, donde le ponen todo tipo de obstáculos para ingresar a Sara. La derivan a la Unidad de Agudos del Hospital Infanta Cristina de Badajoz (Dr. Guisado tfno. 924218100) donde queda ingresada. Mantengo varios contactos telefónicos con el psiquiatra y quién me asegura que no va a darle el alta a Sara hasta que se encuentre estabilizada y apta para volver a su centro pero que al no pertenecer a su área de salud tendrá que pedir la derivación a Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-25','Me llama el Dr. Guisado para informarme que ante la negativa del Hospital de Llerena para ingresarla, va a drle el alta en el día de hoy puesto que Sara se encuentra recuperada, con un nuevo tratamiento y ajustada la medicación y que posiblemente al tener una conducta ejemplar en el hospital puede que el problema de base sea la mala relación que tiene con otro residente. Se trasladará a APROSUBA 10 cuando tengan libre una ambuancia para el traslado. Lo comunico al centro (Beatriz) y acordamos que se vigilará el contacto de Sara con su compañero. Mientras tanto se está tramitando la solicitud de cambio de perfil para buscar un centro que se adapte a su patología. Me llama el Dr.Guisado (psiquiatra Unidad de Agudos de Badajoz), para comunicarme que Sara será dada de alta en el día de hoy, por estar estable y con una conducta normal, me envía informe de alta. Contacto con Beatriz para decírselo y para que comunique a Manuela la incorparación a su plaza en ARPSUBA 10.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-20','Conversación telefónica con Esther la hermana de Sara se muestra muy preocupada por el estado de salud de su hermana y la posibilidad de trasladarla a otro centro más alejado de su localidad, por el incoveniente de ir a visitarla. Ella quiere que se quede en este centro para seguir visitándola y llevarla a su casa en vacaciones y otros permisos. Cree que Sara tiene estos episodios para llamar la atención y así conseguir que Esther se la lleve a su casa. La ha visitado en el hospital y le ha convencido de que debe quedarse en el centro y mantener una conducta adecuada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2013-02-26','A la vista del informe del Psiquiatra de darle el alta en la UME, se habla con la Directora del CSS para su traslado a la ULE por considerar, en base al mismo informe, que "persisten interpretaciones e ideas delirantes" y no es posible acceder a su deseo de ir a casa. Sin embargo, como el paciente ha manifestado que si se le traslada a la ULE, él se suicidaría, la Directora del centro estima conveniente mantenerle un poco más en la UME y tratar de convencerle de su traslado a la ULE. Se recaba información sobre la situación sanitaria y social de los profesionales del CSS, contactos con la hermana de Juan, SSB de Guadalupe y un escrito de la CTAEx con toda la información relativa al tutelado, por si el juzgado en un futuro nos la demanda como justificación de nuestra decisión de mantenerle ingresado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ORTEGA'and apellido2='SEVILLA'),'2013-03-05','David tiene una deuda con Planeta Directo por importe de 1324 €, hemos recibido requerimiento del Juzgado Nº 3 de Badajoz. Habría que ingresar el dinero en la cuenta a nombre de Asesoría de Cobro y Gestión, S.L. Teléfono: 934092185 Fax: 934092186 0030 2210 50 0002278271 NO LO HEMOS PAGADO PORQUE DAVID NO TIENE SUFICIENTE DINERO EN CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-02-27','Me llama Juan, director de APROSUBA 10 y me comunica que Sara ha vuelto a provocar un incendio, esta vez, más grave que los anteriores, ha quemado toda su habitación con ella dentro, afortunadamente no ha habido daños personales pero muchos materiales. La guardia civil ha registrado todo el centro para encontrar el mechero con el que supuestamente ha prendido fuego y tomar declaración al personal y residentes afectados. La llevan al COPF para que le hagan una exploración por si lo tiene escondido en la vagina. La médico de familia la deriva a urgencias del hospital de Llerena donde la ingresan en el UHB durante unos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-03-06','Contacto con el psiquiatra de Sara, Dr. Chaudri, me dice que Sara se encuentra estable, no presenta problemática alguna en la unidad pero cuando vuelva al centro lo intentará de nuevo, por su rechazo hacia éste, por eso cree que es un caso muy gravey que debe derivarle al CSS Mérida a la Unidad de Rehabilitación, ya que para UME no cumple criterios médicos. Hablamos con Coro (Directora del CSS) para que la ingrese de manera temporal y la traten hasta que se le asigne plaza en otro recurso más adecuado a su situación. Enviamos la documentación por fax para valorar la situación y decidir. Se lo comunico al psiquiatra y acordamos Sara se mantendrá ingresada hasta que nos conteste el CSS. Además el día 8 haremos una visita a Sara en el hospital y nos reuniremos con él.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-03-06','Contacto con el psiquiatra Dr. Chaudri para preguntar por Sara, me dice que se encuentra estable y no presenta problemas de conducta, tiene un comportamiento ejemplar, pero que cuando vuelva al centro es muy probable que vuelva a intentarlo por el gran rechazo que tiene al centro. Es un caso muy grave y que cree necesario derivarla al CSS Mérida a la URH ya que para la UME no cumple criterios médicos. Contactamos con Coro (directora del CSS Mérida), le pedimos que ingrese a Sara temporalmente para tratar sus trastornos de conducta y mientras tanto se le signa plaza en otro centro más adecuado a su situación. Me dice que mandemos la documentación y se valorará, remitimos por fax todos los informes médicos y sanitarios, CADEX,etc. y esperamos respuesta. Acordamos con el Dr. Chaudri que Sara continuará allí hasta que tengamos una respuesta del CSS. Además haremos una visita a Sara en el hospital y nos reuniremos con él el día 8 de marzo,para tratar el caso, (Lola y Dora). Después nos reuniremos con los profesionales de APROSUBA 10.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2013-02-27','Se solicita justicia gratuita para Carmen en los dos procedimientos abiertos: herencia y filiación.Se envía la documentación al Colegio de Abogados de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='MORCILLO'and apellido2='PAJUELO'),'2013-03-06','Solicitada PF por cambio de titularidad y cuenta bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FRAILE'and apellido2='EXPOSITO'),'2013-03-04','Francisca es trasladada al Centro La Providencia de Ribera del Fresno, se realiza a través de un taxis, se tramita la documentación de solicitud de baja en las cruces y se pasa a Manuela, una vez firmado también se enviará a Magdalena (t.s. de Las Cruces).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2013-03-07','Se solicita al INSS revisión de la pensión de orfandad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2013-03-07','Se solicita al INSS revisión de pensión de orfandad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIANO'and edp.apellido1='MARTINEZ'and apellido2='GONZALEZ'),'2013-03-05','La Directora de la Residencia nos comunica que Mariano se ha caído y ha sido ingresado en el Hospital de Don Benito, en la habitación 310.1. Ella también avisará a su hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2013-03-07','Se mantiene conversación con el Equipo de Dependencia del SEPAD de Plasencia. Han realizado visita pero no observan dependencia alguna. El domicilio está limpio y a Josefa no se le observa que no pueda realizar abvd. Se realizan gestiones para obtener información a través del SSB y el Consultorio Médico. Teresa la médico del CM manifiesta que ella misma acudió a por recetas y no sabe cuando tiene citas con ESM pero estarán pendientes. Por otro lado refiere que la conoce hace mucho y se lleva bien con ella. Se coordinará con la CTA. Puerto TS del SSB no la conoce pero se coordinará con la médico y estará atenta por si sucede alñg´n acontecimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-03-05','Mediante correo electrónico, FUTUEX comunica que "Almudena no se presentó a la cita programada para el viernes 15 de febrero, en Salud Mental.No tiene móvil, no se encuentra en casa cuando se le ha ido a ver, lo que hace realmente dificil localizarla.La gente de la localidad suele verla paseando con su actual pareja(también con dificultades sociales y deficits intelectuales o mentales), una de las causas que había hecho que la situación de Almudena en los últimos meses se agravara". Con el fin de conseguir localizarla, FUTUEX recomienda interrumpir temporalmente la asignación económica y así se hace. También sugiere enviar el caso a los SSB ya que no se contará con el apoyo de los Deleg. de Apoyo por reducción presupuestaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2013-03-07','Se habla con teresa, médico del Consultorio Local de Valdeobispo, refiere que esta paciente ha estado en su consulta a petición de la misma para pedir recetas para su tratamiento. en principio no se las prescribió porque no llevaba informe pero le facilitó informe del ESM y ya ha estado en cuatro ocasiones para recetas. La observa bien y tiene buena relación con ella. Quedamos en coordinarnos y si observa algo nos avisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='POBLADOR'and apellido2='FERNANDEZ'),'2013-03-07','Me comunican desde el centro de APROSUBA 10 de Azuaga, Beatriz y me dice que ha fallecido el padre de Tomás, que se encuentra muy afectado y que su deseo es asistir al funeral y acompañar a su madre y hermana. Le acompañará personalñ del centro, con su propio trasporte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-03-07','Me pongo en contacto con el Juzgado de Instruciión nº 4 de Badajoz donde me informan que la tutelada no ha asistido a la citación para el examen-forense del día 7 de Febrero de 2013. La no comparecencia se ha trasladado a la jueza quien tomará la decisión oportuna y nos lo notificarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2013-03-11','Móvil de Vanesa 642303835. Llama el Trabajador Social y comenta que está en el pueblo, pero sólo durante unos meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-03-08','Mantenemos una reunión con el psiquitra que atiende a Sara en la UHB del Hospital de Llerena (Dr. Chaudri tfnos.: 924877037/645860755)nos explica que la tutelada está totalmente estable, no presenta ningún trastorno de conducta, su comportamiento es ejemplar y no tiene diagnosticada una patología psiquiátrica clara. Ante el peligro de volver a su centro y como en breve va a dar el alta realiza una derivación a la URH del CSS de Mérida, por no cunplir criterios médicos para UME. Desde la CTAEx se envía toda la documentación al CSS para valoración. Hablamos con Sara, la cuál, nos explica que no sabe por qué lo hace, que el mechero se lo proporcionó un compañero del centro, pero muestra su deseo de volver a Aprosuba 10, que no quiere ir a otro centro. Visitamos APROSUBA 10 de Azuaga donde los profesionales nos muestran las instalaciones y recursos con los que cuentan en el centro, totalmente insuficientes para prestar a Sara el control y supèrvisión que necesita. Entramos en la habitación de la tutelada comprobando los enormes daños materiales que tiene tras el último incendio. Esperaremos la valoración del CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-03-11','Visitamos el CSS de Mérida para tratar el caso de Iganacio Frutos Dorado, lleva algún tiempo en el centro y la psiquiatra considera que se encuenta estabilizado, sin problemas de conducta y aceptando todas las normas, participando en la terapias... por lo que, debe dar el alta al paciente que no puede vovlver a casa por las ínfimas condiciones en las que se encuentra y se le solicita un ingreso en residencia de mayores (Felipe Trigo) que al estar en su localidad y tratarse de un centro abierto, puede ir a su casa siempre que lo desee. Aunque su deseo es volver a su casa, acepta la opción como algo temporal.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2013-03-12','Se mantien conversación telefónica con el Doctor Zamora del ESM de Zafra. No se ha presentado Jose Antonio a la cita de ayer. El doctor Zamora refiere que a las ultimas tres citas del pasado año no ha faltado pero antes de éstas había faltado en muchas ocasiones. El tratamiento pautado es Neurontin 600 una por la mañana y otra por la noche pero la inyección se la quitó por su cuenta porque refería que le sentaba muy mal. Manifiesta que no tiene un diagnóstico de psicótico ni esquizoide sino de un trastorno de la personalidad por lo que la inyección no le hace mucho, lo calma un poco pero a nivel farmacológico no hay mucho que hacer. Ningún recurso, ni el Hospital Infanta cuando ha estado ingresado refiere que padezca enfermedad mental, coincide en trastorno de la personalidad. Cree que es un problemas más social que médico por las cirunstancias familiares. Opina que un tratamiento psicológico hubiera hecho algo pero no ya a estas alturas. Se establecerá otra cita para Salud Mental que me informarán de la fecha. También manifiesta que hace 15 días tuvo reunión con CRPS y tienen entendido que van a visitar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2013-03-12','Se mantiene conversación telefónica con Manuela, TS del SSB para comunicarme que no ha asistido Jose Antonio a la cita del ESM del día 11. La madre de Jose Antonio se presentó en su despacho para comunicarselo alegando que hacía muy mal tiempo para viajar. Quedamos que nos avisemos si nos enteramos de la nueva cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-03-12','Asistimos al Juzgado de Instrucción Nº 1 con la tutelada al juicio de faltas, procedimiento nº 268 .........., no se celebró por no habernos asignado un abogado de oficio. Lo solicitamos en ese mismo día y nos mandarán la próxima citación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-03-14','Acompaño a Mª Ángeles (t.s. Dora), a declarar a la policía judicial grupo II (Silvia) por el procedimiento... abierto contra ella por estafas. Lo niega todo y manifiesta que no sabe de qué le está hablando. Además acusa a su compañero de piso de utilizar su e-mail para hacer las compras. Se investigará y nos notificarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2013-03-18','El pasado jueves entra en la CTA escrito de Juzgado no permitiendo el ingreso involuntario en Centro. Dado que Hermenegildo ha estado llamando a la CTA llorando porque quería ingresar en Centro se le dice a Ageda TS, que realice escrito manifestando su voluntad de ingresar y que lo firme. Ya se tenía toda la docuemntación que se requiere para su ingreso cuando se recibe llamada telefónica de la Trabajadora Social de la localidad manifestando que esta mañana se ha personado el tutelado y refiere que se ha ido desde el día 15 a casa de su madre, que esta le ha persdonado y que está muy contenta con ella. Ante esta situación se queda con Ageda que si vuelve a pedir centro lo firme por escrito. Se paraliza las gestiones pertinentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2013-03-13','Hablo con Nati jefa de sección de dependencia de Zafra, me comenta que se lo pasará a la técnico PIA correspondiente para resolverlo y nos avisarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2013-03-19','Se realizará una visita a la vivenda de Carmen el próximo 26 de marzo de 2013 para ver las condiciones en las que se encuentra, iremos las trabajadora sociales de la CTAEx, el aparejador municipal, la policía local, la t.s. del SSB y el instalador eléctrico. Aparejador (Martín, tfno.: 619710212.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2013-03-20','Recibimos resolución de inclusión en lista de espera de CO encontrándose según puntuación obtenida el nº 11, aunque es usuario de RAL, que se derivó en su día a través de menores y ahora cumple los 21 años y hay que asignarle recurso, aunque hasta la nueva resolución continuará en su plaza de residencia y esperaremos a que se le adjudique plaza en CO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2013-03-21','Se mantiene contacto telefónico con Carlos TS IMAS Cáceres. La situación no la ve mal, no le pueden embargar la casa porque es alquilada, no tienen que tener problemas económicos porque el padre cobra 663€ de pensión y está en Centro de Día hasta las 5, padece alzaimer. La madre cobra PNC y actualmente esta muy bien, sale todas las tardes con su amiga, esta controlada medicamente y el opina que esta en estos momentos capaza para realizar la tareas domésticas. El hijo ha pedido vivienda social porque de cara a cuando el resida solo no va a poder mantener alquiler, pero no la quiere en las zonas "marginales" de Aldea Moret y la que estan en la otra zona son para emergencia y urgente necesidad, cosa que no está él en estos momentos. Tiene AD del SEPAD y también del Ayuntamiento pero ha salido una ordenanza nueva y van a tener que elegir. El Ayuntamiento puede asignarle más horas si es necesario en el caso que opte por la del municipio. Carlos no sabe darme datos de qué está embargado. Se piden datos al SEPAD para conocer las ayudas que tienen: -Pilar tien una prestación vinculada al servicio de 21 a 30 horas al mes por la que le pagan 361,08 € al mes -Gabriel tiene una prestación vinculada al servicio de 30 horas al mes de 562,92 € al mes Gabriel tiene retenido enero y febrero yla deuda que tiene se la está cobrando por lo que no la percibe. De Pilar parece que la cobra y no loa tiene retenida. La deuda es de 24.246 €, tiene pagado 5.559 y le queda 19.329€. Pot otro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CELESTINO'and edp.apellido1='RINA'and apellido2='ALEGRE'),'2013-03-27','Denegada Pensión de Orfandad. En trámite remociónde la tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-03-27','Cambio de titularidad y cuenta bancaria de la PF. Se irá de unos días con su hermana a Jerez de los Caballeros. Además se envía autorizacón firmada para pedir la historia clínica a Salud Mental de Jerez y trasladarla al ESM de Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2013-03-26','Se realiza visita a la localidad de Valdecaballeros donde tiene la casa doña Carmen. En el Ayuntamiento se había citado previamente a la Trabajadora Social, Trini; el Aparejador, Martín y el electricista Sergio. Carmen pide constantemente ir a pasar temporadas a su casa pero esta no reúne condiciones puesto que ni tiene luz. Su deseo es que se haga lo necesario en la vivienda, motivo por lo que nos personamos en la misma con el objetivo de ver que reformas hay que hacer. La vivienda presenta mal estado nada más entrar porque al fondo se divisa que no hay escaleras y hay un derrumbe por el que se ve el cielo y cae agua ya que esta en esos momentos lloviendo. La vivienda consta de salita y dos cuartos, uno de ellos sin ventilación. Al fondo, lo que se supone fue una escalera, ya que está destruida, para acceder al piso de arriba, que no se pudo comprobar ya que carecía de acceso. Carece de un espacio para cocina pero si tiene una cocina en la salita, así como una lavadora. Tampoco hay un baño tan solo una taza de WC que está medio suelta en un rincón. La vivienda está sucia y hay ropas por el suelo y a simple vista no reúne condiciones higiénico sanitarias. El aparejador nos indica que le pidamos informe para que nos remita lo que ha visto sobre la casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='ESPINO'and apellido2='ROMAN'),'2013-04-01','Dionisia será trasladada con el servicio de Cruz Roja el próximo día 03 de Abril de la Residencia "Vírgen de Guadalupe" de Membrío a la Residencia Geriátrica Municipal de Madroñera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CARDENAS'and apellido2='CARMONA'),'2013-04-01','Se recibe llamada del CSS Mérida informándo que Mª Carmen la han trasladado al Hospital por un golpe en el ojo. Al final de la mañana informan que ya está en el Centro y no ha sido caso de hospitalización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FRAILE'and apellido2='EXPOSITO'),'2013-04-02','Enviado PIA firmado a Mª José Muñoz, técnico PIA de Vva. de la Serena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-04-04','Cita en el CADEX Badajoz para el cambio de perfil solicitado y solicitud de revisión del grado por agravamiento, le acompañará la psicóloga del centro Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2013-04-03','Se tiene conocimiento a través de la Jefa de Servicio de Protección de Menores de Cáceres (MARA)que atendió casualmente a un señor que estaba por los pasillos y era Ventura. En nuestros archivos teníamos una guarda judicial pero nos ponemos en contacto con el juzgado y nos indican que hay mucha documentación sobre el caso y nos la remitirán en la medida de lo posible. Estudiando el Auto del Juez este acuerda (pues pervisiblemente adoptará cargo tutelar) que la CTA procede acordar como medida cautelar la intervención de las facultades patrimoniales del demandado, de tal forama que la CTA podrá actual como cualquier CURADOR, en tanto en cuanto se sustancia el procedimiento. También llega una comparecencia del abogado Aparicio Jabón en nombre y representación de Ventura que se opone íntegramente a la demanda argumentando los motivos de la misma. Por otra parte Mara llama a la CTA manifestando su premura para que actuemos ante la situación de desprotección de Ventura a lo que le exponemos los hechos que el procedimiento esta lento por la intervención de este abogado a lo que ella opina que este abogado lo único que quiere es sacar dinero. El hijo de su pareja (Mª Angeles)tiene 17 años, esta en situación de guarda judicial provisional en el Centro de Menores "Francisco Pizarro" DE Trujillo ya que Mª Angeles está en la cárcel por un delito de estafa. Mara comunica que toda esta situación nos la va hacer llegar por escrito. Seguidamente nos ponemos en contacto con la TS del IMAS que lleva el caso, Mª Bel la cual nos comunica que el señor Aparicio es el abogado de Mª Angeles y que esta es una estafadora y que no solo lo está haciendo con Ventura sino también con un señor de Guijo de Granadilla llamado Francisco que tiene una sociedad con sus hermanos y ella intenta entrar en la misma, pero en este caso los hermanos se dieron cuenta. Tiene a ambos "engatusados" y los dos son del mismo perfil, de hecho en los bis a bis comunica con él todos los domingos. Entre los dos le pagan al abogado de Mª Angeles para que esta salga de la cárcel. Ventura se casó con Josefina Baltasar Rivas, vendedora de la ONCE y propietaria de varios inmuebles y vendieron una piso que tenían en la Mejostilla poniendo ese dinero a plazo fijo, también tienen Plan de PEnsiones ...y falleció el 15 de diciembre de 2011. Posteriormente en julio de 2012 conoce a MºAngeles y en agosto se va a vivir junto a su hijo con Ventura pagándole 600€ mes en calidad de cuidadora y ya al mes siguiente hace testamento a favor de Jesús , hijo de Mª Angeles. Vestura dio a Mª Angeles un poder notarial para sacar dinero de la cuenta y en una ocasión fue a por dinero y al Director de la entidad le extraño y no se la dio finalmente fue con el pero las cantidades que sacan son de alrededor de 7000€. El menor alardea en el Centro de MEnores de que él dispone en una cuenta que tiene 20.000€, lleva un tran de vida impropio, cuenta con Play Satation de ultima generación,WII, juegos, móvil con internet,motos teledirigidas compradas en internet...y es propietario de una moto con la que recientemente ha tenido un accidente. Desde el punto de vista de Mª Bel lo que está haciendo con él es un auténtico expolio pero él no es conciente de ello su única preocupación es sacar a "su mujer"Mª Angeles de la cárcel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2013-04-08','El Dtor del CRR nos comunica que Antonio ha sido ingresado en el Hospital este fin de semana porque se ha desestabilizado. Al llamar al Hospital, hemos hablado con la Psiquiatra que le atiende y responsable de la Unidad de Psiquiatría y nos comenta que es la tercera vez que ingresa(las otras dos ocasiones en junio y octubre del 2012). Se encuentra descompensado y desconfiado. Necesita que se le reajuste la medicación y, al igual que en las anteriores ocasiones, será cuestión de diez o quince días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIANO'and edp.apellido1='MARTINEZ'and apellido2='GONZALEZ'),'2013-04-08','Se llama a la Residencia S. Francisco para conocer la evolución de Mariano y la Trabajadora Social nos comunica que le dieron el alta en 20 días y con la ayuda de la Fisio ha recuperado el andar. Está muy bien y ha servido su estancia hospitalaria para fumar mucho menos. Su hermano fue varias veces al hospital y sigue haciéndolo a la Residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2013-04-08','Tras la reunión mantenida con los profesionales del CAM, centro en el que se encuentra Minerva, llegamos al acuerdo de que la tutelada debe continuar en el centro hasta los 21 años fecha en la que su hermano cumplirá los 18, se enviará solicitud a la Dirección General de Política Social y Familia pidiéndolo. Minerva está valorada por Dependencia del Julio de 2012 con un Grado I, Nivel 2.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2012-04-10','Solicitada Orfandad y PF ya que la cuantía es mayor que la PNC que cobra actualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2013-04-10','12.15horas: El Director del CRR nos comunican el alta hospitalaria y que van a ir a buscarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2013-04-09','Técnicos de la CTA se personan en la localidad de Guadalupe para conocer el estado de las propiedades de las hermanas Collado Esteban. En el Ayuntamiento esperan la Trabajadora Social, el aparejador y el policía local que nos acompañan. En primer lugar se visita la casa que sita en la Plaza de los Tres Chorros nº 23 y 24 que se observa en la fachada grave deterioro tanto en una de las columnas que se ve bastante agrietada como el la parte lateral de la misma que presenta ahuecamiento con riesgo de desprendimiento. En la visita la gente de la localidad nos hace observaciones de que es un peligro pasar por la calle y no se puede poner vallas porque es demasiado estrecha y es calle de paso a dicha plaza. Por dentro la casa se observa muy deteriorada en paredes, suelos, muros. El olor que desprende es insoportable. Hay bastante alarma social en la zona con la visita porque todo el mundo entiende que es un peligro pasar por la calle por culpa de la fachada lateral de la casa. Hay una vecina que tiene una habitación que le “pisa” la casa de la tutelada y abre la puerta para que observemos el estado lamentable que presenta el techo, por el que se filtra todo el agua de lluvia. La señora expresa que espera que esta vez se haga algo porque hace tres años ya vinieron los de la CTA y aún están igual. También hay una cuadra en la que se ha venido abajo el tejado por lo que está entrando agua cuando llueve. La propiedad que tiene otra de las hermanas en la calle del Tinte nº 5, presenta un balcón visiblemente deteriorado con riesgo que se venga abajo. Al entrar tanto el suelo como las paredes están muy deterioradas así como las vigas de madera del techo que tienen aspecto de estar podridas. Tanto en el piso de arriba como el de abajo, hay mal olor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2013-04-09','Técnicos de la CTA se personan en la localidad de Guadalupe para conocer el estado de las propiedades de las hermanas Collado Esteban. En el Ayuntamiento esperan la Trabajadora Social, el aparejador y el policía local que nos acompañan. En primer lugar se visita la casa que sita en la Plaza de los Tres Chorros nº 23 y 24 que se observa en la fachada grave deterioro tanto en una de las columnas que se ve bastante agrietada como el la parte lateral de la misma que presenta ahuecamiento con riesgo de desprendimiento. En la visita la gente de la localidad nos hace observaciones de que es un peligro pasar por la calle y no se puede poner vallas porque es demasiado estrecha y es calle de paso a dicha plaza. Por dentro la casa se observa muy deteriorada en paredes, suelos, muros. El olor que desprende es insoportable. Hay bastante alarma social en la zona con la visita porque todo el mundo entiende que es un peligro pasar por la calle por culpa de la fachada lateral de la casa. Hay una vecina que tiene una habitación que le “pisa” la casa de la tutelada y abre la puerta para que observemos el estado lamentable que presenta el techo, por el que se filtra todo el agua de lluvia. La señora expresa que espera que esta vez se haga algo porque hace tres años ya vinieron los de la CTA y aún están igual. También hay una cuadra en la que se ha venido abajo el tejado por lo que está entrando agua cuando llueve. La propiedad que tiene otra de las hermanas en la calle del Tinte nº 5, presenta un balcón visiblemente deteriorado con riesgo que se venga abajo. Al entrar tanto el suelo como las paredes están muy deterioradas así como las vigas de madera del techo que tienen aspecto de estar podridas. Tanto en el piso de arriba como el de abajo, hay mal olor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2013-04-11','Solicitado traslado de expediente del CADEX de Badajoz al CADEX de Cáceres por residir en ASINDI (Alcántara).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-04-12','Reunión de las trabajadoras sociales de la CTAEx con las profesonales del Equipo de Salud Mental de Cáceres, se habla de la familia Mendo- García, la situación es normalizada, se sostiene económicamente y existe buena relación entre ellos. Con los recursos actuales cubren las necesidades de la familia por lo que, además de manifestar la negativa a un recurso residencial, creemos que no es lo más idóneo. Se obtendrá información del juzgado sobre los bienes inmuebles embargados y las propiedades que conservan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2013-04-12','A primera hora se mantiene entrevista en los Servicios Territoriales de la Consejería de Salud y política Social con el Equipo Técnico de Menores del CAM “Francisco Pizarro” de Trujillo, ya que el hijo menor de Mª Angeles esta en guarda judicial desde que ésta entró en el Centro Penitenciario. Reme y José Mª están pendientes que la CTA tenga el control de las cuentas de Ventura para dar permiso a Jesús, hijo de Mª Angeles, puesto que ambos consideran su casa es la de Ventura y pide irse los fines de semana con él. Técnicos de la CTA de Extremadura se personan en el domicilio de D. Ventura previa cita. La vivienda consta de salón, tres dormitorios, cocina, lavadero, WC y salón presenta un equipamiento adecuado y en buen estado y las condiciones higiénico sanitarias son adecuadas pero mejorables. Lo que más destaca de la casa es la habitación del hijo de Mª Angeles, en la que hay un sillón ergonómico así como todo tipo de instrumentos de juego (play station, wii, ordenador portátil, TV plasma) y una suscripción de motos a escala que no conseguimos saber a nombre de quién está. Con respecto a su salud, tiene un cateterismo hecho, ha tenido un amago de infarto, también tiene alto el azúcar (no es insulino dependiente) y la tensión también la tiene alta, por lo que tiene prescritos los siguientes medicamentos: - Micardis 80 mg - Atauvastina 40 mg - Lorazepan 1 mg - Bisoprolol 5mg - Tranxilium 10 mg - Merformina 850 mg Don Ventura nos expresa que conoció a su mujer a través de la ONCE porque Ventura tiene perdido el 90% de uno de sus ojos, doña Josefina Baltasar Rivas, ya que ella era vendedora de cupones y se casaron hace tres años. Finalmente enviudó el 15 de diciembre de 2011. En junio de 2012 comienza una relación con Mª Angeles, separada y con dos hijos, uno de ellos menor de edad, con la que enseguida se instalan en el domicilio de Ventura. Actualmente Ventura tiene 59 años y cobra una PNC y una pensión de viudedad en total cuenta con 1200 € mensuales. Mª Angeles está desde diciembre en la cárcel, Ventura expresa que va a salir muy pronto y que fue por una confusión, pero a pesar de que le afirmamos que es por un delito de estafa él no lo quiere ver así, pues la defiende fervientemente. Refiere que todos los meses pasa a Mª Angeles una cantidad, que según expresa son 300 €, para que pueda pagar al abogado y la saque de la cárcel porque él desea que pueda salir para que le siga cuidando ya que manifiesta una y otra vez que es muy buena con él y lo quiere mucho. Afirma que son pareja de hecho, aunque según nos comentaron los técnicos de menores no se llegó a tramitar. Comentamos que tenemos entendido que Mª Angeles tiene otro novio y que éste también le da dinero para el abogado. El afirma que eso no es cierto y que Mº Angeles solo le quiere a él. No asume la posibilidad de que tenga otro novio. Ventura, por su discapacidad, se muestra como un niño y en algunos momentos se emociona al hablar de ella. Muestra una carta de ella para que la leamos y al hacerlo llora pidiendo que quiere que la saquen de la cárcel. A través de la lectura de dicha carta Mª Angeles hace referencia al hermano de Ventura, advirtiéndole sobre la negación de la entrada en su casa porque dice que él tiene muchas cosas de valor y no se las vaya a quitar. Preguntamos por este hermano y refiere que vivió con él un tiempo y que ya no quiere volver hacerlo, que está en paro y no quiere saber de él. No tiene relación con su familia y tampoco la de su difunta esposa pues dice que ella estuvo en la Casa de la Mujer por maltrato de sus familiares. Manifiesta que no piensa dejar nada de la herencia a la familia de ella porque se lo prometió antes de morir y tampoco a la suya, motivo por el que se lo ha dejado a Jesús, hijo de Mª Angeles. Con respecto a éste último tema le aconsejamos que revoque tal decisión ya que hay mucho tiempo para decidir esas cuestiones y expresa que se lo pensará. Ya revocó un poder notarial en el que le otorgaba a Mª Angeles poder universal para su patrimonio. Explicamos a Ventura cuál es el cometido de la CTA y que nivel de protección se le puede otorgar desde aquí que es con respecto a su patrimonio, cosa que él agradece pero manifiesta que él no quiere ir a un Centro que no entendemos quién le ha dicho tal cosa puesto que entendemos que él puede vivir independientemente con algo de ayuda de una AD a lo que opina que se lo pensará porque él cree que Mª Angeles va a salir pronto. Preguntamos qué cuentas tiene y en dónde con la intención de conocer donde pueda tener su patrimonio con la finalidad de protegerlo. Él manifiesta que esta contento porque ya está protegido, pero refiere no acordarse donde tiene las cartillas por lo que se presta a buscarlas con los técnicos de la CTA. No encontrándolas en ningún lugar pero si documentos que nos aportan algunos datos como un seguro de vida de Caja Extremadura y otras domiciliaciones. Entres éstos encontramos la revocación del poder universal pero no queda claro si fue antes o después por lo que el mismo se ofrece para que hagamos copias. También conseguimos saber que tiene un seguro de vida que está en Caja Duero de la calle Antonio Hurtado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='ANDREU'and apellido2='DAVILA'),'2013-04-16','Ha fallecido Jacinta Dávila Pozo, tía de Javier. A partir de ahora el familiar de referencia será Vicente Dávila Dávila, primo político de éste. Su número de teléfono es: 610 637 297','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2013-04-19','Se envía el PIA firmado a Zafra, pero paralelamente Inma (técnico PIA Zafra) solicitará plaza en recurso de mayores en Mérida o localidad por cercanía a su domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2013-04-22','Se cumplimenta solicitud de ingreso en Centro para personas mayores previa entrada urgente via fax de instrucción del Juzgado de 1ª de instancia e instruciión nº 6 de Cáceres para que la CTA haya de asumir la protección de doña Tomasa adoptando las medidas necesarias para que se lleve a cabo el internamiento adecuado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2013-04-22','Se mantiene conversación telefónica con Lola (ts Siruela), me comenta que la situación no ha cambiado y que no se puede dialogar con ellos para darle una solución, que el juzgado ha rechazado la solicitud de remoción de la tutela de Vitoriano que en la actualidad la tiene Francisco, que el derecho a la libertad de vivir como ellos quieran está por encima de todo. Tras muchas actuaciones y visitas desde la Comisión, los SSB y la ts del Centro de Salud, ha sido improductivo, ellos rechazan cualquier recurso. Se llevará el seguimiento en la medida de lo posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2013-04-23','Se cotacta con María (hermana de Jesús)me comunica que siguen residiendo en Arganda del Rey, ella, su marido, su hermana Ana y Jesús. Mantiene que será temporal pero en realidad llevan dos años allí. El día 14 de Mayo tienen una citación en el juzgado de Coria para repartir una herencia a la cuál acudirá la CTAEx y las hermanas del tutelado. Jesús se encuentra bien, no realiza ninguna actividad, sólo ayuda en las tareas domésticas y si la comisión le insta a que el tutelado debe residir en la CCAA de Extremadura, volverán de inmediato, ya que, no quieren cambiar la situación legal de su hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2013-04-23','Contacto con Ana Isabel (Psicopedagoga PLACEAT), por la incidencia que nos envía de Carlos Alberto sobre la estancia en casa de su madre en Semana Santa. Por las malas relaciones con la pareja de su madre, se pone muy nervioso y el día 29 de Marzo fue ingresado en el Hospital Vírgen del Puerto de Plasencia por una ingesta abusiva de medicación. Se propone desde el centro que se realicen visitas sólo en fechas especiales,(cumpleaños, Navidad...)y sólo pernoctará una noche, además se autorizará el trasporte a través de Cruz Roja. Se autorizan visitas a Carlos en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2013-04-23','Se mantiene conversación telefónica con Ventura para comunicarle que ya no puede utilizar las tarjetas de crédito que desde ahora tiene que ir a la caixa a por 100€ a la semana. Hablamos sobre las domiciliaciones que tiene en su cuenta y que no puede mantener como el digital plus, el movil, el seguro de la moto, fasciculos de planeta agostini todo del hijo de Mª Angeles.... y el número de la Granja de San Ildefonso de un señor que está fallecido. El quiere seguir pagando por el niño que tiene apadrinado y por la Asociación contra el Cáncer. Desea mantener digital plus pero le comunicamos que tiene la cuenta en números rojos y que esos gastos son suplerfluos en este momento. Llora al acordarse de Mª Angeles de la que habla como su esposa y quiere que salga de prisión porque "ella es muy buena". No piensa cambiar el testamento y vuelve a decir que prometió a su difunta no dejarle nada a su familia. Con respecto al juicio no se realizó porque su prima no se presentó , refiere que esta va a decir que él se vale por sí mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2013-04-23','Se recibe información sobre Genaro desde el Centro Aprosuba 11 que en su timpo de ocio viene realizando salidas fuera de la localidad en compañía de personas que desconocen y el no lo reconoce y cuando se le pregunta se pone agresivo. Saben por terceras personas que esas personas no son buenas compañías. Técnicos de CTA se ponen en contacto con el Centro. Ana TS afirma que lleva un tiempo que le viene a buscar un señor en un coche y cuandollega no está bebido pero viene manchado de barro, como si se dedicara a trabajar. Algunas personas le han visto en Helechal y creen que está recogiendo patatas y por eso viene sucio. El lo niega. Desde la CTA se le insta a que hablen con ese señor y le comuniquen que no se puede llevar a Genaro, así como a esas personas que no son de fiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2013-04-24','Se recibe llamada de Guadalupe y expresa que desea que le revisen en la clínica de Lugo como lo hacían cada dos años cuando residía allí. Tras sufrir una paliza en un portal ella quedó con los huesos desechos y un doctor que vivía allí le atendió de sus dolencias por eso acudía cada dos años a revisión y ayer precisamente fue al CS y le dijo su médico que debía de estar pasando muchos dolores cosa que ella afirmó rotundamente. De hecho le han derivado a radiología para que le vean un pie que lo tiene fatal. Se le comunica que si el director del CRR puede llamarnos para que hablemos con él sobre este asunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2013-04-29','Visitamos la vivienda del tutelado, ya que, tiene humedad y está dañando la casa de su vecino. Además cuando Felipe ha ido a pasar unos días a su casa tenía cortado el suministro eléctrico, por tener el contador dentro de la misma. Quedamos con el albañil para verlo, la humedad viene posiblemente del tejado e instalarán el contador fuera para poder darle de nuevo el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2013-04-29','se mantiene conversación telefónica con Paquei de la (EALE)para comunicarnos que han recibido de la Oficina de Asistencia a Víctimas del Delito la medida impuesta de orden de alejamiento. Paqui comunica que fue Julio al juicio y que finalmente no se celebró porque la madre y el abuelo reconocieron los hechos. En la CTA no se ha recibido nada por lo que ellos mismos nos lo envían via fax. La medida de aljamiento sobre Manuel Montaño Soler y Pilar Montaño Rangel en Sentencia dictado en procedimiento abreviado 155/2012 por lo que se les condena a ambos, entre otras, a la pena de prohibición de aproximarse a menos de 200 metros de él, domicilio o lugar de trabajo y cualquier otro lugar donde se encuentra, así como comunicar por cualquier medio, por tiempo de DOS AÑOS. La condena quedará extinguida el 22/1/15.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2013-05-02','Se realizan distintas llamadasa telefónicas al objeto de obtener datos relativos a Rafael. Se nos informa de lo siguiente: - Su último domicilio conocido es en Mérida C/ Carderos. Centro "PAD". - Que pertenece al Centro de Salud urbano 2 de Mérida y su médico es D. Alfonso García Cabañas. - Que no se tiene constancia de que tenga familiares. - Que en 2011 acudió al CEDEX de Valdepasillas . - Que no ha pasado nunca recoocimiento de grado de discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIO'and edp.apellido1='CARRETERO'and apellido2='HERNANDEZ'),'2013-05-13','En el día de hoy se reliza llamada telefónica al INSS para saber el motivo por el que se le ha dado de baja en la PFHC. Atiende el teléfono José Murcia y nos explica que efectivamente se le ha tramitrado la baja por no existir convivencia entre el interesado y la perceptora de la prestación. Se trmita nueva solicitud para cambiar el titular de la mencionada prestación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2013-05-14','Se recibe llamada telefónica de Maribale, Aprosuba 9 , para informar que Vanesa no ha regresado al centro tras la última salida. Formulará denuncia ante la G.Civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-05-14','En el día de hoy se realiza llamada telefónia a Mª Paz, Trabajadora Social del S.S. de Base de Don Benito para obtener información sobre Almudena y me informa que en el día de ayer estuvo dando problemas. Que agredió a cinco señoras, que fue a las dependencias de Servicios Sociales con la intención de agredir a las responsables. Que iba arrancando los espejos de los coches. Que no se toma la medicación. Me explica que a lo largo de la mañana hablará con su médico de familia. Y que nos remitirá informes por fax tanto social, detallando los últimos acontecimientos como de la intervención de la Policía Local','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2013-05-15','Se cumplimenta docuento de opción de P.N.C a P.F.H.C. Se opta por P.F.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2013-05-15','En el día de hoy se realiza llamada telefónica a la casa de la misericordia y se habla con el padre Fernando al objeto de preguntarle sobre Álvaro Rafael. Me explica que es una persona que tiene muchas difiultades, que da bastantes problemas pero que está bien y que puede continuar en ese Centro. Que es consciente de que es muy dificil buscarle otro recurso más especializado por su patología.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2013-05-17','En el día de hoy se llamaa la Notaría de Cáceres ( Avda. virgen de Guadalupe) para preguntar si sería posible obtener información sobre el testamento de Ventura. Nos informan de que los testamentos no se pueden retirar si no es posr el interesado pues cuanto él testó no estaba incapacitado. Consultrá lo solicitado y nos llamarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2013-05-20','Llama María la psicóloga del CRR de Badajoz informando que Vanesa no se adapta al centro, lleva 3 meses y tiene poca adherencia al Centro. Han decidido que le van adejar ir una semana fuera porque este fin de semana se ha dedicado a romperlo todo y en otras ocasiones agrede al personal. Le comunico que que no puede dejarla ir del Centro porque no tiene donde ir y ella refiere que el CRR es voluntario y abierto. Paso la llamada a Isabel Reyero y les comunica que bajo nuestra responsabilidad no le puede dejar ir.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2013-05-21','Vanesa llama desde el CRR y pide 350€ para irse en taxi a Plasencia con su madre. Se habla con CSS de Plasencia y no nos dan buenas referencias de la madre. Por otra parte se habla con su psiquiátra Antonio Gonzalez 924218004 porque cuando hay razones de urgencia le ven sin cita, manifiesta que ha visto a Vanesa el jueves pasado y que convocará subcomisión de valoración Unidad de Rehabilitación Hospitalaria. Posteriormente hablo con María psicóloga y refiere que ha hecho todo lo posible porque Vanesa se quede en el CRR. Se habla con Vanesa y la convencemos para que se quede en el CRR porque se va a reunir una comisión para que le den otro recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ORTEGA'and apellido2='SEVILLA'),'2013-05-21','David tiene una nueva deuda por unos fásciculos que compró a una editorial y tenemos que pagarlo a plazos. Han aceptado que todos los meses hagamos una transferencia de 50 €. Hemos empezado a pagarla en el mes de mayo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-05-21','La deuda que tenía con Cofidis ya está abonada. Sólo faltaba este mes pagar 53,89 € y se han pagado en mayo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ORTEGA'and apellido2='SEVILLA'),'2013-05-21','La deuda que tenía con Planeta Direct al no poder pagarla ya que no tiene dinero suficiente, la vamos a pagar a plazos de 50 € todos los meses comenzando en mayo. La deuda asciende a 2320,06 € debido a los intereses que ha tenido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2013-05-21','Se mantiene conversación telefónica con Jesús TS SSB, tras los frustrados intentos de ponernos en contacto con Vanesa(642303835). Informa que sigue en Málaga y que está con una familia de rumanía cuya hija es amiga de Vanesa que reside en Zafra y es por ésta por la que sabe de ella. La última vez que habló con Vanesa le dejó muy claro que no puede irse fuera de España por la pensión. quedamos que de momento no hacemos ninguna modificación puesto que hay muchas posibilidades que Vanesa vuelva pronto a Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-05-20','En el día de hoy se personan en las dependencias de la C.T.A.E. Almudena y su padre para pedir explicaciones acerca de porqué esta Comisión tiene bloqueadas las cuentas. Se les explica que el motivo de tal acción ha sido el presionar a Almudena con el fin de que se pudiera en contacto con nosotros y comunicarle la fecha del próximo juicio. Ya que llevaba meses sin llamrnos por teléfono. Se firma un " contrato" con ella y con su padre, como testigo, del que dejamos copia en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-05-21','De nuevo se personan en la Comisión Tutelar Almudena y su padre y nos dan la siguiente información: - Que ayer acudieron a consulta con el psiquiatra y Almudena no accedió a ponerse un inyectable .Pero que le ha prescrito otro tratamiento. -Que se va a vivir con su padre al domicilio de éste y permanecerá en el mismo siempre que la convivencia sea buena y no se vea con su compañero sentimental -En cuanto al aspecto económico concluímos que se le permitirá reintegrar una cantidad de 30 Euros semanales delos cuales 30 serán para su padre para contribuir a los gastos comunes del domicilio familiar y otros 10 para sus gastos personales. Se le explica que nedida que ella responda a los compromisos adquiridos y firmados dos días atrás, se podrá modificar esta cantidad. Deberá ir acompañada por su padre al banco. - Que los gastos derivados de la compra de ropa serán cubiertos por su padre y reintegrados por nuestra parte después. - Que a finales de esta semana se pasaran por Apenesmer (Mérida) para informarse sobre las actividades que allí se realizan al objeto de integrarse en alguna. - Que su compañero sentimental tiene llave de su casa de Don Benito y su padre, D. Antonio no está se acuerdo con este particular por lo que propone que se mande a un cerrajero acompañado de otra persona para cambiar la cerradura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2013-05-23','Se llama a Asindi para preguntar por Victoria, se nos explica cuál es su situación actual. Está teniendo problemas sobre todo en la comunidad, debe dinero. La psicóloga está interviniendo constantemente con ella. Ha ido recientemente a su casa y "todo se le ha revuelto".Consideran que el tratamiento psicológico es muy necesario y nos reiteran que la psiquiatra les ha indicado verbalmente que no se le puede proporcionar este tratamiento en su unidad. Se les pide que le tramiten Ley de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2013-05-23','Llamamos a Felipe para que tenga conocimiento de que su madre tiene que ingresar en el Centro Residencial Sierra de San Pedro en Casas de Don Antonio el lunes día 27 de mayo. Refiere que vendrá su hermano Jesús de Pamplona para pasar la Feria y que el mismo lleva a su madre a la Residencia por lo que no hace falta que sea Cruz Roja la que haga el trasporte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2013-05-24','En el día de hoy nos ponemos en contacto con una técnico de Dependencia, Estela (927160021)y nos explica que aún no se le ha revisado el PIA pero que se le hará en breve, se modificará y se le revisará el recurso asignado. Se oferterá plaza pública o Prestación Vinculada. Nos llamará para que optemos. Acontinuación se llama a Margarita Trabajadora Social de Albalá para preguntar sobre la interesada e ir reuniendo información que nos permita tomar la mejor decisión a la hora de negociar la prestación Margarita nos explica que aunque Rosario tiene a dos cuñados y una hermana en el mismo centro, su situación económica no va a sorportar por mucho tiempo el coste de la plaza. Margarita ya ha hablado con la hermana sobre la opción de que se le pueda cambiar de residencia y esta lo entiende y expresa que le parece bien que tomemos las decisiones que consideremos oportunas. La Trabajadora Social hablará con la Directora del centro y con los familiares.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='RUBIO'and apellido2='LEO'),'2013-05-24','Nos llama Margarita, Trabajadora Social de Albalá para comentarnos que ha hablado con la Directora de la residencia sobre Rosario y que le ha explacado que cada vez que sale del centro se descompensa mucho y que por ese motivo apenas realizan salidas. Le ha explicado las circunstancias económicas de la interesada y las opciones de futuro que hemos de valorar con respecto del recurso residencial. La directora explica que el cambio de residencia puede ser dificil debido a los problemas de conducta de Rosario, que existe otra residencia gestionada por ellos en Arroyomolinos y que si fuera posible gestionar el cambio a ese centro la adaptación sería algo menso dificil pues parte del personal de la misma conocen a la mencionada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2013-05-28','Se mantiene conversación telefónica con Jesús,hermano de Martín le informamos que estamos haciendo gestiones para dar de baja a los vehiculos y el Twingo está quemado en el domicilio de la calle García Marquez. Quedamos con él para entrar en el domicilio. Seguidamente hablo con Martin desde el CSS de Plasencia refeire que tiene el twingo quemado y que también. La motocicleta peugeot está en el depósito de la policía local porque se la quitaron por no tener la placa de matrícul y por ir sin papeles de eso sería or el año 2009 o 2010 era de color gris metalizado. Por otra parte de la motocicleta honda de 49 cc porque se la dió a un amigo que no se la pagó y además es un delincuente. El vive en la calle que es herencia de su madre porque en la calle García Marquez no se puede vivir y como tuvo un brote psicótico rompió todo y la instalación electrica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GONZALEZ'and apellido2='NEVADO'),'2013-05-28','Realizamos llamadas a la Asociación Leonesa de la Caridad. Refieren que es un comedor social y que no saben de esta persona pero que daran aviso al albergue. llaman del albergue y Anonio solo pernoctó el 1 de abril y no saben más de esta persona. Dejo aviso de que si vuelven nos lo pongan en nuestro conocimiento. se realiza escrito al Juzgado informando que no sabemos de su paradero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-05-28','En el día de hoy se recibe llamada telefónica de Mª Ángeles,mantiene conversación telefónica con la Jefa de negociado de la Comisión Tutelar, la conversción gira en torno a los mismos temas que en días anteriores sobre los problemas para recoger su ropa y enseres en el piso que había tenido alquilado y que actualmente está buscando otros. Se le explica que no tiene dinero suficiente y exige que se le ayude desde esta Comisión.Se le reponde con un no rotundo por lo que comienza a decir " que no quiere vivir", Se llama a U.S.M de Valdepasillas y hablamos con la Trabajadora Social, se le explica la situación en la que se encuentra Mª Ángeles en el momento actual así como el contenido de la última llamada recibida. Carmen, la Trabajadora Social del mencionado centro nos informa de que hasta agosto no vuelve a tener programada consulta. Explica que mirará los datos que tiene sobre ella y se pondrá en contacto de nuev con nosotros. Que entienden que deben intervenir ellos. Me pongo en contacto con el juzgado para solicitar información sobre el procedimeinto y las no comparecencias de Mª Ángeles a la cita con el Forense.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-05-27','El 27 de mayo de 2013 se personan en la CTAEX Almudena y su padre, para informarnos de que todo sigue igual, que van a ir a comprar ropa, que han sacado 40 E del Banco....Almudena expresó que quería llamar a su pareja, que estaba enamorada de él, que le echaba de menos y que deseaba ir a verlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-05-28','Acude de nuevo a vernos el D. Antonio, padre de Almudena nos informa de que cuando salieron de nuestras dependencias y en un decuido, ella llamó desde un teléfono público a su pareja y le informó que estaba con su padre, en Valverde de Mérdia. D. Antonio explica que al poco tiempo de llegar a su domicilio se presentó el compañero de Almudena y ambos se marcharos de casa. Previamente le entregó los 40 Euros íntegros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2013-05-30','Técnicos de la Comisión se desplazan hasta el Centro Residencial Gerivida donde se encuentra Sofía Florentina. A primera hora nos entrevistamos con la directora, Belén, que nos informa sobre su situación actual tras la muerte de su hermana Dolores. Se encuentra triste y como siempre han estado juntas y no se relacionaban mucho con el resto de los residentes ahora se encuentra sola. Opina que van a tener un problema cuando ocupen la otra cama de la habitación. Manifiesta que en todo este tiempo que las hermanas han estado en Gerivida no ha acuidido ningún familiar a visitarlas y justo después de la muerte ha venido una hija de una prima para interesarse por ella por temas de testamento. Florentina pide hablar con la CTA en concreto con Pedro pero le manifestamos que ya no está y ahora somos otros técnicos los que llevamos su caso. Quiere irse a Guadalupe a su casa a vivir, puesto que ya su hermana ha muerto y no tiene porqué estar en ningún Centro. Le comunicamos que esa posibilidad es inviable ya que el estado de su casa no es habitable y que ella necesita los cuidados que porporciona un centro residencial. Florentina se altera y comienza a dar voces manifestando que ella es una mujer de posibles y no tiene porqué estar ahí. Le decimos que aunque tiene patrimonio no tiene dinero para arreglar la casa. Sigue alterada, no escucha y no se consigue entablar un diálogo con ella. Se le pregunta si quiere vender alguna tierra para poder tener dinero pero no quiere ni hablar de esa posibilidad. Se le pregunta si sabe quien de su familia ha venido a verla y dice que sí que es Manoli. Seguidamente Belen, directora de Gerivida, informa que Florentina tan solo tiene 169 € de una FAS y no tiene dinero para comprar ropa por lo que se la proporcionan de otras personas fallecidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2013-06-03','Se recibe llamada de Mª Cielo informando que Diego casi no va al Centro de Rehablitación y que quizá sería mejor que acuda por las tardes al Centro de Ocio. Quería poner en conocimiento a la CTA esta decisión pero observa el problema que no sabe si hay autobuses por las tardes de Fuente del Maestre a Zafra y viceversa y también por el problema de quién se encargaría de acompañarlo en el bus en el caso que lo hubiera. Me habla de Pilar su cuidadora (647407464)y me pongo en contacto con ella. Cuenta que se pasa el día tumbado sin querer hacer nada y que mañana tiene cita con el psiquiatra. Quedo en comunicarme con el psiquiatra y que llamará para darme su nombre.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-05-31','En el día de hoy se persona en la C.T.A.E.X. D.Antonio, el padre de Almedena y nos aport la siguiente información: - Que no se ha marchado a Don Benito, como habíamos pensado. Se han quedado en Mérida. - Sabe a través de una amiga, que duermen cerca de las vías del tren en el recinto de la estación de trenes. Al parecer se despiertan y van a los aseos de la estación. Compran dos "litronas, se las bebe Miguel Ángel y después se marchan a la Puerta de la Villa, hasta por la tarde y regresan de nuevo a las inmediaciones de la estación de RENFE. Tras marcharse D.Antonio nos ponemos en varias ocasiones, en contacto con la Unidad de Salud Mental de Don Benito con el objeto de hablar con el psiquiatra Dr. Alberto Gallego. No conseguimos hablar con el, por encontrarse, primero reunido y más tarde en consulta. Hablamos con Agustín , trabajador Social y le contamos las últimas noticias sobre Almudena. Quedamos en que nos llamaría su médico cuando pudiera. Hacia las 12 horas se presenta en el despacho de la Jefa de Sección de la C.T.A. Miguel ángel quien nos informa que estaba con Almudena hasta hace una media hora que se han separado, que ella le había informado minutos antes de su intención de venir al SEPAD. Le decimos que por allí no habia apareceido y aprovechamos para indagar sobre lo que ambos han hecho en los últimos días. Comentamos con él brevemente sobre el estado de Almudena, ke explicamos que su relación ene stos momnetos nos les hace bien y debería distanciarse, a lo que asiente. Su intención, según manifiesta es marcharse a Don Benito en el tren de la una "y pico".Le pido el número de móvil: 680.37.36.48. Hacia las 14 horas, en vista de que no podíamos contactar con el psiquiatra, realizamos llamada telefónica a Miguel Ángel y nos indica que Almudena está con él.Hablamos con ella y quedamos en que se irá el fin de semana con su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2013-05-03','Se recibe llamada de Mª Cielo informando que Diego casi no va al Centro de Rehablitación y que quizá sería mejor que acuda por las tardes al Centro de Ocio. Quería poner en conocimiento a la CTA esta decisión pero observa el problema que no sabe si hay autobuses por las tardes de Fuente del Maestre a Zafra y viceversa y también por el problema de quién se encargaría de acompañarlo en el bus en el caso que lo hubiera. Me habla de Pilar su cuidadora (647407464)y me pongo en contacto con ella. Cuenta que se pasa el día tumbado sin querer hacer nada y que mañana tiene cita con el psiquiatra. Quedo en comunica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2013-05-03','Se recibe llamada de Mª Cielo TS CRR Zafra manifestando que Diego no acude al Centro. El viene solo desde Fuente del Maestre, coge el autobús pero ultimamente no quiere ir. Según opina Mª Cileo podría ser que le venga bien acudir al Centro de Ocio , pro este recurso es de tarde y no sabe si hay autobuses por la tarde. Me pongo en contacto con Pilar su cuidadora (647407464) diego tiene un fuerte deterioro con su enfermedad y poco podemos sacar de él, el avance es mínimo. No quiere hacer nada solo estar en la cama, lleva una lucha con él par que se levante y realice sus obligaciones y no consigue nada. Mañana tiene cita con su psiquiatra, el doctor Zamora (924554571) y sería recomendable avisarle de lo que está pasando. Me pongo en contacto con el doctor Zamora y le informo de como está en estos momentos Diego. Refiere que le presionara y le meterá miedo con ingreso para que reaccione y acuda a sus obligaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-06-03','En el día de hoy se mantiene entrevista con Almudena y su padre. Les explicamos que debe ingresar en algún recurso pues el acuerdo que firmamos la semana anterior se ha inclumplido por parte de Almudena y por lo que D. Antonio verbliza la situación en el domicilio no se va a mantener por mucho tiempo, pues él cree que su pareja no va a aguantar mucho. Almudena expresa que se quiere marchar a su casa y le explicamos los motivos por los que, de momento, no puede ser. Se le dice que no podemos negociar y que si no puede estar en el domicilio de su padre ,la opción siguiente es el ingreso en un recurso residencial. A continuación llamamos a Alberto Gallego, le explicamos cómo está la situación y la conversación mantenida con padre e hija. D. Alberto nos informa de istintas opciones: - Residir con su padre y acudir a PROINES. - Unidad de Hostipalización de Media estancia. - Elevar a la Comisión la propuesta de estancia en recurso residencial. Pasados unos minutos de nuevo llama el Dr. Gállego y nos informa de que ha hablado con técnicos del SES y de PROINES de la propuesta de Centro Residencial para Almudena. Al parecer ella ya había estado en CRR de Badajoz, abandonando el centro por propia voluntad, pero que eso no implica que no pueda volver siempre que se cuente con su voluntad. Que él propondrá dicho recurso a la mencionada comisión y que se le asignará plaza donde exista vacante, cree que en Plasencia. Nos informa que podría ser derivada a la UME mientras existe vacante en este recurso, en caso de que no pudiera ir al domicilio de su padre. De nuevo volvemos a mantener entrevista con Almudena y su padre y quedamos finalmente en que se esperá a que se resuelva el ingreso en CRR o centro de similares características. Que vivirá con él. Le indico a D. Antonio que si hubiera alún problema llame al 112 o al Dr. Gállego y este último podría mandar un informe al médico de urgencia del CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2013-06-04','Llamo al CAM "Francisco Pizarro" y entablo conversación telefónica con Juan Pedro, director del centro. Jesús, hijo de Mª Angeles Cuenca Gonzalo, no ha tenido permiso para visitar a Ventura porque los técnicos no lo vreen recomendable. Tiene permiso para pasar fines d esemana con su tía materna y su abuela, ambas no quieren saber nada de Mª Angeles. El fin de semana pasado estuvo con su tía y ha visitado a Ventura pero en ningún momento ha pernoctado con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2013-06-05','Se mantiene conversación telefónica con Pepa, gerente de Aprosuba. Informa que el programa del que hablamos no es para entidades públicas sino para asociaciones por lo que lo que nos queda para que Eva y Miguel Angel vivan juntos es alquilar piso y ver posibilidad de coordinarnos con SS.SS. Hablamos con Encarna, psicóloga del Programa de Familia, buscando la posibilidad de apoyo en el caso de que se vayan a vivir juntos . En principio comunica que el PF solo puede trabajar con menores de 18 años pero que entiende que se podría hablar con el Quipo y que no podrían realizar mas que una visita a domicilio. En cuanto a la Auida a domicilio lo llevan los Trabajadores Sociales del SSB. Nos ponemos encontacto con el padre de Miguel Angel Molina (pareja de Eva) 676973974 le comunicamos que nuestros planes son alquilar piso en Montijo con gastos a medias y que sean supervisados por el medio comunitario (SSB y PF)y está de acuerdo pero tiene que hablar con su mujer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2013-06-06','Se recibe llamada de Vanesa manifestando su interés en ir a vivir con el "padre de su hijo", Antonio Alexander Barrasa (687276558)en Ceclavín pidiendo una y otra vez que le "dejemos por favor". Le explico que estamos pendiente de la Comsisión que ha convocado su psiquiatra para ver que centro se le asigna, que tenga paciencia pero ella no quiere, quiere irse con Antonio. Le manifiesto que no tengo datos sobre Antonio y que de momento eso no va a ser posible pero le explico que me enteraré sobre esta posibilidad. Posteriormente me pongo en contacto con la TS e Ceclavín, Marta, refiere conocer perfectamente a Antonio, que es enfermo mental y presunto padre de la hija de Vanesa, la familia de él pidió en su tiempo pruebas de paternidad, finalmente este menor fue retirado por el Servicio de Protección de Menores.Hasalido del psiquiaátrico de Plasencia el día 30 de mayo, apenas hace una semana y la madre de éste dice que esta muy bien pero que tiene que seguir la medicación sino vuelve con los síntomas. Desde la opinión de la TS del SSB sería inconvniente que vivieran juntospues desestabilizaría a Antonio. por otra parte la familia de él no quiere saber nada de ella y Antonio reside con su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA ELENA'and edp.apellido1='DELLA'and apellido2='VISTA'),'2013-04-16','Se busca número de teléfono embajada de Italia y se mantiene conversaciónt telefónica con Esther, trabajadora Social del mismo (912106937 calle Lagasca 98 28006 Madrid) Le comunica que tenemos una tutelada a Marta sin parientes en España y viviendo en residencia de la Junta de Extremadura sin ninguna movilidad. Esther dice que el pasaporte lo tiene caducado desde hace tiempo. Se le puede solicitar renovación que importa 82€ o Carta de Identidad (DNI) por importe de 5,8€. opina que como no va a viajar y no tiene dinero se le haga Carta de identidad. Se envia solicitud a Beatriz para que la cumplimente y se le realice fotografías.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA ELENA'and edp.apellido1='DELLA'and apellido2='VISTA'),'2013-05-21','Se remite solicitud de Carta de Identidad a la Embajada de italia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA ELENA'and edp.apellido1='DELLA'and apellido2='VISTA'),'2013-06-04','Se contesta al Juzgado de Cáceres que no podemos facilitar datos de filiación porque no los tenemos y que se ha solicitado recientemente carta de identidad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-06-07','Tras dos días intentando contactar con Don Antonio, conseguimos hablar con él. Nos indica que Almudena no está bien, que se quiere marchar del domicilio, que quiere vivir en su casa, que quiere ver a Miguel Ángel... A continuación nos ponemos en contacto con el Dr. Gállego, sin exito pues está en un Congreso. Pasdados unos minutos y recibimos llamada de PROINES, Don Benito, con Mª José Trabajadora Social, en relación con el expediente de otro tutelado y aprovechamos para hablar de Almeduena puesto que ellos la concocen. nOS comenta que la decisión que se ha tomado de dejar a Almudena con su padre, en su opinión no es acertada pues a lo largo de años se ha demostrado que esta fórmula no funciona. Hablamos sobre el protocolo de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-06-10','En el día de hoy a 8:48 horas, se recibe llamada telefónica de D. Antonio para comunicarnos que a las 10:00 horas, se personará en las dependencias de la C.T.A.E.X con Almudena. Que ya no se puede mantener en su domicilio. Le explico que justo a esa hora nos marchamos de viaje y que no estaremos en toda la mañana, me responde que en ese caso permitirá a Almudena que se marche a Don Bento. Llamo Dr. Gállego, le explico brevemente los últimos acontecimientos.Le pido instrucciones, me indica que se va a proceder a un ingreso involuntario. El ingreso se llevará a cabo desde el domicilio de su padre. Se pone en marcha el protocolo de urgencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2013-06-11','Mariloli se persona en la CTA manifestando que tiene un paepl don el fiscal le pone que se quiere ir del CRR y que su hermano le ha dicho que se vaya prepando las maletas. Le comunico que se habló con el SSB para que fueran a ver a su hermano porque según ella estaba muy preocupada por su salud. Hablo con Miguel Simón psicólogo del CRR y director del centro. Refiere que Mariloli ultimamente insiste en irse del centro pero informa que no está para vivir sola. Tiene ultimamente conductas desorganizadas, su relación con su hermano es conflictiva, hay un triángulo extraño entre su amiga, su hermano y ella. Mariloli utiliza la enfermedad de su hermano para ir a Almendralejo pero le consta que el hermano no quiere que vaya. El hermnao visita con cierta frecuencia el centro. Mariloli está desorganizada en su planificación, con inconsistencia grande en torno a toma de decisiones, gastos... Tiene periodos de permiso para visitar Almendralejo y no se plantean los periodos mas largos porque tienede a abandonar la medicación, la higiene y se abandona. Tiene el problema que ve como otros compañeros abandonan el centro y ella no. ni en Mérida CRPS ni en Almendralejo hay un recurso apropiado para ella. Titene periodos confusionales y problemas de manejo como la incontinencia urinaria que padece que no hace bien el tratamiento, tiene problemas de autogobierno de su salud. Ahora mismo no hay una alternativa mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2013-06-11','Se llama al Centro Gerivida para que nos informen cómo sigue Florentina después de nuestra visita. Belén la directora del Centro nos informa que sigue igual que siempre y obsesionada que quiere hablar con Pedro. Por otro lado, la familia está llamando para decirle que tiene que hacer testamento por lo que el personal del centro muestran su repulsa ya que no han venido ni al entierro de su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2013-06-11','se establece conversación telefónica con la psiquiatra de Carmen tras haber recibido llamada telefónica de sus vecinos manifestando que se ven desde las ventanas por la noche la luz encendida y porrazos en las paredes. Teresa Martinez refiere que sí va a ponerse la inyección pero a pesar de esto se encuentra descompensada y ha podido comprobar que está peor. Quieren realizar visita domiciliaria pero no saben si podrán hacer un internamiento involuntario que sría lo deseable en estos momentos. Quedamos en estar en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA ELENA'and edp.apellido1='DELLA'and apellido2='VISTA'),'2013-06-11','Se recibe resolución de reconocimiento de situación de dependencia y se contacta telefónicamente con Beatriz de Care, no entendemos quien ha solicitado la dependencia sino tiene carta de identificación. Me comunica que se les hizo a todos los que estaban institucionalizados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2013-06-11','Se recibe llamada telefónica de la TS de CARE Casar de Cáceres para comunicarnos que mañana operan a Rafael y el permiso ya está firmado pero desea saber si le tienen que acompañar. Van a dializarlo. Le comunico que sería deseable que alguien estuviera con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-06-13','Técnicos de la CTAEx se desplazan hasta las dependencias de la policía judicial de Badajoz para toma de declaración de la curatelada, con ella se encuentra su madre, posteriormente llega su abagada de oficio. La madre no se queda por referir que su hija no quiere volver al pueblo y que debemos buscar un centro para su hija porque en su opinión volverá " a las andadas". Ella no está bien en su casa e insulta a todos a su hermano a su sobrino y a ella también. Se procede a tomarle declaración sobre un delito de estafa y usurpación de identidad por haber cogido una carta en el buzon de una vecina y con sus datos pedir crédito para la compra de un movil. Mª Angeles no reconoce que ella quitara la carta del buzón sino que aparecieron en el suyo y pensó que era una oferta de empleo. Cuando salimos fuera de la comisaría hablamos con ella y manifiesta que no quiere volver a Alburquerque con su madre, no está agusto y todos los de su familia están todo el día riñiéndola y se siente como en una prisión. Su deseo es irse de alquiler y que su madre tiene la obligacion de pagale el mismo al igual que ayuda a su hermano. Quiere el dinero íntegro de su pensión. Le informamos que si ella se porta bien se lo iremos dando conforme lo necesite pero que ella tiene que dejar de estafar y le aconsejamos sobre que es lo que le pude pasar si sigue por ese camino. Por otra parte también le aconsejamos que podría ingresar en algún centro a lo que ella no quiere, se niega rotundamente. Al preguntarle si va a casa de la madre de su novio dice que no que irá a dormir a casa de un amigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-06-17','Se tiene conversación telefónica con TS del SAD del IMAS de Cáceres, Lourdes Pérez. Informa que a pesar de ser incompatible la AD del Ayuntamiento con la de Dependencia en este caso se ha hecho una excepción y se les va a prestar. Han realizado ella y Carlos varias visitas al domicilio y al Centro de Día donde Gabriel permanece. La psicóloga del Centro dijo que los lunes no viene en condiciones óptimas de higiene. La razón es que los domingos no se les presta AD. Actualmente por parte del IMAs , le hacen aseo tantao a Pilar como a Gabriel las tardes de los lunes, miércoles y viernes de 7 a 8:30 y por la mañana recoge la Auxiliar a Gabriel cuando viene del Centro. de 1:30 a 2: 30, lo saca del furgón, lo sube a su casa y le cambia el pañal. El SAD de Dependencia va a primera hora de la mañana lo levanata y lo asea. Han enviado informe de Carlos el Trabajador Social del Imas donde porpone ingreso en Residencia ya que lo han visto muy pasivo y ausente. Abrahan y Pilar están asimilando este ingreso y parece que han accedido siempre que sea en Cáceres. La madre ha mejorado mucho y desde el Ayuntamiento están viendo posibilidad de Vivienda Social para ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='HERNANDEZ'and apellido2='MARCOS'),'2013-06-17','Se recibe llamada telefónic de Dña. Julia Hernández, hermana de Felisa para expresar su descontento con el Centro (C. R. Nuñomoral) pues egún refiere no le permiten visitar a su hermana. Nos ponemos en contacto con el Centro y mantenemos conversación telefónica con Mª José, Trabajadora Social quien nos explica que efectivamente no creen conveniente que Felisa reciba visitas de su hermana por varios motivos: - Hay un proceso judicial abierto aún por unos presuntos malos tratos hacia Felisa y la dirección del centro desconoce que familiares son los que pueden estar imputados. - Felisa se altera mucho cada vez que recibe llamadas o visitas de sus familiares. - Se le ha indicado a Dña. Julia que no realice llamadas sin antes consultarlo con la dirección del centro si bien ella no lo respeta y aprovecha las horas en las que sabe que puede acceder a su hermana sin que la dirección lo sepa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2013-06-18','Tras varias gestiones con Programa de Familia de Montijo para ver la posibilidad de que si Eva y su novio se fueran a vivir juntos pudieran ejercer supervisión y a pesar de no ser perfil acceder a nuestra petición, así como conseguir servicio de Ayuda a Domicilio la madre del novio de Eva no consiente en que ambos convivan porque opina que Eva está muy bien con su familia los fines de semana y su hijo no debe tirar el dinero en un alquiler porque además su marido va a estar en paro. Hablo con con Pepa y le comento lo que dice la madre, quedamos en hacerle una visita y lo hablamos con ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-06-18','se mantiene conversación telefónica con el hijo de Pilar y Gabriel, Abrahan. Le informamos que estamos cambiando PIA de su padre para poder ingresarlo en Centro Residencial ya que el Centro de Día no reune requisitos para él. Se opone totalmente refiriendo que si ingresamos a su padre en un Centro Residencial su madre y él "morirán de hambre" porque a él se le acaba el paro y el contrato de trabajo y con la pensión de su madre no tienen por lo que refiere que "no podría pagar el coche y el seguro". Manifiesta su enfado ante esa decisión y le comunicamos que esa decisión no es firme aún pero que tanto la TS del SAD como el del SSB van a proponer ingreso en Centro pero que aún no nos hemos puesto en contacto con ESM. También opina que no sabe que es lo que estamos haciendo desde CTAEx porque él le llegan aún cosas de su padre sobre sus embargos. Se le informa que él no ha colaborado en ayudar a esta Comisión y realmente es un trabajo complicado averiguar todos sus negocios, propiedades y embargos a lo que Abrahan se compromete en venir a esta Comisión a entrevistarse con nosotros y ayudar en lo que pueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-06-19','Se mantiene conversación telefónica con Pilar, Ts del ESM de Cáceres para contrastar opiniones sobre el ingreso en Centro Residencial de Gabriel. Le informo sobre como Gabriel se esta deteriorando y que va a necesitar otro recurso más adecuado pues el Centro de Día en breve no va a resultar adecuado. Manifiesta que no estaba enterada de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-06-21','Se llama a los Servicios Sociales de Cáceres para obtener información sobre las últimas actuaciones que han mantenido con la familia. Carlos TS IMAS refiere que no los ve mal del todo porque la situación se va a mantener ya que a pesar de que son incompatibles la AD de dependencia y la del Ayuntamiento en este caso se va a mantener ambas y estan cubiertos pero logicamente esto no se va a mantener todo el tiempo, en unos meses la del IMAS se le quitará. Conoce que Abrahan se le acaba el paro y en cuanto al trabajo puede que se lo renueven. Reconoce que Gabriel se ha deteriorado bastante y qu el fin de semana no se mueve del sofá por lo que entiende que a corto-medio plazo tenga que ir a un Centro Residencial. Opina que si Gabriel se va a un Centro tanto Abrahan como Pilar no tendrían problema para percibir la Renta Básica y el acceso a un vivienda social. Ellos quieren que cuando se le pida vivienda social sea en Aldea Moret pero no en la zona donde están y es que no hay otras. Refiere que deberíamos esperar hasta que se vea si sigue Abrahan con el contrato de trabajo o no y dependiendo de esto tomamos decisiones al respecto. Quedamos en retomar el caso para mediados de julio, por lo que de momento no curso la solicitud de cambio de PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2013-06-20','En el día de hoy y tras recibir correo de la dirección del CRR de Badajoz sobre Vanesa nos ponemos en contacto con Ana, Directora del mencionado centro al objeto de ser informados sobre el incidente que provocó el ingreso de la tutelada en el hospital. Nos informan de que desde la fecha de la reunión que mantuvimos en las dependencias del CRR Vanesa ha seguido con los comportamientos que presentaba en las últimas semanas. Autolesionándose, muy demandante.... El lunes pasado sobre las 10:3o estos comportamientos inapropiados se intensificaron más y se prolongaron durante más tiempo de lo habitual. Comenzó a mostrarse impaciente, demandante, a tirar objetos , a amenazar con matar a todos... por lo que los trabajadores del centro llamaron al 112. Allí mismo fue preciso medicarla y aún así seguía agitada. Finalmente fue ingresada por el Dr. Antonio Leal. En cuanto al protocolo sobre el traslado se nos coment que por parte del CRR ya están todos los trámites hechos y se ha enviado la documentación a su psiquiatra el Dr. González, con el que también ahan mantenido conversación telefonic para que agilice la derivación .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='FERNANDEZ'and apellido2='VILLANUEVA'),'2013-06-19','Se mantiene conversación telefónica con Candelas ya que se ha recibido llamada de TS de ESM de Bilbao para ver si nos había llegado una documentación. No da muchos datos por lo que se revisa expediente y no queda clara la situación, motivo por lo que llamamos al CSS de Plasencia para que nos pongan al día. Candela TS CSS de Plasencia refiere que la tiene en el Pabellón de Psicogeriatría del CSS. Esta mujer llegó al Centro en el año 82, residía en Bilbao con su marido y sus8 hijos, uno de ellos de 4 años murió poque se precipitó del balcón y posteriormente abandonó su familia y volvió a su pueblo. Se la encontraron divagando por su pueblo, concretamente en el cementerio en busca de sus padres, estaba con un brote psicótico muy fuerte. Se intentó en su día derivarla a Bilbao pues es donde está la familia pero esta no quiso saber nada, parece ser que nunca entendieron que los abandonase y la falta de afectividad es un característica de su enfermedad. Nunca recibió visitas y nunca se interesaron por ella. Sus hijos lo han vivido como un abandono por parte de ella. Al morir el marido y posteriormente otra hija que cuidaba de la pequeña porque también tiene problemas de salud mental, esta cede su parte de la casa a la hija pequeña, que es la que actualmente reside en ella, los hermanos se la han cedido en usufructo a esta pero necesita reparaciones y es pa pareja de ella la que se ha hecho cargo. cuando murió el padre se vio quen o había hecho separación legal con Juana por lo que Nuestra tutelada tiene gran parte de la casa. Esta hija de Juana (Laura9 es usuaria del ESM de Bilbao y la TS le ha comunicado que tiene una pensión de orfandad y lo que necesitan es una autorización de la cuenta que tiene cuyo titular esta su madre, para poder hacer frente a los gastos de la casa como por ejemplo de la comunidad que desde que falleció el padre no se paga. De esta cuenta se paga el seguro de defunción de Juana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='FERNANDEZ'and apellido2='VILLANUEVA'),'2013-06-20','Se mantiene conversación con Mila (TS ESM Bilbao) Verán como se puede desbloquear esa cuenta y si nosotros tenemos que hacer algo lo haremos. Por otra parte el usufructo de la casa como Juana no va a residir en ella no tendrán ningún problema y en cuanto al seguro de defunción nos darán los datos para pasarlo a la cunenta de Juana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2013-06-19','Se mantiene conversaciónt telefónica con Feliciano para comunicarle que no es posible que se le siga prestando el servicio de acompañamiento por parte de FUTUEX por los recortes que han tenido pero se le puede prestar por una empresa privada. Le parece bien pero que no sea caro a lo que le informo que compararemos precios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-06-21','Técnicos de la CTAEx se desplazan hasta Badajoz con la finalidad de acompañar a Mª Angeles, de nuevo, en la toma de declaración en la Comisaría, en esta ocasión por la denuncia formulada el 16 de mayo de 2013 de Mª Aranzazu Toledano Caro, señora que le tenía alquilada una habitación a Mª Angeles en la calle doctor Fleming n º 37 y en ella se encontró una libreta que abrió pensando que era de su hijo donde localizó apuntes manuescritos por Mª Angeles donde tenía relacionado a algunos vecinos, comprendiendo datos de filiación, números de cuentas bancarias personales y entidades bancarias correspondientes, números de tarjetas de crédito... Mª Angeles llega a la cita en la Comisaría a las 9:45 aproximadamente, estabamos citados a las 9:00 después de haberla avisado que estabamos esperando, procedía del Centro Hermano, ha permanecido en el mismo durante dos días y ya no puede seguir allí. Le comunicamos que podríamos buscar un Centro adecuado a su perfil a lo que nos contesta que ella es una mujer y no una niña y no quiere estar tutelada. Dice que ha estado ingresada 7 días en el UHB por voluntad propia, le ha tratado el doctor Calderón, por lo que se encuentra muy bien, se toma la medicación y está tranquila. Tiene prescrito Aremis 1 pastilla por la mañana y 2 pastillas por la noche de SEroquel Prolong 300mg. Manifiesta que ella desea alquilar una casa en la zona centro que ha visto por 200 €, tanto la policía como la CTA le indican que eso no es posible y si así fuera no le queda apenas para vivir. Tratamos de convencer a Mª Angeles de nuevo sobre la posibilidad de ir a un centro pero no quiere esa alternativa así como tampoco la opción de ir a casa de su madre en Alburquerque.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICOLAS VICTORIANO'and edp.apellido1='RODRIGUEZ'and apellido2='VENEGAS'),'2013-06-25','Se mantiene conversación telefónica con Maribel, trabajadora Social del CSS de Mérida quien informa que Francisco está ene l hospital de Mérida y se encunetra muy mal de salud. Nos facilita los dato de una sobrina que al parecer se preocupa mucho de él: Emilia Sánchez Rodríguez C/Jara 1 Burguillos del Cerro ( Tlfno: 655007320 )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CIRCUJANO'and apellido2='ZAMBRANO'),'2013-06-25','Llama Maribel, trabajadora Social de CSS de Mérida para comunicar que mañana la familia de Jaun vienen a visitarlo y saldrán a pasar el día fuera del Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='GARRIDO'and apellido2='DURAN'),'2013-06-25','Se le solicita abogado de oficio por un delito de lesiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2013-06-25','Se mantiene conversación telefónica con Pilar, cuidadora de Diego, refiere que ha estado una semana ingresado en la UHB por prescripción de su psiquiátra, el Doctor Zamora (924553608). Le han dado el alta el viernes pasado, el sábado se levantó, pero al día siguiente, a pesar de su insistencia, no consiguió que se levantarse de la cama. Este lunes ha tenido que "gritar" para que se levante , se asee y acuda a las clases. Opina que se está riendo de todos ellos. Pilar se muestra muy enfadada con Diego y refiere que debemos hablar de nuevo con nuestro tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2013-07-05','Se mantiene conversación telefónica con la T. Social del C.A.M.P. de D.Benito y nos informa de que Hermenegildo se ha escapado del Centro. Que él estaba muy contento de estar en el Centro pero que le llamó su madre por telefóno, que no saben que le dijo pero a continuación se marchó del Centro saltando la valla. Llamo a su madre tres veces y no contesta al teléfono','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2013-07-05','Teléfono Carmen 661112466','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='ANDREU'and apellido2='DAVILA'),'2013-07-08','Los primos de Fco. Javier estan promoviendo la declaración de herederos desde la Notaría de Zalamea. Nos hemos puestos en contacto con el Juzgado de Paz 924 780005 para que soliciten a Barcelona su partida de nacimiento y con la Notaría 924 780915 para que se pongan en contacto con nosotros para cualquier tramite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2013-07-08','Mª LUZ, hermana de Mª Luisa nos llama para comunicarnos que esta tarde irá a ver a su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2013-07-08','Alexandra de APROSUBA 11 nos comunica que el 10/07/2013 intervienen oftalmológicamente en Don Benito a Genaro y que enviaran la factura del cuidador durante su estancia en el hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2013-07-08','Se llama por teléfono al ATS ( Antonio Cruz Macías) de Saturnino para saber si ha acudido a ponerse el inyectable. Nos informa que no ha ido a la cita que tenía previst para el 14 de junio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2013-07-05','Se recibe llamada telefónica de Maribel (T. Social) de Llerena para informarnos de que ha llegado al domicilio del tutelado una Resolución de extinción del derecho de PNC, por la que además se le reclama una suma de idnero por cobro indebido. Me pongo en contacto con PNC y les envío un fax mediante el cual se le pide la documantación antes mencionada. Una vez examinda la documentación me persono en PNC al objeto de asesorarme sobre la posibilidad de interponer reclamación previa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2013-07-10','Mantengo conversación telefónica con la Asesora Jurídica de PNC y me explica que no se va a estimar la reclamación con casi toda probabilidad pues están claras las circunstancias por las que se ha extinguido el derecho.Por lo que optamos por no presentar Reclamación. Me explica el proceso que seguirá el asunt: - Pasado un tiempo prudencial ,se enviará el expediente a la Tesorería pues es allí donde reclamarán la deuda. - Se dará la opción de abonarla durante un periodo voluntario y más tarde pasará ser "ejecutoria" Probablemente el pago se pueda aplazar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2013-07-08','Llamo a la Trabajdora Social de Cabeza del Buey y me comenta que el tutelado estuvo en la localidad pero en el mismo días se volvió a marchar en un taxi al Centro. Llamo al centro y me confirman que está allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2013-07-15','En el día de hoy nos ponemos en contacto con Dña Carolina Montaño , hermana de la tutelada quien nos facilta en telefóno de esta: 622044323, le contamos que el motivo de nuestra llamada es limitarle el dinero, se muestra de acuerdo con esta decisión. continuación nos ponemos en contacto con la tutelada le explicamos que tiene un descubierto en la cuenta y que a partir de hoydaremos la orden al banco para limitarle la cantidad mensual a 450 Euros. Se muestra conforme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2013-07-15','En el día de hoy me pongo en contacto con D. Ángel Vita para informrle que se va a efectura un cambio en la titularidad de la PF y que se le abrirá una cuenta nueva. Aprovecho para preguntar por el tutelado, me informa que todo va bien. Que está a la espera de conseguir algun trabajo o poder incluirle en algún programa de inserción laboral. Le pregunto por la opción de un C.O. y no la rechaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMALIA'and edp.apellido1='PEREZ'and apellido2='MARAGATO'),'2013-07-16','Se realiza llamada telefónica a la Unidad de Salud Mental de Plsencia para saber el estadod e Amlia. Nos atiende Ana, Trabajadora Social quien tras consultar con la Psiquiatra de la tutelada nos informa de que l última consult a la que asistió fue el 10 de octubre de esta año y se encontraba estble en ese momneto anivel clínico. Que no ha acudido a la última cita que tenía programada en Julio. Le pido que me proporcionen otra cita. Llama la DUE y nos da cita para el 22 de agosto a las 10:30','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2013-07-17','Después de un sinfin de llamadas a la Fiscal, Carmen Barquilla, se consigue hablar con ella para comunicarle que en enero Beatriz tenía 7.848 euros y que unos días antes de aceptar la tutela la CTAEx,como medida cautelar adoptada en el procedmto. de remoción de tutela, esto es, en noviembre, únicamente tenía 7 euros. Ella comunica que la Sentencia,dictada el 5 de julio, ya es firme, por lo que diligenciarán a las TS de la localidad del domicilio de los padres un seguimiento del caso. Se le informa que a partir de agosto se ha suspendido la transferencia a NACE, por lo que podrán hacer uso de toda la pensión de Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2013-07-22','Pepa, de APROSUBA Montijo, comunica que Eulalia fue ingresada el sábado 20 de julio en el HIC con problemas de vesícula.Ha montado turnos entre el personal para estar con ella y seguramente necesitará contratar un servicio de compañía si se alarga la estancia. Nos irá comunicando la información que les vaya dando el médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2013-07-23','Ingresada en el HIC en la semana del 8 de julio, el 23 de julio es traslada a la UME del CSS de Plasencia por derivación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2013-07-23','Ayer, día 22, con la ayuda del 112 y de su familia, Saturnino ingresa en la Unidad de Psiquiatría del HVirgen de la Montaña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2013-07-19','La consulta de oncología del HDon Benito, Dr. Rodriguez García; requiere informar personalmente al tutor de Consuelo en persona y recabar de él el consentimiento informado para administrarle un nuevo tratamiento. Se le informa del procedimiento utilizado habitualmente ( información telefónica, remisión del consentimiento vía fax y remisión de éste por la misma vía) y se niega; exige la presencia en consulta. Nos remite a la Asesora jca así como a la TS del hospital pero no cede. Se ruega a la AJ que lo ponga en conocimiento de la Dirección Médica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2013-07-24','Se recibe llamada de Eva manifestando que quiere que se le de baja en el piso que ha estado ocupando a fecha de 1 de agosto ya que su deseo es vivir con su novio en la casa de sus suegros.También manifiesta que quiere compara un armario para su ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='LORO'and apellido2='MUÑOZ'),'2013-07-23','Se recibe llamada telefónica de Mª Vi Clemente TS CSS Plasencia, para que autoricemos traslado en taxi al tutelado al CAM de Don Benito. Se comunica a Manuela renuncia voluntaria de la plaza de Centro de día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2013-07-23','Se recibe llamada telefónica del TS de Calera de León, Jose, refiere que las actuaciones de reforma de la vivienda de nuestro tutelado ha deteriorado la medianera de la vecina doña Filomena Durán y se le filtra agua por lo que ha realizado escrito denunciando sus daños y solicitando que se repare el daño causado. Me pongo de nuevo en contacto con Jose y refiere que el albañil trabajó bajo las indicaciones del arquitecto tecnico y segun refiere ese derribo está bien hecho y el problema es que esta vecina tiene hecha mal su medianera y por ese motivo se le filtra agua. Nos ponemos en contacto con el arquitecto técnico Francisco Javier Alvarez para pedir informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2013-07-30','Hoy se solicita al Juzgado autorización para ingresarlo en la UME de Plasencia cuando le den el alta en la UHB de Cáceres. Se adelanta por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2013-07-30','Autorizado por el Juzgado, ayer 29 de julio de 2013, se le ingresa involuntariamente en la Residencia Municipal de Villa del Rey. Hoy nos comunican que le están intentando estabilizar su diabetes pero que está continuamente diciendo que se quiere ir y no van a poder retenerla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2013-07-31','Técnicos de la CTA se desplazan a Castuera con motivo de la citación por parte del Juzgado de 1ª Instancia e instrucción nº 1 de Castuera por la celebración de un juicio de faltas seguidos por lesiones cuyos hechos ocurrieron en Cabeza del Buey el 25/2/2013 en calidad de denunciado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2013-07-23','Se llama al Dr. Rodriguez para reconducir el tema pero no se pone y la ayudante nos informa que la dejan hasta que llegue de vacaciones su médico el Dr. Furones','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2013-07-24','Informada la DGerente y Vicepresidenta de la CTAEx, llama al Gerente del Área de Salud de DBenito para reconducir las gestiones y continuar con el tratamiento a la paciente. Al final se deja para que la atienda su médico que viene el día 1 de agosto,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='PIZARRO'and apellido2='GOMEZ'),'2013-08-01','Llaman los hermanos de Consuelo y nos informan que estan ella y Nico en el Hospital pero que no le ponen la quimio por no tener el consentimiento informado. Hablo con el Gerente y el médico y comentan que la semana próxima informan y mandan el consentimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2013-08-01','Hoy se nos comunica la denegación de la pension solicitada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2013-08-01','Rosa del CSS plasencia ha requerido al Dr. Jimenez que en su derivación a la UME indique que el paciente vive solo, pero éste se niega comunicando que el contenido de su derivación es suficiente para que se admita y advierte que aguanta al paciente hasta el día 8 como máximo. En ese intervalo, Rosa intentará hablar con el Juzgado, pues insiste que la admisión es más idónea a través del Juzgado de lo Penal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-07-22','Hoy lunes se presenta el hermano de Mª Ángeles comunicando y registrando el escrito en donde sus padres manifiestan que la situación con su hija en Alburquerque es insostenible y que no toma ninguna medicación por lo que solicitan su ingreso en un centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-08-29','Se recibe otro escrito por correo electrónico de los padres comunicando que el 24 de julio tuvieron que llamar al médico y, a través de la Guardia Civil,fue ingresada en el HIC en donde permanece.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-07-30','Puestos en contacto con la Psiquiatra que le atiende, Mª Jesús Cabello, se le indica la necesidad de que la derive a la UME de Mérida y así lo acepta, pero al ponerse en contacto ésta con los familiares le informan que tiene un cumplimiento de pena y que lo más rapido sería a través del Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2013-07-31','Al principio de la mañana, se solicita al Juzgado de lo Penal nº 2 que sustituya la pena de tratamiento psiquiátrico ambulatorio por el de internamiento y al final de la jornada se habla con la Secretaria judicial para que se haga urgentemente para que no medie el alta del HIC y pueda ser llevada directamente a la UME desde el hospital. Así lo intentarán. Recibiremos sus noticias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2013-08-06','Teléfono de Javier (señor que trabaja las tierras de los hermanos Rangel Porro): 625086636','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2013-08-06','Han procurado comprar una parcela de Teodoro, pero no hemos optado por vender. El teléfono de la Señora es 675519472 y se llama Consolación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2013-08-09','Me pongo en contacto con Teo, el encargado del Centro Residencial de Villa del Rey para comentarle que sería necesario que Salvadora fuera valorada por ESM pero que para ello necesita ser derivada por su médico de cabecera. Refiere que se va a poner en contacto el próximo martes, que es cuando está el médico en el Consultorio Local pero que observa el problema que ellos no tiene personal para acompañar a Salvadora al ESM. Le comunico que veremos posibilidad de asignar un delegado tutelar para estos casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATILDE'and edp.apellido1='SORIA'and apellido2='ORTIZ'),'2013-08-12','En el día de hoy se recibe oficio de Francia por el que comunican que se suspende la Penesión de Matilde por no haber recibid la Fe de Vida que se nos solicitó en Abril. Tras mirr el expediente comprobamos que tal documento sí fue enviado, con fecha de salida 8 de mayo. LLamo al centro de Plasencia hablo con Juan Carlos Granado y quedamos en que le envío la nueva Fe de Vida para que sea enviado y el ofico que se envió en su d´´ia para que también lo adjunte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-08-14','En el día de hoy se realiza llamada telefónica al Centro Socio Sanitario al objeto de preguntar por Almudena. Hablamos con Maribel, T.S. y no informa que ella continúa con el mismo discurso expresando continuamente que quiere marcharse a vivir a su casa. Maribel cree que una vez que salga de la UME no va aconsentir en irse a ningún otro recurso. Quedamos en que hablaremos más adelante del asunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2013-08-16','El pasado 14 de agosto se mantiene conversación telefónica con Margarita ( T.S ) sobre el asunto de la limpieza del domicilio de Salvarora. Al precer se niega a entregarle la llave a Margarita pero el Secretario del Ayuntamiento, que tiene buena relación con ella, lo va a intentar. En el día de hoy se llama al secretario y nos informa que ha quedado con la tutelada el martes para ir al domiclio con ellos. Expresa que ha pedido dinero para unas gallinas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2013-08-20','e autoriza a Tomasa para que, acompañada por su hijo Jesús vaya a retirar 150 Euros al banco para comprar ropa. Teléfono de Jesús: 636183793.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2013-08-20','En el día de hoy y tras autorizar retirada de efectivo del banco a Tomasa se recibe llamada telefóniva de su hijo Jesús par informarnos que han acudido al banco y no es posible retirarlo pues según les han dicho en la oficina no tiene saldo, además les han dado un estracto con los últimos movimientos y han podido ver que ha sido su hijo Luis Miguel quien ha efectuado las retirada en varias ocaiones durante los últimos meses. Se recibe inmediatamente después llamada de Luis Miguel diciendo que está muy nervioso, que sus hermanos le están enviando wassap diciendole que le van a denunciar al juzgado. Confiesa que ha retirado dinero del banco, sin permiso y promete que lo devolverá a plazos pues se lo ha gastado todo. Le pido que lo ponga por escrito y que tmbién me mande una lista de los gastos de bolsillo que estime. Pasados unos minutos llama de nuevo para informarnos que en su cuenta tiene otro decubierto y que no va a tener dinero para comer, para el piso y que si podríamos darle dinero de la pensión de su madre esta mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2013-08-20','En el día de hoy se recibe llamada telefónica de Jesús uno de los hijo de Tomasa quien nos informa que en el banco se han enterado de que su hermano Luis Miguel ha realizado distintas retiradas de efectivo en estos últimos meses, dejando la cuenta corriente de su madre sin dinero. Inmediatamente después se recibe llamada de Luis MIguel quien nos informa que está muy nervioso porque sus hermanos le están diciendo por "wassap" que le van a denunciar por haber retirado el dinero de su madre. Él confiesa que ha realizado esos reintegros pero que los pagará, que ahora no tiene dienero, propone pagarlo poco a poco. Pasados unos minutos vuelve a llamar Luis Miguel para contar que además del dinero de su madrfe se ha gastado todo el suyo y que tiene un decubierto de más de 600 Euros por lo que no va a tener dinero para hacer los pagos del mes de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2013-08-22','Se llama al Secretario del Ayuntamiento y nos informa que Salvadora no le ha entregado la llave del domicilio. Que está constantemente diciendo que se quiere marchar de la residencia y que quiere hablar con sus "tutores" Se realiza llamada a la residencia para hablar con la interesada pero no está. Se mantiene conversación con una trabajadora, Teo quien nos confirma que Dori se quiere marchar, que le está costando mucho la adaptación, que sus compañeros la rechazan y apenas tiene trato con ellos. También nos comenta que el gerente de la residencia les h indformado que ella no puede ir su casa, entiendo que de visita pues ésta no está en buenas condiciones. Le informo que vamos a limpiar el domicilio y que ella puede entrar y salir de la residencia cuando quiera siempre que respete las normas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2013-08-21','En el día de hoy se recibe llamada telefónica de Jesús uno de los hijo de Tomasa quien nos informa que en el banco se han enterado de que su hermano Luis Miguel ha realizado distintas retiradas de efectivo en estos últimos meses, dejando la cuenta corriente de su madre sin dinero. Inmediatamente después se recibe llamada de Luis MIguel quien nos informa que está muy nervioso porque sus hermanos le están diciendo por "wassap" que le van a denunciar por haber retirado el dinero de su madre. Él confiesa que ha realizado esos reintegros pero que los pagará, que ahora no tiene dienero, propone pagarlo poco a poco. Pasados unos minutos vuelve a llamar Luis Miguel para contar que además del dinero de su madrfe se ha gastado todo el suyo y que tiene un decubierto de más de 600 Euros por lo que no va a tener dinero para hacer los pagos del mes de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2013-08-21','Se contacta con Dña. Isabel para decirle que ya está en nuestro poder la copia del recibo de Iberdrola. Se lop envíamos a su hijo Paco por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2013-08-27','En el día se realiza visita a Centro Socio Sanitrio de Mérid a petición del Dr. Ali. (Se hace informe de la visita)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2013-08-04','Se mantiene conversación telefónica con Carmen, TS del ESM para que nos remitan informe de las ultimas actuacones realizadas en relación a Carmen y el estado de salud actual en el que se encuentra ya que lo necesita la CTA para hacer informe a Fiscalía. Carmen manifiesta que antes de enviarlo quiere antes realizar una visita y mantener conversación con los vecinos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOSA'and apellido2='MARTINEZ'),'2013-09-05','Se recibe información por parte del TS de Helechosa sobre el tutelado. La noche del 1 al 2 de septiembre José ha desaparecido del Piso, no ha dormido en el mismo. Se procede a su búsqueda por parte de la policía y se encuentra a José en la Estación de Autobuses de Castuera con una garrafa de 5 litros de vino. El TS refiere que actualmente esta en el piso pero se escapa cuando quiere porque los recursos de contención no existen. Por otra parte manifiesta que está muy agresivo con todo el mundo y precisa un recurso más adecuado para él. Le solicito parte policial e informe social avalando tal petición. Lo dirigirá al correo electrónico de Marisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='APARICIO'and apellido2='GALLEGO'),'2013-09-02','Se recibe llamada de Demetrio Gallardo, tío de Eva, en la que nos alerta de que Eva no desea estar en Novaforma, por lo que requiere que la cambiemos a otro y, a ser posible, en Don Benito para que el resto de familiares y amigos puedan visitarle. Si esto no fuera posible, indica la posibilidad de que se la traslade a un centro privado de dicha ciudad, costeándose, si fuera necesario con la venta de un piso que dice tener en Venezuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ELENA CONCEPCION'and edp.apellido1='BUENO'and apellido2='ALBA'),'2013-09-30','-Amalia se reune con Angel ( Dtor. del Centro Trevauto ) en Badajoz, para recoger el contrato de compra-venta de un turismo que ha comprado el matrimonio y no habían comunicado a la Comisión .Me dan el contrato para que lo firme la Dtra.-Gerente del SEPAD y sea totalmente válido . Han dado una entrada de 500 € , han entregado un vehículo viejo y se han acogido a las deducciones por discapacidad . El resto hasta completar 19495€ lo pagarán en un único plazo , hemos comprobado sus cuentas y puede cubrir el pago . Igualmente se comunicará al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2013-09-30','-Amalia se reune con Angel ( Dtor. de Trevauto) donde el matrimonio ha comprado un vehiculo sin comunicarlo a la Comisión . Explico su situación y que para formalizar el contrato se necesita la firma de la Dtra.-Gerente del Sepad. Se entrega el mismo que se les enviará firmado por correos. El coche les cuesta 19500€ , han dado una entrada de 500€ y el resto se pagará en Noviembre cuando se lo entregen en pago único , puesto que tiene dinero suficiente para cubrirlo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2013-09-27','-Amalia contacta con diferentes inmobiliarias para concretar con cual de ellas se pone a la venta el piso del que es copropietario . Se mantiene reunión con Viprés , Extrecasa y García-Márquez , contando ya con una tasación del inmueble que nos puede servir de referencia. Se guarda la información en su expediente , pendiente de decidir con cúal inmobiliaria se realizará la gestión y precio de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2013-09-30','Aprosuba comunica que esta madrugada, Eulalia ha sido de nuevo ingresada en urgencias del HIC aquejada de otro cólico. Estamos a la espera de los resultados de las pruebas que se le estan realizando.','2');
