insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ORTEGA'and apellido2='SEVILLA'),'2011-09-25','-traslado del centro en Burgos al CSS Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2013-09-25','El 25 de septiembre la Jefe de Sección de la Comisión Tutelar y una Trabajadora Social se encuetran en las dependencias de la Gerenecia Territorial de Cáceres realizando gestiones. Se nos acercaron tres trabjadores de la gerencia para preguntarnos si nosotros erámos los "Tutores de José" puesto que ellos están preocupados por éste pues les dice frecuentemente que no le queda dinero para llegar a fin de mes. Nos informan de que José se marcha a diario después de su jornada laboral a su pueblo a Almoharín, que lo hace en el coche de otro compañero de trabajo. Refieren que sólo en contadas ocasiones, cuando tiene turno de tarde se queda a dormir en el piso tutelado. Ellos no quieren identificarse pues no quiere tener problemas pero nos piden que lo solucionemos en beneficio de José por el cariño que todos le tienen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2013-10-01','-Queda definitivamente comprobado que Fco. Javier es el único propietario del piso sito en C/ Portalegre , nº4 , 1b . Los tios no son copropietarios , según escritura de aceptación de herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2013-10-01','El jueves 26 de septiembre la dirección del centro denuncia a laPolicía la desaparición de José Mª y hoy ha sido entregado por las fuerzas de seguridad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMALIA'and edp.apellido1='PEREZ'and apellido2='MARAGATO'),'2013-10-01','Se llama a la Trabajadora Social del Servicio Social de Base para comunicarle que el próximo viernes iremos a realizar visita domiciliaria a Amalia Pérez Maragato. Me facilita el teléfono de su hermano Juan: 666083480','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2013-10-07','-Se solicitó PNC y ahora se opta por ella y dejamos PF , con los ingresos del padre no superamos el límite fijado por PNC .Con esta va a percibir las dos pagas extras y no tiene copago de medicamentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2013-10-09','Se recibe llamada telefónica de la T.S. del CSS de Plasencia para informar de que Salurnino el pasado día 7 ser marchó con otro residente al un club de alterne. Que ha sacado todo el dinero que había en su cuenta, dejandola en números rojos y que dice haberselo gastado todo en cocaína. Nos piden una autorización para registrr sus pertenencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2013-10-17','- Me acerco al piso donde reside Daniel , y mantengo reunión con parte del equipo de EALEX . Acordamos reiniciar las visitas de la abuela en jueves alternos , de 19 a 21 h y según se desarrollen veremos para Navidades . La abuela tendrá que confirmar el miercoles . LLamo a su abuela para comunicarselo y no responde a los mensajes de tf. (619085037) . Quedo pte. la visita a su domicilio en C / Berna , 53 , para asegurar que ni la hija , ni su examarido residen con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOSA'and apellido2='MARTINEZ'),'2013-10-18','- Tras la situación que plantea José en los Pisos de Helechal ( conducta disruptiva , consumo de alcohol , dialisis, empeoramiento sanitario seguramente se le tenga que amputar un pie ) .. . se hacen gestiones para solicitar plaza residencial . Por dependencia no se puede realizar porque según Antonio (TS) no va a dar nivel . Por Decreto ya se solicitó y nos enteramos que hace un par de meses se le dió plaza en la R.M. La Coronada en Villafranca de los Barros , a la que José ha renunciado y Antonio envió la misma . Está en Lista de Espera en el Prado en Mérida , próximamente lo llamarán para valorar el preingreso , está en el puesto 17.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2013-10-21','Se hace llmada telefónica al Centro de mayores donde ingresó el viernes pasado. Nos comentan que todo ha ido bien y que necesitan datos sobre los asuntos económicos. Le indico que apenas tiene dinero en las cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LUJAN'and apellido2='PIMPOLLO'),'2013-10-23','Se mantiene conversación telefónica con la Técnico PIA de Zafra para consultar el expediente de la tutelada. Nos inform del estado del mismo. Quedamos en que se pida una "reapertura del expediente" y se le solicitará plaza residencial. Los pisos donde reside en la actualidd no están acreditados','2');
