insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2013-11-04','-Se ha detectado que para el procedimiento de division de herencia ya habia una abogada de oficio : Margarita Garcia Diaz ( 924221903) . He hablado con ella y se va a poner en contacto con la procuradora pq nadie le ha comunicado que hubiese nueva citació judicial . Quedamos pte. de sus noticias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2013-11-04','Por el Director del CRR de Plasencia se nos comunica que Guadalupe ha sido ingresada en el Hospital debido a un proceso de agitación y desorientación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2013-11-05','El Director del CRR comunica que ayer por la tarde ha tenido que firmar un permiso como guardador de hecho para realizarla una punción lumbar. En el Hospital siguen sin conocer el origen de tanta desorientación y agitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-05-13','Se le diagnostica cáncer de pulmón en estadío IV. Diagnóstico muy grave. Pocas esperanzas. La noticia se pone en conocimiento de su hermana Inés.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-05-21','Comienza la administración de quimioterapia. Se informa a su hermana Inés Mv 654 355 782','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-07-09','En la consulta oncológica se nos informa, a través del Dtor. del CRR de Plasencia, que los pulmones están siendo controlados para que no se encharquen. Tiene alteraciones con la diabetes como consecuencia de la quimio. Por el calor, hay que restringirle las salidas. Pérdida de peso. Nueva cita a mediados de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-07-11','Se le autoriza a salir de excursión a Navas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-08-05','Inés, la hermana de Lorenzo muestra preocupación por su delgadez y palidez. Se le avisa que es fruto del tratamiento de la quimio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-10-29','Por el Dtor. del CRR se nos comunica que el tumor ha remitido y que, aunque se observa otro, no hay metástasis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2013-11-04','Se nos solicita consentimiento informado para reservorio con el fin de seguir con el tratamiento quimioterápico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2013-11-04','Con esta fecha se le da de alta en el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2013-10-25','Ingresa en la UHB de Plasencia derivado por su psiquiatra, como consecuencia de ideas delirantes, sueño constante y lentitud verbal y psicomotriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABRIEL'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-11-25','En el día de hoy y tras haber concertado cita telefónica con el hijo del tutelado, se reliza visita domiciliaria. En el domicilio se encuentran Dña Pilar, la esposa, el hijo y una auxiliar de ayuda a domicilio. Mantenemos conversación con todos. Con Dña. Pliar sobre su estado de salud, sobre la dinánica familiar así como de las dificultades que puedan encontrarse en los cuidados de D. Gabriel. Con su hijo D.Abrahan incidimos en estos temas además de preguntarle sobre las propiedades y los procesos judiciales que existen. Tambié hablamos con la Auxiliar de ayuda a domicilio quien nos informa de que cada día es más complicado subir losm dos tramos de escaleras que existen','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2013-11-13','En el día de hoy se visita el domicilio de Jesús en Cáceres, al objeto de conocer las condiciones en las que vive así como saber si realmente vive en Cáceres o continúan en Madrid como sospechamos. Se hacen dos intentos pero no abren la puerta. Se mantiene conversación con un vecino que dice conocerles bien. Ns informa de lo siguiente: - Que hace años que viven en ese edificio. - Que residen de forma permanente que se les ve de vez en cuando pero con relativa frecuencia. - Que la pasada semana les ha visto durante toda la semana. - Que en el pasdo han tenido problemas muy graves con los vecinos como que intentaron atropellr a unos con el coche, que bloqueaban con su vehículo la puerta del garaje impidiendo así el accso o salida de vehículos del mismo. - Que saben que los tres hermanos tienen algún problema mental, que además los tres han estado sanos hasta una determinada edad. Que cree que los tres han cursado estudio universitarios. - Que son " personas raras" que no mantienen relación con nadie. - Que no trabajan y cree que una de las hermanas está casada. Le dejamos el telefóno de la Comisión Tutelar por si existiera algún problema o nos quisiseran facilitar algún tipo de información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2013-11-13','En el día de hoy se acompaña a Luis Miguel al Juzgado para representarlo en una declaración. Terminada la misma se mantiene conversación con le sobre su estado de cuentas y la imposibilidad de mantener ese ritmo de gastos así como recordarle que él no puede contraer deudas de las que nosotros no tengamos conocimiento. Se le explica que si continá así deberemos de tomar alguna decisión con respecto a la idoneidd de vivir de forma independiente. Se le aconseja que no hable con nadie sobre su declaración ante el Juez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2013-11-14','Nos comunica Marivi la trabajadora social de Campanario que se han arreglado unos desperfectos de su casa y que las llaves se encuentran en la policía local del pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO MANUEL'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2013-09-12','Tras varias conversaciones con Domingo Diaz Rivera (el que ha venido explotando las tierras)se pacta 190€ la fanega y a Javier Muñoz, el marido de la que ha heredado a la tía se le contesta que seguimos en la misma situación y por tanto no aceptamos su propuesta.','2');
