insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2013-11-28','-se realiza visita domiciliaria el dia 27, se envia informe de segimiento al juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2013-11-27','-se realiza visita a domicilio y se recogen fotografías de los desperfectos del piso que iremos subsando poco a poco .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2013-11-27','-Se visita a Emilia , abuela de Daniel Montaño ( C/ Berna , 53 tf. 619085037) para comprobar el estado de la vivienda y su solicitud de salidas con Daniel . La casa está en perfecto estado de habitabiliadad e higiene , en muy buenas condiciones y con mucha limpieza . La abuela tb tiene un buen aspecto a nivel personal y solicita permiso para que Daniel pase con ellas las fiestas del 24-25-31-1-6 de diciembre . Por nuestra parte y siempre que mantenga sus compromisos de no faltar a las citas propuestas y no permitir acceso al domicilio de su hija ( orden de alejamiento en vigor ) no existen inconvenientes para ello .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2013-11-26','-Recibimos comunicación del C.de Salud de Merida según el cual , Ati no asiste a sus citas con enfermeria para inyectarse su medicación desde mayo . Lo llamo telefónicamente y me cuenta ha retomado su relación con Joaquina y desde mayo vive en Palafolls ( Cataluña ) con ella en un piso que les han cedido los padres de esta . Que está siguiendo medicación en el C.de Salud de esta localidad y que está muy contento . Mantiene su piso de alquiler en Mérida , pendiente de regresar para llevarse todas sus cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ROMERO'and apellido2='VERA'),'2013-12-11','-El CADEX suspende TTo Psicologico que se le venia prestando , consideran que después de seis meses de tto. este no va a poder mejorar más . Aprosuba 6 solicita reclamación , hemos hablado con Mª Angeles , Dtra CAdex y nos explica que la decisión del equipo es unánime y no se podrá retomar el tto . Llegará la resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SIXTO NICANOR'and edp.apellido1='ALMODOVAR'and apellido2='JIMENEZ'),'2014-01-15','El hermano de Sixto (José María Almodóvar) ha enviado documentación sobre la herencia de la casa que tienen los todos los hermanos (924832938)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2014-01-16','Llama Blanca del CSS para decir que Feliciano quiere ampliar los días de salida, concretamente dos semanales. Se le dice que sin problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2013-12-02','En el día de hoy se realiza visita al domicilio de Jesús y su hermanas aunque sin éxito al no abrir nadie la puerte. Se pregunt a un vecino quien nos informa que se les ve por el bloque y el vecindarioi y que no hay problemas aparentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2014-01-09','-Traslado del Ctro. Residencial de Felipe Trigo al C.R. el Cuartillo en Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2014-01-20','En el día de hoy se recibe un fax de Manuela,Trabajadora Social de la localidad. Nos envía el PIA de José Antonio. No ponemos en contacto con ella. LLamamos por teléfono y nos explica que una Delegada Tutelar, Silvia,ha estado en el domicilio del curatelado esta mañana, encontrasndose una Resolución relativa al PIA del mismo que ha recibido hace unos 15 días. Le explico que no hemos recibido nada pero que estabamos esperandolo pues la empresa que le presta el servicio aún no ha cobrado. A continuación me entrevisto con un técnico de dependencia y me informa que ya se ha pagado el dinero y que debemos justificar la prestación del Servicio con factura y recibo bancario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2014-01-21','Llama la sobrina de Francisco y Vitoriano. Dejan un móvil de contacto 671970885 y 711721837','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2014-01-29','A lo largo del mes de enero mantenemos contacto con Asindi , telefónicamente o a través de mail sobre la hospitalización de Victoria. La información que nos van transmitiendo es la siguiente: - Ingresó en la Unidad de Salud Mental del Hospital de Cáceres.En los días previos, venía mostrándose agitada, llegando a evidenciar conductas de agresión y manifestando constante inquietud y nerviosismo. Tras una primera consulta domiciliaria, se volvió a contactar con su médico de atención primaria, quien consideró la conveniencia de valoración en la mencionada unidad especializada. Se procedió a su traslado y, tras la exploración por parte del psiquiatra de la unidad, se comunicó la necesidad de ingreso. - Se ha estado en contacto con con Salud Mental. Nos comentan que han procedido a un ajuste de medicación y que los primeros días ha tenido muchos signos de depresión y tendencia a aislarse. Queya parece un poco más estable, pero que permanecerá ingresada, al menos, hasta el viernes. -El alta hospitalaria de Mª Victoria se produjo, el lunes 27 de enero. Tiene un comportamiento estable y no presenta signos de alteración conductual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2014-01-29','Nos llama por teléfono D. José María Doncel, abogado de Dña Concepción, hermana del tutelado, para informrnos que el Director de la Residencia de Hoyos, donde se encuentra el tuteldo junto a su hermana está siendo investigado por por haber intentado apropiarse de parte del patrimonio de Dña. Concepción. Que por este motivo ella ya no quiere estar en ese Centro, por lo que solicita que su hermano también sea trasladado. Su familia ha hecho gestiones para trasladarles al Centro de Mayores Real de Navalnmoral. Se llama al Centro de Navalmoral para pedir información, la Directora eel mismo, nos facilitan la siguiente: Es un centro geriátrico mixto, para validos y asistidos, disponen de medico geriatra que pasa consulta de lunes a viernes. -ATS/DUE y auxiliares de enfermería permanente 24 horas. -Terapeuta Ocupacional y Fisioterapia con programas personalizados y rehabilitación. Actividades al aire libre y excursiones en primavera y verano. -Monitora de manualidades, y de ocio y tiempo libre. -Celebración de eventos y fiestas. Actividades socioculturales. -Psicóloga a disposición de familiares y residentes. - Un servicio de comedor con 4 comidas diarias, pautadas por medico geriatra y dietista, además disponen diariamente de dieta especial por si la necesitan. -Peluquería -Podología -Servicios religiosos (los viernes) -El precio estipulado para estancia de Don Marcelo es 1.100€ (como precio especial) - Es un Centro acreditado para atender a personas en situación de Dependencia. Se habla con el despacho del abogado y con Dña. Teresa Pérez Cayetano, prima de los hermanos Manzano Pérez, quienes manifiestan que desean hacer el traslado cuanto antes pues al parecer los hermanos están muy nerviosos. Nos proponen como fecha para el traslado el viernes 31.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2014-01-30','El 29 de enero se traslado mediante transporte de Cruz Roja a D. Francisco aL Centro de Mayores de Azuaga. Se llama a la Directora del mismo quien nos informa que ha llegado bien, que ha pasado bien la noche y que es pelnamente consciente de dosnde está.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMALIA'and edp.apellido1='PEREZ'and apellido2='MARAGATO'),'2014-01-30','Se llama a Laura Técnico PIA de Plasencia para preguntar sobre la plaza de Amalia en Centro Residencial. Nos comenta que hay pocas posibilidades que entre pronto en Casas del Castañar, les explico que no tenemos porqué centrarnos sólo en ese recurso que se le puede ampliar la lista de espera a otros. Nos informan que en cualquier residencia del Valle del Jerte o de Plasencia y alrededores v ser dificil entrar conm un grado II. Al parecer en el momento actual podría ingresar en un Centro Residencial de Villa del Campo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMALIA'and edp.apellido1='PEREZ'and apellido2='MARAGATO'),'2014-01-31','Llamo a Pilar, Trabajadora Social del SSB Valle del Jerte y le expongo la situación referente a la disponibilidad de plazas para Amalia. Acordamos aceptar la de Villa del Campo, en caso de que se le adjudicara e intentar que permanezca en lista de espera a las más cercanas a su población.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA NIEVES'and edp.apellido1='HERREROS'and apellido2='ORIVE'),'2014-01-31','Llama Paqui, la hija de Nieves para informarnos de la muerte de su padre. Nos dice también que se engargan ellos de pagar el seguro de decesos de su madre. El número de póliza 161060714','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA NIEVES'and edp.apellido1='HERREROS'and apellido2='ORIVE'),'2014-01-31','Teléfono Paqui (hija) 619136632','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMALIA'and edp.apellido1='PEREZ'and apellido2='MARAGATO'),'2014-01-31','Se llama a la Técnico PIA de Plasecnia pra interesarnos por l plaza en Centro residencial de Amalia. Nos comenta que se encuentra en lista de espera de los Pisos Tutelados de las Casas del Castañar pero que será muy dificil que con el grado de Dependecia que tiene reconocido entre pronto. Les traslado mi sorpresa pues cuando se negoción el PIA desde aquí no se indicó ningún centro concreto si no que se hizo la propuesta de que no se le alejara mucho de su entorno auqnue sin ser la misma localidad. Se nos explica que la única posibilidad de que se le adjudique pronto un plaza pública es optando por una más lejana. A continuación se llama a Pilar, trabajadora Social del SSB y se le explica la situación. Llagamos al acuerdo de aceptar cualquier otra que nos de y mntenerla en lista de espera para la de Navaconcejo y El Torno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MORENO'and apellido2='BORREGUERO'),'2014-02-03','Nos ponemos en contacto con Lola, Trabajadora Social del SSB para intresarnos sobre la limpieza del domicilio, nos coment que ella se ha puesto en contscto con Mª Eugenia, Trabajadora Social del Centro de Salud y esta a su vez había contactado con la veterinaria, quien emitiría un informe una vez que el Ayuntamiento se lo pidiera formalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2014-02-03','Nos ponemos en constacto con Margarita, trabajadora Social del SSb para informarle de que desde la Comisión Tutelar no podemos asistir a la limpiaza de la casa de Slvadora y le preguntamos si estaría dispuesta a acompañar a los operarios de la limpieza. Nos comenta que sólo iría si Salvadora estuvira de acuerdo pero que si no es así ella no lo hace pues ya ha tenido problemas con ella en el pasado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GORDILLO'and apellido2='PINTO'),'2014-02-14','Teléfono hermano 936583294','2');
