insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2014-03-05','-En relacion a la PFHC del ISFAS que actualmente tiene suspendida por estar trabajando con contrato de jardineria del ayto de su localidad , no hay que gestionar nada , su padre lo tiene todo preparado en una gestoria. Guardo en su expediente el correo con toda la información . Me avisará con los siguientes trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2014-03-05','Recibimos llamada telefónica de Pilar, Trabajadora Social del Equipo de Salud mental de Cáceres. Nos informa de que Consuelo ha acudido a consulta ayer pero que ha llegado tarde por lo que la psiquiatra no la ha visto y le ha dado cita para el día 18 de marzo. Sí ha mantenido entrevista con la Trabajadora Social quien le ha propuesto ir a un centro residencial y ella está conforme, reconoce que en su domicilio no puede estar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2014-03-06','-Ante la insistencia de Iris , hija de Rosa , sobre posibilidad de trasladar a su madre a una residencia más cerca de Madrid que es dónde sus hijas residen contacto con la TS de la RM La GRanadilla. Comentan que llegó en pésimas condiciones , que se encuentra muy adaptada y contenta en el centro , no sería conveniente el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2014-03-10','-solicitado centro residencial por discapaciadad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2014-03-10','El centro nos comunica que Hermenegildo se ha fugado. Horas después nos cuenta que se le ha localizado en su casa con su madre.','2');
