insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2014-03-12','Lorenzo ingresa en el hospital como consecuencia de una caída. De momento se suspende el inicio de la radioterapia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2014-03-21','Causa alta en el hospital pero debido al alto grado de dependencia se gestiona su traslado a una residencia de mayores T2 Como en estos momentos no hay plaza vacante, se traslada a CARE de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZO'and edp.apellido1='FLORES'and apellido2='CALLEJA'),'2014-02-03','Se inicia la quimio en pastillas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2014-03-21','Nos personamos en el domicilio de Maribel, madre del novio de Eva , en Pueblonuevo del Guadiana , para conocer la situación la misma . Eva lleva en la casa desde agosto d 2013.La relación con Miguel Angel es buena , se llevan bien , no suelen discutir . Miguel tiene 65% de discapacidad y percibe PFHC.Los padres se han separado de hecho , Maribel trabaja como limpiadora en el Ctro. Salud y percibe 485€.El marido se hace cargo del pago del agua , luz , hipoteca y le pasa 200€/ mes por los dos hijos . Eva está dada de alta en cocina en Ap8 , no está muy a gusto , percibe en torno a 500€. Los dos acuden a Aprosuba 8 , los recogen en su transporte y los regresan a las 6 de la tarde. Cuando llegan sacan a los perritos a pasear . Los fines de semana los pasan en casa o en el campo con la familia . Quieren casarse , han ido al juzgado a solicitar información. Maribel ha pedido información para ser la tutora de Eva. Próximamente tienen cita en el ginecólogo , todos los tratamientos anticonceptivos le producen hemorragias . Ya está empadronada en la localidad . Se acuerda una transferencia pte. a la cuenta donde aparece Eva y Maribel de titular . De los 624€ ( salario +24€ PNC) se va a dar 150 a Maribel para gastos de comida, 160 tabaco , 100 € gastos de bolsillo , en total 410€/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='VEGA'and apellido2='FUENTES'),'2014-04-07','-Recibo llamada de la UHB de Badajoz donde Antonio ha ingresado hace 15 dias por descompensación psiquiatrica tras un altercado en el domicilio . Ha sido tratado de síndrome de abstinencia alcoholico. Hoy le dan el alta y regresa al domicilio donde convive con su padre , un señor de 88 años , donde se sucenden episodios de conflictividad familiar . Desde la UHB se solicitó ingreso en la Unidad de Larga Estancia del CSS de Mérida que ha sido denengada. La única opción es que Antonio voluntariamente siga tto. en CEDEX desde donde seria derivado a la Unidad de Alcoholismo de Plasencia , opción que ni su psiquiatra ( DTRa. Silvestre ) ni su médico de cabecera consideran que nuestro tutelado quiera acceder . Se le ha planteado al padre que abondone el domicilio para pasar a Pisos Tutelados de la localidad o vivir en Barcelona con un hija , pero se niega mientras el hijo esté en el domicilio por temor a que le ocurra algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2013-11-25','En el día de hoy se recibe llamada telefónica de Inés hermana del tutelado pr exponernos la situación de su hermano. Pide que se le de cuanto antes ingreso en centro residencial. Con muchas dificultades pues es complicado hablar con ella se le explica que la Comiión Tutelar no dispone de centro propios y que si él está en alguna lista de espera deberá esperar su turno como cualquier otro ususario.A continuación se llama al Equipo de Dependencia de Villanueva, nos informan de que se optó porel Servicio de Ayuda a Domicilio porque José Luis no reunía perfil para ningun centro. Les pregunta sobre un centro de mayores privado al que la familia había hecho referencia. Tras informarse al respecto nos explicanm que no le admitirán en ese centro pues ya fue expulsado del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2013-12-27','En el día de hoy se recibe llamada telefónica de Dña. M José Murillo, hermana del tutelado, en esta conversación nos expresa un sin fin de quejas derivadas de la empleada de ayuda a domicilio. Se le pide que nos informe por escrito. A continuación se llama al Servicio Social de Base de la localidad, no encontrandose la trabajadora Social mantenemos conversación con la Concejala de Asuntos Socialoes de la localidad. Se le pregunta por la auxiliar de ayuda a domicilio y las posibles quejas que pudieran dimanarse de la prestación del servicio.La información que aportan es que lo que sí conocen es que la propia auxiliar está teniendo muchos problemas tantoi con el interesado como con la familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2014-04-14','Se llama por teléfono a Martín para concertar entrevista con él en las dependecnias de la Gerencia Territorial de Cáceres. No contesta al teléfono','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2014-04-14','-Tras recibir informe sobre la situación de Dolores por parte de la entidad en la que comunica sobre la misma , pregunto a MªLuz ( Salud Mental ) sobre la posibilidad de acceso a UDAC.Me comunica que en una visita que realizaron a la entidad ya se lo propusieron y el Dtor. Florencio Tena , rechazó la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='CACERES'and apellido2='CABANILLAS'),'2014-04-15','-Gestiones para busqueda de informacion para realizar el inventario : 1) Contacto telefonico con Julia (TS de Talavera la Real ) No saben el paradero de Mª Soledad , en el pueblo no reside . Sí viven su madre y su hna. , discapacitada ,tutelada por la madre, que acude a Aprosuba 8 . Residen en el domicilio propiedad de la pareja sentimental de la madre . Las TS de la localidad fueron citadas a un juicio por lesiones en el ambito familiar entre madre e hija pero del que no han vuelto a recibir información. 2) Contacto telefonico con SSB de Badajoz , Pilar Mateos es la TS de la zona del Gurugú donde creemos que reside Soledad con su novio . Pte. de volver a hablar con ella por encontrarse ausente. 3) Contacto telefonico con servicio de empadronamiento del Ayto . Badajoz , me confirman que aparece empadronada en C/ Hornos de Medina , 27 . Solicito por email volante de empadronamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2014-04-15','-GESTIONES REALIZADAS PARA INVENTARIO : 1)Contacto telefonico con Esther, TS del Ctro. de Salud. me va a reenviar informe social con información personal de Paloma . Percibe PF. Se va a solicitar PNC pq no reune requisito de demanda de empleo para RAI. 2)Contacto telefonico con su primo Domingo Rguez. Le solicito información sobre dirección exacata de la casa de alquiler donde residen, cómo se hace el pago del mismo , tf de Paloma ... 3) Contacto telefónico con Paloma , hablo con ella , le explico su situación juridíca y me presento y me comenta su situación personal . 4 )Programada visita domiciliaria para el proximo dia 24 en su domicilio en Jerez de los Caballeros. Acudirá también Esther y si puede su primo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2014-04-15','En el día de hoy se mantiene conversación telefónica con El padre Fernando Pecero de la Casa de la Misericordia de Pinofranqueado sobre el fax recibido relativo a las condiciones de Basilio.Nos informa que las condiciones en las que vive son deplorables, que ha bebido de forma abusiva, incluso se ha caído al suelo desde un taburete como cnsecuencia de esto,me repite todo lo informado en el fax recibido el 12 de este mes. Por mi parte le pregunto si alguna de esa conductas que ha presentado podían considerarse peligrosas y susceptibles de intrvención de urgencias sanitarias, respondiendo en sentido positivo por lo que quedamos en que en futuras ocasiones se avisará al médico o servicio de ugencias. Con relación al resto de las cuestiones se informa de que en breve un técnico en representación de la CT mantendrá entrevista personal con él y se le explicará que si no accede a vivir en el centro de forma permanente se le trasladará a otro recurso residencial.Aprovecho para solicitarle el informe de salud de Dependencia para solicitar la valoración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='ALVES'and apellido2='MOYA'),'2014-04-21','En el día de hoy se recibe llamada telefónica de Pilar, Trabajadora Social del CSS para informarnos que Santos se escapó el sábado pero que ya ha sido localizado por la policia en Cáceres y que esa misma mañana lo llevan de vuelta al centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2014-04-22','Nos llama Candelas del CSS para informarno que José Mª volverá de vacaciones de Semana Santa el día 229 y no el 28 como habíamos autorizado.Y que tal y como convenimos las dos antes de marcharse de vacaiones le dio 100 Euros para su estancia en el domicilio familiar.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2014-04-23','Se recibe llamada telefónica de Carmen, Trabajadora Social del Centro para informar que Hermenegildo se ha escapado. Cuando llegó de su pueblo estaba esprándolo la Guardia Civil para comprobar que no hubiera traído ningún tipo de sustancia, como ya había ocurrido en ocasiones anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2014-04-24','El Director del CRR de Cáceres comunica que Emilia en un viaje a Plasencia con su novio la Semana Santa ingirió pastillas y alcohol y fue ingresada en el Hospital de Plasencia en donde continúa ingresada. La Psiquiatra está estudiando la posibilidad de derivarla, al menos, a la URHO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2014-04-24','-Realizo visita domiciliaria en Jerez de los Caballeros . Por el momento se acuerda que se quedarán en el domicilio con un control exhaustivo del pto. economico. Su primo Domingo cogerá los 250€ del alquiler para entregarselo a la propietaria y asegurar el pago. La visita se recoge en el inventario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2014-04-28','se envia pliego de cargos al colegio de abogados bjoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='CACERES'and apellido2='CABANILLAS'),'2014-04-30','-realizo visita domiciliaria en c/ hornos de medina en el Gurugú . La informacion se recoge en la declaración anual .','2');
